INSERT INTO `assessment_widget` VALUES (1,68,2019,'III TRI',NULL,'il fatturato dei trattamenti termici conto terzi è in crescita ormai dal 2012 (7 anni ) . ','A causa di crisi di mercato cicliche il 2019 e il 2020 potrebbero chiudersi con una contrazione del fatturato complessivo del settore , depresso sopratutto da calo delle vendite auto (diesel in crisi ) e per l\'incertezza internazionale che pesa sugli investimenti ','/snap/68_1573238769.png',1),(4,70,2019,'III TRI',NULL,'La riduzione della redditivitÃ  dal 2Â° al 4Â° posto Ã¨ connessa a 3 problematiche principali in ordine di importanza  : \n1) Aumento ammortamenti per investimenti ingenti 2) Aumento dei costi materie prime in misura maggiore dell\'aumento dei prezzi applicato ai clienti \n3) Aumento incidenza MOD diretta e indiretta','1) Contenimento e riduzione investimenti al fine di ottimizzare saturazione impianti \n2) Ridurre incidenza materie prime   Portare a termine strategia di aumenti \n3) Ottimizzare costo MOD ','/snap/70_1571924992.png',1),(8,71,2019,'III TRI',NULL,'Il costo dell\'indebitamento Ã¨ in linea con quello dello scorso anno . Passato dal 4Â° al 5Â° Posto ','Riduzione graduale livello di indebitamento , anche in considerazione della contrazione del fatturato .','/snap/71_1571995654.png',1),(10,102,2019,'III TRI',NULL,'Risultati in target in linea con le attese ','Continuo monitoraggio RISCHIO SU CREDIT SAFE . \nApplicazione procedura del secondo insoluto per blocco materiale ','/snap/102_1571909955.png',1),(12,103,2019,'III TRI',NULL,'Il valore di EBTDA Ã¨ ridotto rispetto a quello dello scorso anno a causa di :\n1) Aumento costi materie prime non bilanciato da aumento prezzi vendita \n2)Aumento incidenza mod ','1) Ridurre incidenza materie prime   Portare a termine strategia di aumenti \n2) Ottimizzare costo MOD attraverso azzeramento straordinari , ottimizzazione squadre , riduzione indiretti in funzione del livello di fatturato previsto per il 2020 ','/snap/103_1571914726.png',1),(13,104,2019,'III TRI',NULL,'Il valore di ROI Ã¨ ridotto per le seguenti motivazioni:\n1) Aumento attivo  per investimenti ingenti \n2) Aumento dei costi materie prime in misura maggiore dell\'aumento dei prezzi applicato ai clienti \n3) Aumento incidenza MOD diretta e indiretti','1) Contenimento e riduzione investimenti al fine di ottimizzare saturazione impianti \n2) Ridurre incidenza materie prime   Portare a termine strategia di aumenti \n3) Ottimizzare costo MOD ','/snap/104_1571914729.png',1),(14,106,2019,'III TRI',NULL,'Obiettivo centrato anche grazie ad una politica di monitoraggio clienti storici e verifica preventiva clienti potenziali tramite portale Credit Safe','Continuare con una verifica periodica degli insoluti e situazioni di rischio clienti su portale CREDIT SAFE ','/snap/106_1571914543.png',1),(22,130,2019,'III TRI',NULL,'Nel corso del 2019','','/snap/130_1573219590.png',1),(23,150,2019,'III TRI',NULL,'Nel corso del 2019','','/snap/150_1573219459.png',1),(24,147,2019,'III TRI',NULL,'Nel corso del 2019','','/snap/147_1573219451.png',1),(37,100,2019,'III TRI',NULL,'Il valore medio per l\'investimento in formazione Ã¨ per il 2018 di 0,69 mentre per il 2019 Ã¨ di 0,96 quindi al di sopra del target (0,3) e del valore dell\'anno precedente in quanto l\'azienda investe molto sulla formazione soprattutto nell\'ambito della sicurezza, basti pensare che quest\'anno Ã¨ stata ampliata la squadra antincendio e di primo soccorso, sono stati eseguiti corsi di lavori in quota e PLE per i manutentori, Ã¨ stata riconosciuta lâ€™abilitazione allâ€™uso di gas tossici a piÃ¹ operatori rispetto al passato e precisamente (2 operatori per ogni squadra)','','/snap/100_1603024696.png',1);
INSERT INTO `assessment_widget` VALUES (38,109,2019,'III TRI',NULL,'\nil valore dell\'assenteismo Ã¨ gradualmente aumentato negli ultimi anni ma sempre sotto il target che Ã¨ del 3% segno del fatto che la politica di incentivi funziona. A consuntivo 2017 avevamo 2,53, a consuntivo 2018 avevamo 2,88, al terzo trim.2019 superiamo di poco il target con 3,09 ma attribuiamo tale valore ad un fatto eccezionale: la malattia di un dipendente dal 28/04/19 sino al 05/11/19, pertanto non possiamo dire che la politica  degli incentivi non funziona, anzi nel 2019 l\'azienda ha ripartito il premio mensile spettante al lavoratore (capoturno o vicecapoturno) presenti e ciÃ² non per punire chi Ã¨ malato ma per premiare i presenti \n\n','','/snap/109_1603024598.png',1),(39,111,2019,'III TRI',NULL,'Nel 2018 considerando il target del 10% rileviamo che c\'Ã¨ stato un aumento rilevante delle ferie residue con un valore di 13,75 dovuto all\'incremento del carico di lavoro. Ci siamo prefissati di scendere sotto il target con la turnazione a scorrimento nel 2019 e infatti a partire da Gennaio 2019 sino a settembre 2019 registriamo la graduale diminuzione del valore medio da 13,50 a 11,72 Dobbiamo precisare che fino ad Aprile 2019 la riduzione del valore medio Ã¨ quasi sicuramente dovuta alla turnazione a scorrimento essendo rimasto alto il valore del fatturato, ma da Maggio essendosi ridotto del 20% il fatturato, il valore medio scende anche per la riduzione del carico di lavoro, anzi da settembreâ€¦abbiamo pianificato una turnazione con diminuzione del personale per ogni turno e inserimento di ferie e rol ...','','/snap/111_1603024617.png',1),(40,112,2019,'III TRI',NULL,'Partendo dalla considerazione che il target degli infortuni Ã¨ 1 a consuntivo 2018 il valore rilevato Ã¨ 0,10 quindi sotto il target, poichÃ¨\' lâ€™unico infortunio registrato nel 2018 Ã¨ quello di Luca Pellegrini, infortunio dovuto esclusivamente  alla sua negligenza (il responsabile di manutenzione inala azoto e sviene poichÃ© si affaccia nella cisterna di azoto senza i necessari dpi).\nNel 2019 la % degli infortuni sale a 1,66 superiamo il target poichÃ¨ vengono registrate 144 ore contro le 48 ore dell\'infortunio dell\'anno precedente, ma anche questo infortunio Ã¨ dovuto a mera distrazione dell\'operatore (che scendendo dal muletto posiziona male il piede provocandone la distorsione).\nPer quanto concerne l\'analisi dei quasi infortuni  a consuntivo 2018 la % Ã¨ di 0,87 al di sotto del target che Ã¨ 1,5 in quanto sono stati registrati 2 quasi infortuni Vitale e Dei Novellisti con le rispettive azioni correttive (vedi analisi near) Nel 2019 la % Ã¨ sempre al di sotto del target ma superiore rispetto al 2018: siamo saliti a 1,36 poichÃ¨ sono registrati 3 quasi infortuni (Martinez Dragomir e Marianacci-(vedi analisi near) di cui uno considerato fatto accidentale.\n','Strategia futura\nConsiderando che l\'azienda ha investito molto sulla formazione di sicurezza e che comunque siamo al di sotto del target cosa possiamo fare per eventi dovuti a negligenza e imprudenza? Ãˆ stata apposta cartellonistica dove si raccomanda di camminare piano per le scaleâ€¦.\n','/snap/112_1603024391.png',1),(41,110,2019,'III TRI',NULL,'Partendo dal target del 5% come per le ferie si registra a consuntivo 2018 un aumento rilevante con un valore medio di 8,68 dovuto all\'incremento lavorativo.\nCi siamo prefissati di ridurre tale valore con l\'inserimento di nuove risorse e sebbene vengano introdotte altre unitÃ   nel 2018 gli straordinari crescono sempre piÃ¹ e cominciano a scendere a partire da Gennaio 2019 cioÃ¨ quando si cominciano a vedere i benefici della turnazionea  scorrimento, proprio come per le ferie una riduzione graduale sino ad essere forzate per diminuzione del lavoro','','/snap/110_1603024401.png',1);
INSERT INTO `assessment_widget` VALUES (42,113,2019,'III TRI',NULL,'il grado di motivazione del personale ottenuto dalla media delle domande somministrate ai dipendenti Ã¨ 4 quindi al di sopra del target e anche del valore del 2018 cioÃ¨ 3,9 ma da un \'attenta analisi possiamo notare che i valori piÃ¹ bassi del 3% si riscontrano per le stesse domande del 2018 (domanda 13 percezione di un\'atmosfera non molto armoniosa all\'interno del personale; domanda 16) mancanza di comunicazione e collaborazione tra i colleghi e addirittura un valore di 2,95 quindi sotto il target per la domanda 17) mancata assunzione di responsabilitÃ  in caso di errore ','Il grado di motivazione del personale ottenuto dalla media delle domande somministrate ai dipendenti Ã¨ 4 quindi al di sopra del target e anche del valore del 2018 cioÃ¨ 3,9 ma da un \'attenta analisi possiamo notare che i valori piÃ¹ bassi del 3% si riscontrano per le stesse domande del 2018 (domanda 13 percezione di un\'atmosfera non molto armoniosa all\'interno del personale; domanda 16) mancanza di comunicazione e collaborazione tra i colleghi e addirittura un valore di 2,95 quindi sotto il target per la domanda 17) mancata assunzione di responsabilitÃ  in caso di errore \nStrategia futura\nRiteniamo che non applicando azioni correttive nel 2018 sono emersi gli stessi risultati se non addirittura peggiorativi.\nSoffermandoci sulle cause del risultato della domanda  17 si puÃ² ipotizzare la tendenza dell\'operatore a non assumersi le proprie responsabilitÃ  per non incorrere in non conformitÃ  lettere di richiamo-rischi di licenziamento.\nstrategia di miglioramento?  \nFare riunioni con gli operatori per far recepire loro la consapevolezza della qualitÃ  del processo produttivo e del prodotto e far capire loro che il sistema sanzionatorio non Ã¨ qualcosa di personale ma Ã¨ funzionale al raggiungimento di quel risultato.\nIn queste riunioni mensili o trimestrali gli operatori possono commentare le sanzioni comminate e proporre soluzioni per evitare che lâ€™errore si ripetaâ€¦\nLo scopo di queste riunioni e confronti Ã¨ anche quello di favorire un clima piÃ¹ armonioso.\n\n ','/snap/113_1572968500.png',1),(73,128,2019,'III TRI',NULL,'I costi extra trasporti in relazione all\'anno precedente sono diminuiti per la stessa ragione di cui sopra. ','Sensibilizzare maggiormente il personale addetto. Utilizzare addetti più adatti al ruolo (Melchiorre   Napolitano).','/snap/128_1573132639.png',1),(76,135,2019,'III TRI',NULL,'Le nc rispetto all\'anno precedente sono diminuite, anche se qualche errore sussiste. Questo risultato è dovuto all’esperienza maturata dai magazzinieri. Inoltre sono state ridefinite aree dedicate a materiale da rinvenimento differenziato, materiale di minuteria, eliminazione del magazzino a bordo sabbiatura e definizione unica di area post trattamento. ','diminuendo il personale, quello operativo deve essere più performante e attento. Utilizzare addetti più adatti al ruolo (Melchiorre   Napolitano)','/snap/135_1573132736.png',1),(107,119,2019,'III TRI',NULL,'IL RITARDO Ã¨ PARI ALLO 0%.GLI INTERVENTI VENGONO EFFETTUATI TUTTI E , COSA PIÃ¹ IMPORTANTE, IN TEMPI  TRASCURABILI.','CONTINUARE CON LA STESSA DETERMINAZIONE E ABNEGAZIONE.','/snap/119_1573132088.png',1),(109,116,2019,'III TRI',NULL,'L\'efficacia della manutenzione Ã¨ in linea con il target assegnato.come si puÃ  notare, seppur essendo il dato positivo, sui forni llf c\'Ã¨ stato un peggioramento dell\'1,5% rispetto all\'anno passato.questo si puÃ² imputare ad alcuni fermi avvenuti per cariche bloccate all\'interno del forno.','Formare sempre di piÃ¹ gli operatori della produzione sul giusto modo di comporre le cariche;maggiore attenzione alla manutenzione degli attrezzi ','/snap/116_1573132091.png',1);
INSERT INTO `assessment_widget` VALUES (111,120,2019,'III TRI',NULL,'La ripartizione delle ore di manutenzione sono anche esse positive, con una netta supremazia da parte della man programmata. il target Ã¨ stato raggiunto anche se , per quanto riguarda i forni llf , Ã¨ border line. anche questo Ã¨ imputabile al fermo di alcuni forni a causa di cariche bloccate','la strategia da adottare per il futuro Ã¨ quella dei fermi progrmmati dei forni sempre piÃ¹ fiscale. questo permetterebbe di ridare vita agli impianti ad ogni fermo ed evitare possibili rotture. \nformare sempre di piÃ¹ il personale sulla corretta preparazione delle cariche e manutenzione degli attrezzi periodica.','/snap/120_1573132094.png',1),(113,118,2019,'III TRI',NULL,'target raggiunto ampiamente sulla man predittiva.\nperfetta la manutenzione programmata','continuare ad essere esigenti con il personale addetto alla manutenzione e continua formazione sulla conoscenza degli impianti.','/snap/118_1573132116.png',1),(115,149,2019,'III TRI',NULL,'Rispetto allo stesso periodo dell\'an no scorso , gli interventi sono stati del 3% maggiori.questo, di per se, Ã¨ un buon segnale, perchÃ¨ gli operatori iniziano ad inserire nell\'apposito modulo gli interventi da effettuare. questo Ã¨ molto importante perchÃ¨ l\'attenzione di 10 persone Ã¨ superiore a quella di 3 persone','Sensibilizzare gli operatori della produzione a segnalare i problemi che riscontrano sugli impianti, tralasciando quelli superflui e senza senso','/snap/149_1573132124.png',1),(123,114,2019,'III TRI',NULL,NULL,NULL,'/snap/114_1573048131.png',1),(125,122,2019,'III TRI',NULL,NULL,NULL,'/snap/122_1573140213.png',1),(126,124,2019,'III TRI',NULL,NULL,NULL,'/snap/124_1573148244.png',1),(127,115,2019,'III TRI',NULL,NULL,NULL,'/snap/115_1573140216.png',1),(128,117,2019,'III TRI',NULL,NULL,NULL,'/snap/117_1573140219.png',1),(129,140,2019,'III TRI',NULL,NULL,NULL,'/snap/140_1573140221.png',1),(130,137,2019,'III TRI',NULL,NULL,NULL,'/snap/137_1573048210.png',1),(194,97,2019,'III TRI',NULL,'Come è possibile notare il primo trimestre ha scaturito una percentuale di addebito ben al di sopra del target. Questo dato negativo è stato raggiunto a causa di una non conformità del cliente  Bellino Srl dove TS ha partecipato al rimborso di un lotto di 50qli fallato a causa di un trattamento di recupero su un lotto lavorato precedentemente da un nostro competitor.\nIl secondo semestre supera lievemente il target, incidenza su questo dato da ricercare nella problematica e risarcimento danno al cliente CMT per una carica di bottoni criccati.\nPer il terzo trimestre il target è rispettato.','Migliorare la gestione delle campionature non automotive. Concordare con il cliente il piano di campionamento e migliorare la formula di offerta, attendere benestare a procedere solo dopo aver inviato il lotto campione. Migliorare la gestione dei cicli termici e loro modifiche /\naffinamenti.','/snap/97_1572962551.png',1),(197,96,2019,'III TRI',NULL,'Le non conformità di tipo interno sono mediamente  al di sopra del target e dei risultati dell\'anno precedente, fatta eccezione del 2° trimestre.\nDi sicuro l\'introduzione di nuove risorse e un\'attento monitoraggio dei costi di rilavorazioni implementato sul sistema informatico qwin fa registrare questo peggioramento.\nIn questo grafico sono riportate anche le rilavorazioni che spesso TS sostiene a causa di processi al limite, vedi cogeme, e materiali utilizzati dai clienti non idonei al trattamento richiesto dove per spirito di collaborazione e fidelizzazione cliente spesso accetta.','Aumentare il livello di controllo sui processi. Aumentare il livello di conoscenza tecnica del personale di produzione con formazioni mirate.\nMaggiore presenza dei responsabili di produzione in officina per correggere e formare tutte le attività legate strettamente all\'operatore.\n\n\n','/snap/96_1572963348.png',1);
INSERT INTO `assessment_widget` VALUES (203,151,2019,'III TRI',NULL,'Il tempo di chiusura degli 8D supera di gran lunga il target impostato. Purtoppo la chiusura delle RNC dipende spesso da fattori legati al cliente o a nuovi lotti da realizzare.\nAttualmente non esiste un dato storico di confronto con gli anni precedenti in quanto questo kpi risulta inserito nell\'anno in corso.','Sarebbe opportuno per il prossimo anno monitorare il tempo di risposta al cliente relativo al punto delle azioni correttive immediate (D3 e D4).\nMediamente i tempi di ripristino e analisi delle cause non superano i 2gg lavorativi.','/snap/151_1572962405.png',1),(206,152,2019,'III TRI',NULL,'L\'organizzazione ha implementato nel corso dell\'anno il monitoraggio di questo nuovo indice di performance. Il target impostato è stato possibile raggiungerlo per i trimestri 2 e 3. \nMentre si nota come nel primo  gli 8D sono eccessivamente sopra il target.\nLa maggiorparte delle attività  legate all\'operatore e alla movimentazione dei particolari sono le cause di non conformità più importanti.','Puntare sulla specializzazione degli operatori.\n','/snap/152_1572962450.png',1),(211,94,2019,'III TRI',NULL,'L\'indicatore relativo al primo e secondo semestre risultano fuori Target. Questo indice è la sommatoria in PPM di tutti i p/n che vengono scartati da cliente e rilavorati da TS. La messa a punto e ottimizzazione dei cicli di nitrurazione con il controllo della sonda H2 ha generato diverse rilavorazioni aumentando il valore dei PPM e portando l\'indice fuori target. Il secondo trimestre è influenzato dalla numerosità assai elevata dei pezzi di CMT. Infatti si nota un aumento vertiginoso dell\'indice. Per il terzo trimestre la messa a punto dei cicli e l\'assenza di pezzi di scarto fanno rientrare il valore di perfomance al di sotto del target.','Blindare tutti i processi di nitrurazione.\nPorre maggiore attenzione a quei processi di ripristino richiesti dal cliente.\nNon avviare al trattamento particolari se non sono stati presi accordi con i clienti circa le criticità riscontrate da UT.\nProcedure di gestione cicli termici più robuste.','/snap/94_1572963058.png',1),(212,95,2019,'III TRI',NULL,'L\'indicatore risulta essere positivo relativamente al target impostato ad esclusione del mese di maggio dove la numerosità del lotto di scarto del cliente CMT ha fatto aumentare l\'indice.','La nuova procedura sulla gestione dei cicli termici e il nuovo tools permetterà per il futuro di ridurre il rischio di errore nonchè la causa della problematica legata alla nc del cliente.\n','/snap/95_1572966650.png',1),(213,98,2019,'III TRI',NULL,'I costi di non qualità nel primo trimestre risultano essere al di sopra del target a causa della compartecipazione di TS alla failure del cliente Bellino che fa schizzare l\'indicatore oltre 1%\nBuono e sotto il target l\'indicatore dei trimestri successivi. Si apprezza un netto miglioramento  rispetto all\'anno precedente.','La continua sensibilizzazione e formazione a gli operatori sui metodi di lavoro e sulle criticità dei prodotti/clienti ha portato di certo un risultato positivo in termini di costi di non qualità.\nDa migliorare l\'aspetto legato alle  rilavorazioni. Spesso si corre per saturare gli impianti ma non si condivide con UT le criticità dei prodotti. Manca la percezione delle criticità da parte della produzione. Da cambiare assolutamente la procedura sulla campionatura. \nRivedere mansionario UT afficheè possa dedicarsi a gli aspetti tecnici piuttosto che quelli burocratici. ','/snap/98_1572963062.png',1);
INSERT INTO `assessment_widget` VALUES (217,125,2019,'III TRI',NULL,'Dall\'analisi delle perdite quelle di maggiore rilievo sono i tempi di set-up, altre attività, i tempi di messa a punto e i ritardi di laboratorio.','Un modo per ridurre i tempi di set_up potrebbe essere quello di accorpare produzioni che prevedono l\'utilizzo di set-up simili.\nTra le altre attività rientrano i tempi di imballaggio, oliatura, e lavaggio (purtroppo queste attività sono direttamente legate alla lavorazione quindi difficilmente si può agire su questa perdita). Lo stesso vale per i tempi di messa a punto dei cicli probabilmente solo con l\'esperienza l\'operatore potrebbe ridurre tali perdite, che sono fortemente legate alla complessità dei pezzi da trattare. I ritardi di laboratorio dal mio punto di vista sono legati al trasferimento del laboratorio nel nuovo capannone.    ','/snap/125_1573055418.png',1),(225,126,2019,'III TRI',NULL,'La produttività del reparto induzione negli ultimi mesi è aumentata. Infatti si nota anche un trend crescente rispetto agli ultimi 12 mesi. Siamo comunque al di sotto del target (70%) per l\'anno 2019.','Per la strategia futura bisogna analizzare le perdite (vedi sopra).','/snap/126_1573054737.png',1),(235,131,2019,'III TRI',NULL,'Rispetto al target siamo in linea con la produzione oraria media, le produzioni che abbassano la media sono le teste sterzo (produzione media oraria di circa 70).','','/snap/131_1573207604.png',1),(237,127,2019,'III TRI',NULL,'Si ha una saturazione degli impianti in media pari al 30% (da scorporare principalmente tra la IND2 e IND4), comunque lontani dal valore target del 60%. ','','/snap/127_1573147353.png',1),(252,107,2019,'III TRI',NULL,'Il primo trimestre risulta essere perfettamente allineato al target, indice migliorato rispetto all\'anno precedente. Non si raggiunge il 100% a causa della campionatura eseguita su STA2000 ove richiesto un valore di durezza superficiale troppo elevato rispetto al materiale e trattamento eseguito.\nBuono il risultato del del secondo trimestre.\nIl terzo periodo analizzato registra un 87% di efficacia. Inferiore sia all\'anno precedente che al target. In questo caso pur avendo eseguito una campionatura conforme a livello di specifiche tecniche si è ritenuto di registrare la campionatura come non ok in virtù delle deformazioni indotte dal trattamento di bonifica sul pezzo.\nL\'indice non raggiunge il target anche a causa di un numero più limitato di campionature eseguite.','Nel corso dei 3 trimestri solo due campionature sono state registrate con esito negativo. \nRitengo che il dato è tutto sommato positivo.\nMigliorabile la gestione delle campionature rivedendo sia la procedura che il carico di UT. Spesso campionature minori vengono gestite da PRO senza registrazione degli esiti da parte di UT. \nUna migliore definizione dei ruoli e mansioni potrebbe aumentare sia il livello di performace che di monitoraggio.\n\n','/snap/107_1573027117.png',1),(253,108,2019,'III TRI',NULL,'Target rispettato e migliorato rispetto all\'anno precedente.\n','Continuare a monitorare le campionatura dando importanza sia all\'aspetto tecnico che logistico.','/snap/108_1573027131.png',1),(254,143,2019,'III TRI',NULL,'L\'organizzazione è riuscita ad eseguire campionature girando i costi vivi delle stesse ai clienti. \nQuesto lavoro è stato possibile grazie ad una robusta collaborazione di UT e COM','Continuare con la strategia intrapresa.','/snap/143_1573031851.png',1);
INSERT INTO `assessment_widget` VALUES (258,88,2019,'III TRI',NULL,'Come da  Diagramma allegato abbiamo 167 Ordini Conformi su 168, siamo in linea con gli anni precedenti. La N.C. relativa al Fornitore  RIVOIRA  (Fornitore di Ammoniaca) è sorta inseguito al problema riscontrato e individuato non nel Gas di processo bensì nello stato di conservazione delle Bombole all\'interno del quale veniva contenuto il Gas di processo. La N.C. si è chiusa con l\'addebito dei danni causati dalla sporcizia che i medesimi recipienti hanno introdotto all\'interno degli impianti. Mentre l\'Azione Predittiva per azzerare il rischio è stata la fornitura di Serbatoi Nuovi (segnalati)esclusivamente dedicati ella Fornitura Tempra sud.','Mantenimento del grado di attenzione nelle forniture portando a zero le N.C.','/snap/88_1573059258.png',1),(263,123,2019,'III TRI',NULL,'analizzando la percentuale di lead time si evince che il settore del vuoto è quello che è più in sofferenza sia a livello di lead time sia a livello di % commesse in ritardo Questo ritardo è dovuto alla non saturazione delle cariche. Valori oltre il target vi sono anche a livello di Nitrurazione (per mancanza impianto) e induzione (assenza responsabile).','Nella riunione mattutina monitorare continuamente le commesse in ritardo (oltre i 7 gg), sollecitare produzione nel caso la commessa non sia programmata e laboratorio qualora mancasse il collaudo e, ove pronta, avvisare tempestivamente il cliente.  \nA livello di vuoto dobbiamo inserire cariche fisse settimanali, per quanto riguarda l’induzione in attesa che rientri il responsabile in aspettativa, bisogna avviare un percorso di formazione per il sostituto. Per quanto riguarda la nitrurazione a gennaio 2020 sarà installato un nuovo impianto.  \n','/snap/123_1573132668.png',1),(268,154,2019,'III TRI',NULL,'Indicatore nuovo inserito per valutare la capacità di ottimizzare i trasporti e quindi ridurre il costo. Mentre i trasporti verso BARI- ANCONA e LAZIO risultano ottimizzati con costo medio sotto il target, nella zona ABRUZZO, il valore 2019 è superiore al Target. Questo è dovuto alla perdita di un cliente importante SICMA che saturava i trasporti, giustificandone il costo.','il costo da sostenere per il trasporto nella zona ABRUZZO è tale da non giustificare la continuità del servizio.  A questo punto abbiamo due strategie:\n1)Aumentare la resa carica dei trasporti andando a riprendere i clienti persi (SICMA ed EUROCARDAN) e i nuovi clienti (CT-FORGE- SCUTTI). \n2) Proporre trasporto a clienti della zona che utilizzano corrieri (TMC – PAMEC) ad un prezzo di 0.06 €/kg. \n3) Interruzione di tale prestazione con utilizzo di corriere a nostro carico con ribaltamento costi al cliente. \nDa un’analisi dei costi i trasporti risultano più convenienti se affidati all’esterno in caso di carico inferiore a 13.000 kg e superiore a 16.000 kg. Ovviamente tale scelta è da verificare di volta in volta a livello produttivo. \n','/snap/154_1573132720.png',1),(269,153,2019,'III TRI',NULL,'','','/snap/153_1573132723.png',1),(270,121,2019,'III TRI',NULL,NULL,NULL,'/snap/121_1573132684.png',1),(294,86,2019,'III TRI',NULL,'Nel 2019 è stata portata avanti una strategia di aumento prezzi che doveva raggiungere un valore complessivo medio del 2% .\n ','Per effetto del rallentamento del mercato e della concorrenza dei competitors che hanno abbassato i prezzi non è possibile completare il processo di aumento in quanto vi è il rischio di  perdita clienti . Riprenderemo aumenti nel 2020 . ','/snap/86_1573146848.png',1);
INSERT INTO `assessment_widget` VALUES (344,89,2019,'III TRI',NULL,'Nel 2019 sono stati posti dei Limiti più stringenti in merito al Lead Time (giorni) in merito alla consegna dei prodotti, scelta obbligata per un\' Azienda Certificata. Tale Azione è finalizzata anche ad una corretta pianificazione dei Costi e  del Budget di spesa evitando situazioni in cui il CASH FLOW Mensile degli Acquisti sbilanci pericolosamente le Capacità di Spesa dell\'Azienda','Ottimizzazione \ndell\'indice portandolo il più possibile allo 0.','/snap/89_1573059586.png',1),(345,90,2019,'III TRI',NULL,'Chiusure Ordini il linea con Anni \nprecedenti, l\'indice conferma una efficienza e un affidabilità dei fornitori in termini di rispetto dei Lead time garantiti','Spingere su Ordini Programmati nelle forniture ','/snap/90_1573058986.png',1),(346,91,2019,'III TRI',NULL,'KPI 2019 del tutto negativo, pur troppo il mantenimento se non addirittura la riduzione dei prezzi di alcune materie prime viene del tutto erosa da due indici che rappresentano il 50% dei costi totali su materie prime: Energia e Metano, tale incremento sopratutto del Metano azzera completamente i margini ottenuti con la  \nstabilità dei restanti costi su materie prime.','Ottenere su nuove forniture Energia e Metano le migliori quotazioni che il Mercato può offrire mettendo in competizione il maggior numero di Fornitori in grado di Offrire forniture in base alle nostre esigenze. Condizione essenziale mantenere i prezzi invariati sulle restanti forniture di Materie prime.','/snap/91_1573059537.png',1),(383,84,2019,'III TRI',NULL,'I tempi di pagamento sono in linea con i valori obiettivo. ','Per il futuro occorre impostare i termini di pagamento di massimo 90 giorni. ','/snap/84_1573238800.png',1),(384,85,2019,'III TRI',NULL,'I dati ottenuti dalle interviste telefoniche ai clienti dimostrano che il motivo principale per il 46% delle offerte  non sono andate ancora in porto è legato alla sfavorevole condizione del mercato che non favorisce l\'avvio dei nuovi progetti in tempi rapidi. Per quanto riguarda le offerte perse le motivazioni sono da ricercarsi nella mancata produzione dei pezzi ovvero il mancato ottenimento del progetto anche a causa dei prezzi temprasud elevati.   ','Migliorare l\'efficienza nel monitoraggio delle offerte in stand by  per i progetti in fase di sviluppo da cliente. 		\n		\n ','/snap/85_1573238822.png',1),(385,83,2019,'III TRI',NULL,'Durante l\'anno abbiamo ricevuto offerte di elevato valore economico attualmente ancora in fase di valutazione da parte dei clienti. Complessivamente il valore delle offerte è cresciuto insieme alla percentuale di offerte andate in porto che ha ha superato il target. ','Strategia già analizzata in motivi di rinuncia ','/snap/83_1573239484.png',1),(386,136,2019,'III TRI',NULL,'DA AGGIORNARE KPI','','/snap/136_1573146883.png',1),(387,82,2019,'III TRI',NULL,'DA AGGIORNARE KPI  ','vedere sotto ','/snap/82_1573152509.png',1),(388,81,2019,'III TRI',NULL,'','','/snap/81_1573152204.png',1),(389,80,2019,'III TRI',NULL,'Target raggiunto e superato. ','Continuare con la strategia di diversificare il più possibile il fatturato su più clienti ','/snap/80_1573239581.png',1),(390,79,2019,'III TRI',NULL,NULL,NULL,'/snap/79_1573146896.png',1),(397,69,2019,'III TRI',NULL,'La quota di mercato nel 2018 è cresciuta rispetto all\'anno precedente  .','Consolidare quota di mercato anche attraverso l\'acquisizione e il futuro controllo di Unitrat che permetterà di raggiungere al gruppo una quota di mercato complessiva di circa il 45% . ','/snap/69_1573151099.png',1);
INSERT INTO `assessment_widget` VALUES (399,72,2019,'III TRI',NULL,'Il fatturato fino a ottobre 2019 è anche se di poco superiore al 2018 . A causa di un rallentamento verificatosi a partire da agosto risulta essere inferiore rispetto al Budget ','Considerando una riduzione del fatturato dei primi 5 clienti (Brovedani e SIAP ) nel 2020 è necessario acquisire nuovi clienti (Bonfiglioli comer ) , sviluppare nuovi progetti (Brovedani - pistoni ) e portare a casa le offerte emesse nel 2019 ','/snap/72_1573151334.png',1),(401,73,2019,'III TRI',NULL,NULL,NULL,'/snap/73_1573152265.png',1),(402,78,2019,'III TRI',NULL,'IL fatturato viene analizzato nel corso degli 11 mesi. Attualmente l\'impianto dominante continua ad essere LLF.\n','Continuare ad investire e a cercare clienti diversificando il fatturato e riducendo il peso % della linea LLF . ','/snap/78_1573152293.png',1),(429,101,2019,'III TRI',NULL,'Il livello di indebitamento % risulta arrivato ad un valore massimo .','Considerando la riduzione del fatturato prevista nel 2020 è necessario per il prossimo anno procedere ad una riduzione di tale parametro ','/snap/101_1573220677.png',1),(431,105,2019,'III TRI',NULL,'Il livello di patrimonializzazione obiettivo di 5.000.000 € è stato raggiunto e superato nel 2018 . ','Considerando la riduzione di investimenti prevista per il 2020 , l\'obiettivo è comunque quello di non scendere sotto il valore di patrimonializzazione target ','/snap/105_1573220687.png',1),(446,97,2019,'IV TRI',NULL,'Complessivamente il 2019 si chiude con un valore medio del 0.43% contro il valore medio del 2018 di 0.37% sopra il target del 0.23% \nApprofondendo l’analisi  è possibile notare che nel  primo trimestre vi è una una percentuale di addebito ben al di sopra del target (cliene  Bellino Srl con TS che ha rimborsato un lotto di 50qli fallato (vedi 8D). Il secondo trimestre supera lievemente il target, a causa di un risarcimento al cliente CMT per una carica di bottoni criccati (vedi 8D) . Infine nel terzo trimestre il target è rispettato. \n','Migliorare la gestione delle campionature non automotive: \n1)Concordare con il cliente il piano di campionamento \n2)Attendere benestare per la prduzione di serie  solo dopo aver inviato il lotto campione. \nMigliorare la gestione dei cicli termici e loro modifiche / affinamenti, in quanto la modifica di un ciclo termico può determinare NC per codici trattati con il ciclo in modifica.\n','/snap/97_1573286929.png',1),(447,96,2019,'IV TRI',NULL,'Il valore del 2019 0.68 % è al di sopra del target ma è anche al di sopra del valore medio del 2018 (0.4%).\nLe non conformità di tipo interno sono mediamente  al di sopra del target e dei risultati dell\'anno precedente, fatta eccezione del 2° trimestre.  L\'introduzione di nuove risorse addette al controllo di tale KPI e un\'attento monitoraggio dei costi di rilavorazioni implementato sul sistema informatico qwin permette un monitoraggio più preciso.\nLe diverse rilavorazione eseguite su Broedani, Rossi e Cogmeme,  hanno influito in maniera importante sul valore di questo KPI.\nIn particolare molte internal NC non causate da errori di manipolazione di componenti e/o imballi da parte degli operatori di produzione','Aumentare il livello di controllo sui processi. Aumentare il livello di conoscenza tecnica del personale di produzione con formazioni mirate. Maggiore presenza dei responsabili di produzione in officina per correggere e formare tutte le attività legate strettamente all\'operatore.   ','/snap/96_1573286932.png',1);
INSERT INTO `assessment_widget` VALUES (448,94,2019,'IV TRI',NULL,'Il valore medio 2019 è al di spora del target ma migliorato rispetto all\'anno precedente. Le rilavorazioni e scarti generati nei primi due trimestri hanno fatto si che il valore medio complessivo abbiamo portato l\'indice in fascia negativa. Da imputare per il secondo semestre alla problemati di CMT che sviluppa un numero elevato di pezzi scarto.\nAnche le rilavorazioni di Brovedani incidono molto su queto indice data la numerosità del lotto di produzione.','Vedi strategia Internal NC.','/snap/94_1667298588416.png',1),(449,95,2019,'IV TRI',NULL,'Valore medio registrato nel2019 risulta di  368 PPM, migliorato rispetto al 2018 ove si registra un valore medio 1535 PPM.\nL\'indice risulta essere mediamente sotto il traget. Si nota una impennata del valore nel mese di maggio proprio a causa della problematica con CMT. ','Migliorata  e irrobustita la procedura sulla gestione dei cicli termici. Acquisito  nuovo software Power BI per aumentare il livello di efficacia per la gestione dei cicli termici e loro modifiche.  ','/snap/95_1573286948.png',1),(450,98,2019,'IV TRI',NULL,'Il valore 2019 pari a 1.09 % risulta leggermente superior al target del 1% e in miglioramento rispetto al valore 2018 (1.47%).\nIl primo trimestre è interessato da un importante innalzamento del KPI dovuto alla problematica di Bellino (vedi 8D) di riferimento.','Continuare con le attività di sensibilizzazione e formazione a gli operatori sui metodi di lavoro e sulle criticità dei prodotti/clienti.\nDa migliorare l\'aspetto legato alle  rilavorazioni. Spesso si corre per saturare gli impianti ma non si condivide con UT le criticità dei prodotti. Si ritiene necessario modificare  la procedura sulla campionatura attraverso un controllo di tutte le campionatura da parte di UT e contestualmente automazione del modulo 8D su QWIN .  ','/snap/98_1573286959.png',1),(451,151,2019,'IV TRI',NULL,'Questo KPI è stato inserito nel corso dell\'anno 2019 pertanto non è possibile apprezzare eventuali inflessioni rispetto al 2018.\nMediamente il valore medio di chiusura attività è decisamente sotto il target. Nel 2° trimestre il valore supera il taget per attività legata all\'acquisto di uno strumento di controllo (micrometro)','Insistere con le riunioni settimanali per il monitoraggio delle attività legate alle non conformità (8D report).','/snap/151_1573286963.png',1),(452,152,2019,'IV TRI',NULL,'Anche questo indice viene introdotto nel 2019. Si registra un andamento medio leggermente sopra il target. ','Insistere con la formazione continua  degli operatori e sulla consapevolezza che la manipolazione dei particolari ha impatto critico sulla qualità dei prodotti (formazioni , OPL bacheca) .  Inoltre è necessario puntare sulla formazione continua di difetti in modo da migliorare la capacità di detection degli operatori (OPL) ','/snap/152_1573286965.png',1),(464,108,2019,'IV TRI',NULL,'Dato Positivo e sotto il target. L\'indice risulta essere migliorato rispetto il 2018.','Continuare con la strategia delle riunioni giornaliere mirata alla definizione delle attività legate alle nuove produzioni.','/snap/108_1573290680.png',1);
INSERT INTO `assessment_widget` VALUES (466,107,2019,'IV TRI',NULL,'Il valore medio registrato nel 2019 è di 94%, sopra al target e sopra al medio del 2018 di 90.6%\nNel primo trimestre non si raggiunge il 100% a causa della campionatura eseguita su STA2000 ove richiesto un valore di durezza superficiale troppo elevato rispetto al materiale e trattamento eseguito. Buono il risultato del del secondo trimestre. Il terzo periodo analizzato registra un 87% di efficacia. Inferiore sia all\'anno precedente che al target. In questo caso pur avendo eseguito una campionatura conforme a livello di specifiche tecniche si è ritenuto di registrare la campionatura come non ok in virtù delle deformazioni indotte dal trattamento di bonifica sul pezzo. L\'indice non raggiunge il target anche a causa di un numero ridotto di campionature eseguite.','Revisionare la procedura di industralizzazione in modo da monitorare meglio sia il numero delle campionature eseguite che gli esiti.\nSensibilizzare i clienti ad eseguire campionature a pagamento con cicli dedicati piuttosto che eseguire prove gratuite con cicli standard e risultati negativi.\n','/snap/107_1573290675.png',1),(470,143,2019,'IV TRI',NULL,'Il valore medio del 2019 risulta essere inferiore al target.\nRisultato positivo.\nL\'organizzazione è riuscita ad eseguire campionature girando i costi vivi delle stesse ai clienti.  Questo lavoro è stato possibile grazie ad una robusta collaborazione di UT e COM','Continuare con la strategia intrapresa','/snap/143_1573297607.png',1),(471,114,2019,'IV TRI',NULL,NULL,NULL,'/snap/114_1580462816.png',1),(473,124,2019,'IV TRI',NULL,NULL,NULL,'/snap/124_1580404537.png',1),(476,153,2019,'IV TRI',NULL,NULL,NULL,'/snap/153_1580463982.png',1),(477,150,2020,'III TRI',NULL,NULL,NULL,'/snap/150_1603204048.png',1),(478,147,2020,'III TRI',NULL,NULL,NULL,'/snap/147_1603200078.png',1),(479,130,2020,'III TRI',NULL,NULL,NULL,'/snap/130_1603200074.png',1),(480,125,2020,'III TRI',NULL,'','','/snap/125_1603443504.png',1),(482,109,2020,'III TRI',NULL,NULL,NULL,'/snap/109_1603024820.png',1),(484,111,2020,'III TRI',NULL,NULL,NULL,'/snap/111_1603024852.png',1),(485,112,2020,'III TRI',NULL,NULL,NULL,'/snap/112_1603024887.png',1),(486,110,2020,'III TRI',NULL,NULL,NULL,'/snap/110_1603275324.png',1),(487,113,2020,'III TRI',NULL,NULL,NULL,'/snap/113_1603024944.png',1),(488,100,2020,'III TRI',NULL,NULL,NULL,'/snap/100_1603025031.png',1),(489,135,2020,'III TRI',NULL,'le non conformità logistica nel I trimestre si nota che sono decisamente più basse in confronto all\'anno precedente, mentre nel II trimestre maggiore disattenzione dovuto a minore controllo da parte ufficio logistica (in smart working) ','controllo continuo e costante da parte ufficio logistica, sensibilizzare maggiormente gli addetti per svolgere le proprie mansioni in modo più attento','/snap/135_1602576313.png',1),(490,154,2020,'III TRI',NULL,'tutti i costi medi restano sotto il target, la zona di Ancona è quella dove risulta il costo medio più alto, mentre il trasporto sulla zona di BARI è quello con costi più bassi, anche se nel III trimestre i costi medi sono aumentati  per volumi diminuiti per forno a pozzo fuori uso. ','da luglio la zona di Ancona viene effettuata dal vettore Palena e dal primo settembre anche la zona LAZIO è stata affidata a Palena, questo per contenere in parte i costi (con volumi bassi inferiori a 13000kg è più conveniente il corriere esterno) ma soprattutto per contenere tutti i rischi legati al trasporto con mezzo proprio','/snap/154_1602575469.png',1),(492,153,2020,'III TRI',NULL,NULL,NULL,'/snap/153_1602574866.png',1),(494,121,2020,'III TRI',NULL,NULL,NULL,'/snap/121_1602574806.png',1);
INSERT INTO `assessment_widget` VALUES (496,123,2020,'III TRI',NULL,'analizzando il grafico si nota che il settore del vuoto e dell\'induzione continuano ad essere i reparti più in sofferenza.\nAnche il reparto NCV risulta oltre il target nonostante il nuovo impianto','monitorare continuamente e in caso di ritardo oltre i 7 gg. confrontarsi con i responsabili di reparto','/snap/123_1602574725.png',1),(498,128,2020,'III TRI',NULL,'i costi extra trasporti risultano diminuiti rispetto all\'anno precedente tranne che per il III trimestre, ma riguarda soprattutto ritardi di produzione non imputabili alla logistica','mantenere sempre alta attenzione  e controllo da parte ufficio logistica e magazzinieri','/snap/128_1602574719.png',1),(514,88,2020,'III TRI',NULL,NULL,NULL,'/snap/88_1602687694.png',1),(515,91,2020,'III TRI',NULL,NULL,NULL,'/snap/91_1602687701.png',1),(516,141,2020,'III TRI',NULL,NULL,NULL,'/snap/141_1602686089.png',1),(520,89,2020,'III TRI',NULL,NULL,NULL,'/snap/89_1602687698.png',1),(521,90,2020,'III TRI',NULL,NULL,NULL,'/snap/90_1602687699.png',1),(523,69,2020,'III TRI',NULL,NULL,NULL,'/snap/69_1602861273.png',1),(524,87,2020,'III TRI',NULL,NULL,NULL,'/snap/87_1602861281.png',1),(526,72,2020,'III TRI',NULL,NULL,NULL,'/snap/72_1602861287.png',1),(528,73,2020,'III TRI',NULL,NULL,NULL,'/snap/73_1602861293.png',1),(531,74,2020,'III TRI',NULL,NULL,NULL,'/snap/74_1602861296.png',1),(533,78,2020,'III TRI',NULL,NULL,NULL,'/snap/78_1602861303.png',1),(535,79,2020,'III TRI',NULL,NULL,NULL,'/snap/79_1602861305.png',1),(537,80,2020,'III TRI',NULL,'Il target è raggiunto e superato ','Continuare con la strategia di diversificare il più possibile il fatturato su più clienti. ','/snap/80_1602869401.png',1),(539,81,2020,'III TRI',NULL,NULL,NULL,'/snap/81_1602869268.png',1),(541,82,2020,'III TRI',NULL,NULL,NULL,'/snap/82_1602861309.png',1),(543,136,2020,'III TRI',NULL,'La percentuale pià alta per valore è individuabile nelle offerte in stand-by. Questo dato è un fattore positivo in quanto rappresentativo di potenziale guadagno. Il secondo motivo di rinuncia per valore è rappresentato dalla quotazione Temprasud elevata, in particolare assegnabile alle offerte di valore economico molto elevato non andate in porto come quelle del cliente Bonfiglioli.','Seguire lo sviluppo dei progetti nuovi in stand-by.\nIntraprendere con i clienti che hanno valutato le offerte troppo elevate una politica commerciale di negoziazione con eventuali incontri presso il ns stabilimento al fine di poter essere attivi come potenziali fornitori   nella valutazione di nuove rdo.\n  ','/snap/136_1602861311.png',1),(545,83,2020,'III TRI',NULL,'Nel corso del 2020 abbiamo ricevuto offerte di  valore economico elevato ma attualmente ancora in fase di valutazione da parte dei clienti e complessivamente il numero delle offerta emesse è stato inferiore rispetto all\'anno precedente. La principale motivazione è da ricercarsi  al periodo di lockdown e durante il quale non abbiamo ricevuto nuove rdo e a causa del quale sono stati sospesi i nuovi progetti e di conseguenza e posticipate  le relative date di inizio valutazione.','Continuare con il monitoraggio delle offerte in stand by al fine di individuare nuovi possibili scenari.  ','/snap/83_1602861312.png',1);
INSERT INTO `assessment_widget` VALUES (547,85,2020,'III TRI',NULL,'Dall\'analisi ottenuta con interviste dirette (telefoniche e tramite mail) più della metà delle offerte emesse non è andato in porto a causa della mancata produzione dei pezzi, ovvero il mancato ottenimento del progetto. Mentre il 28.4% delle offerte emesse non è attualmente in stand-by per la principale motivazione  della sfavorevole condizione del mercato che non favorisce l\'avvio dei nuovi progetti in tempi rapidi. Le quote percentuali di offerte perse a causa della quotazione temprasud elevata sono ridotte a conferma dell\'allineamento prezzi alla concorrenza.','Migliorare l\'efficienza nel monitoraggio delle offerte in stand by per i progetti in fase di sviluppo \nAdozione,  per le offerte di nuova emissione della strategia di allineamento target cliente in favore di volumi maggiori. \n','/snap/85_1602861314.png',1),(549,84,2020,'III TRI',NULL,'Dopo un peggioramento delle abitudini di pagamento iniziato nel 2018 e un allineamento ad un valore massimo di 90 gg del 2019, nel 2020  sono aumentati i giorni di ritardo le aziende che\nsforano le scadenze per più di due mesi. \nCiò è stato dovuto alle difficoltà riscontrate durante i periodi di lock down,  tra i  più colpiti dalle conseguenze dell’emergenza sanitaria, una quota maggiore di società in grave ritardo si osserva nella filiera automotive (-11,7% di ricavi con una percentuale di imprese in grave ritardo già superiore al 10%) dato Cerved Industry Forecast.\n','Per il futuro occorre recuperare il valore obiettivo di 90 gg quindi monitorare a fine anno la solvibilità dei clienti attraverso la verifica delle variazioni del rischio di credito che normalmamente viene efftuata una volta l\'anno pertanto ripeterla a fine anno al fine di analizzarne il trend ad un maggiore livello di dettaglio. Inoltre valutare la possibilitò di concedere degli acconti sul prezzo al fine di ridurre il rischio di insolvenza.  \nSospendere oltre alle spedizioni anche le lavorazioni al verificarsi del secondo insoluto.','/snap/84_1602861315.png',1),(551,68,2020,'III TRI',NULL,NULL,NULL,'/snap/68_1602861317.png',1),(553,86,2020,'III TRI',NULL,'Non è stato possibile completare nell\'anno 2020, causa covid,  il processo di aumenti ai clienti iniziato nel 2019. \nIn considerazione della difficile ripresa economica e delle richieste di riduzione costi e allungamento tempi di pagamento sono stati concessi alcuni sconti sui listini  dato il procrastinarsi della situazione economica precaria, al fine di adeguare i nostri prezzi a quelli dei concorrenti e migliorare la redditività.  ','Per il futuro utilizzare politiche  alternative che riguarderanno:\n- la qualità del prodotto;\n- l\'intensificazione dello sforzo di vendita;\n- l\'implementazione del marketing e della comunicazione;\n- l\'implementazione del servizio di trasporto come servizio supplementare\n','/snap/86_1602863738.png',1),(588,127,2020,'III TRI',NULL,NULL,NULL,'/snap/127_1603443502.png',1),(589,126,2020,'III TRI',NULL,NULL,NULL,'/snap/126_1603443499.png',1),(591,131,2020,'III TRI',NULL,NULL,NULL,'/snap/131_1603463159.png',1),(607,132,2020,'III TRI',NULL,NULL,NULL,'/snap/132_1603443469.png',1),(614,119,2020,'III TRI',NULL,NULL,NULL,'/snap/119_1603527692.png',1),(615,116,2020,'III TRI',NULL,NULL,NULL,'/snap/116_1603527743.png',1),(617,120,2020,'III TRI',NULL,NULL,NULL,'/snap/120_1603527748.png',1),(618,118,2020,'III TRI',NULL,NULL,NULL,'/snap/118_1603527752.png',1),(619,149,2020,'III TRI',NULL,NULL,NULL,'/snap/149_1603527822.png',1),(621,98,2020,'III TRI',NULL,NULL,NULL,'/snap/98_1603534176.png',1),(622,95,2020,'III TRI',NULL,NULL,NULL,'/snap/95_1603534178.png',1),(623,97,2020,'III TRI',NULL,NULL,NULL,'/snap/97_1603534181.png',1),(624,96,2020,'III TRI',NULL,NULL,NULL,'/snap/96_1603534183.png',1),(625,94,2020,'III TRI',NULL,NULL,NULL,'/snap/94_1603534187.png',1),(626,151,2020,'III TRI',NULL,NULL,NULL,'/snap/151_1603534189.png',1),(627,152,2020,'III TRI',NULL,NULL,NULL,'/snap/152_1603534192.png',1);
INSERT INTO `assessment_widget` VALUES (628,107,2020,'III TRI',NULL,NULL,NULL,'/snap/107_1603705145.png',1),(632,108,2020,'III TRI',NULL,NULL,NULL,'/snap/108_1603705148.png',1),(633,143,2020,'III TRI',NULL,NULL,NULL,'/snap/143_1603705152.png',1),(634,71,2020,'III TRI',NULL,'Il costo di indebitamento della Tempra sud rimane costante a differenza dei concorrenti per i quali aumenta. Unico concorrente non indebitato è la general tempering','Mantenere un basso costo di indebitamento spostando il più possibile il debito a medio lungo periodo e sfruttando DL Liquidità ','/snap/71_1603822697.png',1),(635,70,2020,'III TRI',NULL,'Nel 2019 a causa della riduzione del fatturato la marginalità è ridotta per tutti i concorrenti ad eccezione della Tempra sud che si colloca in seconda posizione ','Mantenere una marginalità minima del 5% anche nel 2020 evitando riduzione prezzi e calmierando aumento dei costi .','/snap/70_1603822693.png',1),(638,101,2020,'III TRI',NULL,'Nel 2019 la Tempra sud è riuscita a ridurre l\'indebitamento % rispetto al limite del 80% del fatturato .','Cercare di mantenere l\'indebitamento ad un limite sostenibile in ogni caso non superiore al 90% del fatturato nel 2020 ','/snap/101_1603822698.png',1),(639,105,2020,'III TRI',NULL,'Nel 2019 la politica di investimento tempra sud ha visto un rallentamento come pianificato. ','Anche nel 2020 sono previsti piccoli investimenti di assestamento con nuovi investimenti in forno in vuoto previsti nel 2021 ','/snap/105_1603822700.png',1),(640,103,2020,'III TRI',NULL,'L\'ebtda % nel 2019 si è leggermente ridotto a causa della riduzione del margine operativo lordo . ','Nel 2020 in considerazione del covid si cercherà di mantenere un valore EBTDA > 10% del fatturato ','/snap/103_1603822647.png',1),(641,104,2020,'III TRI',NULL,'ROI 2019 in linea con il valore del 2018 in riduzione rispetto al valore degli anni precedenti a causa dell\'incremento del patrimonio netto . ','Mantenimento del valore di ROI anche nel 2020 al di sopra del valore minimo del 5% ','/snap/104_1603822703.png',1),(642,106,2020,'III TRI',NULL,'Nel 2019 i crediti persi in quanto non più esigibili hanno toccato il valore minimo da 6 anni . ','Nel 2020 a causa della crisi COVID si attende un aumento di perditge su credite a causa di liquidazioni e concordati . E\' necessario monitorare attentamente i ritardi di pagamento ','/snap/106_1603822690.png',1),(646,102,2020,'III TRI',NULL,'Se nel 2019 tale indicatore aveva raggiunto il valore minimo . Nel 2020 a causa del covid vi è stata un impennata di insoluti nel primo semestre. ','L\'allungamento dei tempi di pagamento concordato ai clienti meritevoli dovrebbe evitare l\'aumento di insoluti che impattano negativamente sul rating bancario ','/snap/102_1603822371.png',1),(648,155,2020,'III TRI',NULL,'A livello di costo delle materie prime la tempera sud nel 2019 si pone al 3° posto .','Necessario avviare una verifica dei costi e consumi di materie prime in modo da posizionarsi in modo competitivo rispetto ai competitors','/snap/155_1603822409.png',1),(660,130,2021,'I TRI',NULL,'Si identifica, in maniera evidente, una diminuzione del numero di NC globali nei trimestri analizzati. Il valore medio si attesta al 0.69 % di commesse non conformi su commesse prodotte (target dello 0.3% non raggiunto). La totalità delle NC si riscontrano nel campo QUALITA\'.\nInoltre il valore è diminuito rispetto allo stesso periodo del 2020 e pari al 0,89%.Ciò è correlato ad una più attenta analisi delle NC avvenute, alla struttura ed alle procedure di gestione più precisa ed a un sistema più recettivo all’identificazione delle deviazioni (prima, quindi, che si trasformino in problemi). ','1) Aumentare il livello di controllo per le tematiche ambientali. Negli audit di processo/prodotto e sistema inserire anche una analisi dei problemi ambientali laddove possibile (nota: modificato pianificazione audit 2021).\n2) Continuare sulle attività di formazione e sensibilizzazione così come previsto.','/snap/130_1617956498.png',1);
INSERT INTO `assessment_widget` VALUES (663,147,2021,'I TRI',NULL,'Target di 1 attività aperta per trimestre (nel plant) raggiunto.\n\nSi verifica una preponderanza di azioni correlate ad audit di processo/sistema/prodotto. ','1) Riunioni periodiche per attività di brain storming e a seguire attività atte a migliorare l\'azienda\n ','/snap/147_1617960453.png',1),(665,150,2021,'I TRI',NULL,'Non si è raggiunto l’obiettivo della chiusura dei task. Ciò è dovuta ad un’interruzione dell’attività lavorativa causa epidemia Covid. Alcune attività correlate alla revisione del sistema (revisione procedure, aggiornamento matrice di poli competenza, aggiornamento procedure per sistema ISO 45001) hanno comportato un piano di formazione non ancora completato. ','Continuare con:\n1)formazione al personale interno.\n2) chiusura attività emerse nell\'anno 2020','/snap/150_1617981884.png',1),(669,109,2021,'I TRI',NULL,'Nel primo trimestre del 2021 abbiamo  un valore del  3.73% sopra al target (3%). Ciò è dovuto, principalmente ai primi mesi del 2021 su cui si risente ancora del periodo pandemico 2020 (infatti 3 su 4 malati in quarantena).\nNel secondo trimestre il valore  è di 4,45% superiore al target e più alto del primo trimestre ( 3,73%)\nLa causa è dovuta principalmente alle assenze di alcuni dipendenti per malattie personali.\nEssendo diminuita l\'influenza pandemica su questo secondo trimestre ci si chiede se l\'assenteismo sia dovuto a motivi aziendali, in quanto molti dei malati hanno lamentato mal di schiena, tanto più che da un\'analisi più estesa e cioè dal 2018 al 2021 il valore dell\'assenteismo è salito da 2,88 a giugno 2021 con 4,45; escludendo il 2020 dove l\'aumento è dovuto alla pandemia ci troviamo di fronte ad un valore più alto che ci porta a riflettere. ','La strategia adottatain questi anni è stata sempre la politica degli incentivi (buono pasto impiegati e premio per capiturno) con lo scopo di migliorare il target con l\'accordo di secondo livello che prevede l\'estensione dei premi presenza dai capiturno a tutti gli operatori e ulteriori premi legati al conseguimento di determinati risultati al di sotto di una % di assenza.\nL\'accordo è stato sottoscritto il 28/06/21.Da un lato dobbiamo attendere il prossimo semestre per riscontrare  i benefici dell\'accordo, dall\'altro dovremmo monitorare, se eventuali malattie sono imputabili a cause aziendali, nel senso di predisporre altre misure oltre a paranco e carroponte idonee ad evitare sforzi dell\'operatore.\n(sollevatori automatici)','/snap/109_1630933128.png',1),(670,111,2021,'I TRI',NULL,'A partire dal 2018 (13,75%) sino al 2020 abbiamo assistito ad una graduale \nriduzione della % di ferie (11% nel 2019) dovuta alla turnazione a scorrimento e a piani di ferie concordati, oltre all\'elemento pandemico che nel 2020 ha contribuito a ridurre il target incidendo negativamente sul fatturato.\nNel primo semestre 2021 possiamo dire che si sia stabilizzata la % ( vedendo i valori nel dettaglio notiamo che essi sono pressochè simili tranne la risalita a giugno per aumento del fatturato e anche delle ore di assenza per malattia, ma siamo cmq al di sotto del target) probabilmente ciò è dovuto alla turnazione giornaliera che incide  su metà del personale di produzione (su 24, 12 sono giornalieri) per la quale, in caso di ferie, i dipendenti sono  più facilmente sostituibili.\nDalla\nmia analisi rimane comunque un\'alta % di residuo ferie per i turnistie alcuni giornalieri.','Attendere il prossimo assesment per valutare appieno i benefici della nuova turnazione    a lungo termine e continuare con piani di ferie concordati, non solo per gli impiegati, ma anche per i capiturno e per gli operai che hanno il maggior numero di ferie residue.','/snap/111_1627398900.png',1);
INSERT INTO `assessment_widget` VALUES (671,112,2021,'I TRI',NULL,'Sia nel primo che nel secondo trimestre 2021 non si registrano infortuni. \nPer quanto riguardano i quasi infortuni la % degli ultimi 12 mesi riferita al primo trimestr è 0,03% ( rilevandosi 2 quasi incidenti a Marzo (come da analisi near missis: rottura attrezzo durante il sollevamento per la tempra MB probabile per usura Savini-a causa del malfunzionamento   porta induzion Bolognese urta con il carrello) \nnel secondo trimestre la % è 0 rilevandosi solo  ad aprile 1 quasi  incidente come da analisi near missis( Palumbo nello scarico degli attrezzi non posizionati in modo stabile,cade una griglia sul parabrezzo del carrello elevatore).','Per quanto riguardano gli infortuni:\ncontinuare con formazioni sulla sicurezza (corsi cogenti e non, uso dpi,formazione sui rischi- mansione(formazione pianificata e ancora in itinere)\nPer quanto concernono i quasi infortuni, con l\'accordo di secondo livello  Implementeremo un sistema di denuncia di condizioni/azioni non sicure/ quasi incidenti, attraverso riunioni trimestrali con il comitato di rappresentanza, i resposabili di funzionee chiunque sia interessato.\nL\'obiettivo è  rafforzare l\'azione preventiva in materia di sicurezza e ottenere la certificazione ISO 45001. \n','/snap/112_1630933160.png',1),(672,110,2021,'I TRI',NULL,'Il valore dal 2018 (8,64 %) si è ridotto per inserimento di nuove risorse, turnazione a scorrimento e nel 2019 si è ulteriomente ridotto(5,56%) sia introducendo nuove risorse (seppure poche) sia adottando regole più stringenti per autorizzazione degli straordinari. Nel 2020 la riduzion è dovuta alla pandemia.Nel primo semestre 2021 si è stabilizzato il valore con % del 3,11% \nper implementazione della turnazione giornaliera che oltre a garantirre una migliore distribuzione dell\'orario di lavoro, incide positivamente sugli straordinari riducendo indennità notturne e pomeridiane.\n','Valutare i risultati di questa turnazione\nnel prossimo assessment ','/snap/110_1630933182.png',1),(673,113,2021,'I TRI',NULL,NULL,NULL,'/snap/113_1618467732.png',1),(679,88,2021,'II TRI',NULL,'Nessuna N.C.nel secondo trimestre 2021 .l\'assenza di Non Conformità potrebbe avere come effetto il calo dell\'Efficienza e dello stato di Attenzione da parte dei Fornitori nella gestione delle forniture','Costante Monitoraggio dei Fornitori,\n','/snap/88_1626865652.png',1),(680,89,2021,'II TRI',NULL,'Non si riscontra ritardi, materiale consegnato come da richiesta rispettando le tempistiche indicate dai Fornitori','Mantenimento \ndegli standard\nRaggiunti','/snap/89_1626865897.png',1),(681,90,2021,'II TRI',NULL,'Tutte le forniture e i relativi ordini non hanno subito ritardi.\nBuona la pianificazione \nnella gestione degli ordini\npermettendo anche un efficiente pianificazione\nnelle forniture da parte dei Fornitori ','Mantenimento \ndegli standard\nRaggiunti','/snap/90_1628010018.png',1),(682,91,2021,'II TRI',NULL,'Situazione Positiva e incoraggiante rispetto agli andamenti del mercato.\nIl contenimento e l\'assenza di variazioni derivano da accordi che vincolano i fornitori al rispetto dei prezzi sulla base di accordi contrattuali con effetti a medio e lungo termine.','l\'obiettivo più importante è contenere eventuali aumenti derivanti\nA: da scadenze di contratto \nB: da richieste su forniture non vincolate da Contratti sulle quali i fornitori potrebbero applicare rincari derivanti dall\'aumento dei costi delle Materie prime \nStrategia: \nutilizzo gruppo di Acquisto e eventuali omologazioni di prodotti Univoci per entrambi gli Stabilimenti','/snap/91_1626701816.png',1),(683,93,2021,'II TRI',NULL,NULL,NULL,'/snap/93_1618484044.png',1),(684,141,2021,'II TRI',NULL,NULL,NULL,'/snap/141_1626701837.png',1);
INSERT INTO `assessment_widget` VALUES (685,88,2021,'I TRI',NULL,'Nessuna NC aperta nel primo trimestre 2021, grazie all\'emissione di ordini dettagliati ed alla selezione attenta di fornitori','Condurre analisi delle non conformità in caso di problematiche su forniture attraverso emissione modulo MO 6.15 da parte della Tempra Sud (come riportato in Riesame 2020)','/snap/88_1618484122.png',1),(686,89,2021,'I TRI',NULL,'Target raggiunto e conforme allo stesso periodo del 2020. Non si sono riscontrati e addebitati costi extra dovuti a ritardo ','Come stabilito in Riesame 2020 continuare su questo percorso.','/snap/89_1618484125.png',1),(687,90,2021,'I TRI',NULL,'Obiettivo raggiunto e migliore dello stesso periodo anno precedente (con soli 3 ordini in ritardo).','Continuare sul percorso di tenuta sotto controllo del fornitore.','/snap/90_1618484128.png',1),(688,91,2021,'I TRI',NULL,'Costo medio delle materi prime in discesa rispetto al precedente anno e sotto il target stabilito.','Si prosegue con la strategia futura stabilita nel 2021 (stabilizzazione dei prezzi evitando qualsiasi variazione al rialzo cercando di abbattere i costi con accordi di fornitura a prezzi invariati e fissi che vincolano il fornitore, utilizzando la leva dei consumi nel medio e lungo termine e sfruttando i volumi di Unitrat.)','/snap/91_1618484130.png',1),(689,93,2021,'I TRI',NULL,NULL,NULL,'/snap/93_1618484132.png',1),(690,141,2021,'I TRI',NULL,NULL,NULL,'/snap/141_1618484135.png',1),(695,100,2021,'I TRI',NULL,'Il valore di investimento in formazione nel primo trimetre 2021 è 1,02%,pertanto superiore al target (03%)contro lo 0,48 del trimestre 2020.\nNel secondo trimestre il valore sale a 1,12% contro lo 0,70 del 2020.\nL\'aumento dell\'investimento in formazione è dovuto al calare dell\'emergenza pandemica.\n','Continuare con i piani di formazione continua/cogente e non , soprattutto in vista della certificazione sulla sicurezza iso 45001.','/snap/100_1630933475.png',1),(697,128,2021,'I TRI',NULL,'si evince un incremento ma è correlato ad un unico trasporto e al chilometraggio percorso eseguito nel trimestre con mezzo proprio  ','continuare con la strategia proposta nell\'esame 2020, continuando ad eseguire controlli da parte dell\'ufficio logistica','/snap/128_1626848471.png',1),(698,123,2021,'I TRI',NULL,'si denota che l\'unico valore fuori specifica è il vuoto, dovuto alla difficoltà di effettuare cariche mix per varie tipologie di lega. Delle rimanenti aree di t.t. l\'induzione presenta un numero maggiore di commesse in ritardo rispetto a quelle trattate, sicuramente dovuto all\'assenza per motivi di salute personali di 1 risorsa su 3','Monitorare e segnalare i ritardi al responsabile di reparto','/snap/123_1618559551.png',1),(699,121,2021,'I TRI',NULL,NULL,NULL,'/snap/121_1618558891.png',1),(700,153,2021,'I TRI',NULL,NULL,NULL,'/snap/153_1626848313.png',1),(701,135,2021,'I TRI',NULL,'nel I trimestre abbiamo avuto una unica non conformità','la strategia adottata, oltre ad effettuare controlli programmati come nel 2020, sarà quella di mettere un responsabile di reparto (Alex Di Fonzo) come supervisore','/snap/135_1626848440.png',1),(702,154,2021,'I TRI',NULL,'i costi nella zona di bari risultano più bassi in quanto il trasporto viene ottimizzato viaggiando quasi sempre a pieno carico. In Abruzzo dal mese di febbraio i trasporti sono stati eliminati avendo costi eccessivi rapportati al fatturato dei clienti coinvolti. Per le zone di Ancona e Lazio  rapportando il I trimestre al IV 2020 i costi sono aumentati per   per un aumento di kg trasportati (x Lazio incremento di fatturato del 13%, per Ancona dell\' 8%)','continuare fino a dicembre 2021 con i trasporti a mezzo vettore Palena, continuando a monitorare i costi','/snap/154_1626848275.png',1);
INSERT INTO `assessment_widget` VALUES (710,126,2021,'I TRI',NULL,'Analizzando il diagramma della produttività nel 1°semetre 2021 siamo al di sotto del valore target pari al 70%. Oltretutto, rispetto allo stesso periodo del 2020 abbiamo un netto calo produttivo nei mesi di gennaio e marzo. \nLe probabili cause sono analizzate nel diagramma a torta relativamente alle analisi delle perdite.\n','Vedi \"Analisi perdite induzione\".','/snap/126_1618846050.png',1),(713,127,2021,'I TRI',NULL,'La saturazione degli impianti è si al di sotto del target (pari al 50%) ma con un trend crescente negli ultimi mesi.','Continuare con il programma riportato in Riesame 2020.','/snap/127_1618846064.png',1),(714,131,2021,'I TRI',NULL,'Per quanto riguarda la produttività oraria, prendendo come riferimento la Produzione in serie dei perni del cliente Fiorella, siamo al di sopra del valore target e in linea con l’andamento annuale.','Nessuna azione.','/snap/131_1618846072.png',1),(715,125,2021,'I TRI',NULL,'Rispetto al 2020, come si evince confrontando i due diagrammi a torta delle analisi delle perdite, si nota un aumento di quest’ultime relativamente a:\n1.	Tempo messa a punto (delta 4%)\n2.	Tempi set-up (delta 5%) \nLe cause principali sono da imputare a:\n1. assenza del CT di reparto, dunque, le lavorazioni sono state effettuate da lavoratori meno esperti il che giustifica l’aumento dei tempi di set-up e messa a punto ciclo.\n2.Impianto IND2 in manutenzione straordinaria (soprattutto nel mese di marzo), pertanto tutte le lavorazioni che generalmente venivano fatte su questo impianto sono state dirottate sugli altri impianti (principalmente sulla IND4), con conseguente aumento dei tempi di set-up, aumento dei tempi di messa a punto, a questo bisogna aggiungere il tempo necessario per adattare le attrezzature e gli induttori, normalmente utilizzati sulla IND2, ai vari impianti.\n3. Ore di formazione pianificate e in corso degli operatori meno esperti su costruzione induttori e docce (tempo improduttivo).\n','Continuare con il programma stabilito in Riesame 2020 del 03/09/2020. Non si è provveduto ad acquisto di un durometro portatile.','/snap/125_1618895008.png',1),(744,86,2021,'II TRI',NULL,'Dall\'inizio dell\'anno 2021  abbiamo subito un forte incremento dei costi energetici, delle materie prime di processo, comprese attrezzature industriali ed inoltre da  Luglio 2021 per gli effetti dell\'aggiornamento del contratto CCNL vi sarà un ulteriore incremento anche del costo della manodopera. Per tale ragione l\'attività di aumenti a clienti sospesa nell\'anno 2020 causa covid è ripresa attraverso emissione nuovo listino prezzi generico da inviare a tappeto a tutti i clienti di fascia B e C e aumenti a clienti con listini specifici secondo file analisi aumenti.','Portare avanti attività di aumneto secondo le scadenze stabilite da file.\n','/snap/86_1627040856.png',1),(745,84,2021,'II TRI',NULL,'Dati attualmente non disponibili per migrazione file a sistema Cloud','Da valutare dopo ripristino KPI','/snap/84_1623315459.png',1),(746,83,2021,'II TRI',NULL,'Nel corso del 2021 sono state emesse offerte per circa 4.388.000 euro. Inoltre il valore delle offerte confermate è inferiore al target di 500.000 euro.','Monitorare il valore delle offerte in standby e le offerte confermate affinchè siano rispettati i volumi oggetto dell\'offerta.','/snap/83_1628092446.png',1);
INSERT INTO `assessment_widget` VALUES (747,136,2021,'II TRI',NULL,'Sono in stand by le offerte con volume di affare maggiore (es: CNH, SIAP, ROSSI) . \nRelativamente al 2021 le principali 5 offerte perse emerse dall\'analisi di pareto sono :\nSIAP S.P.A.\nTR VIC spa\nMARVIT SPA\n3 M TECNOLOGIE MECCANICHE SRL\nCAGNONI SRL\ndi queste l\'offerta chiusa di SIAP (che da sola prende il 41% del vaore sulle prime 5)  è legata ad un ad un cambio di progetto in funzione del quale il cliente finale sceglie la tempra in spina e non più cementazione e tempra. Delle altre 4 offerte due sono per quotazione troppo alte (3 M TECNOLOGIE MECCANICHE SRL\nCAGNONI SRL).\n','A seguito analisi di Pareto sulle prime 5 offerte non ottenute. si consiglia\n1) Diminuzione dei prezzi su offerte valutate troppo elevate\n','/snap/136_1628092359.png',1),(748,81,2021,'II TRI',NULL,'24 clienti  generano l\'80% del fatturato (fascia A) pertanto il target di 20 è superato; \n','Mantenere il target obbiettivo ai fini di una diversificazione ottimale.','/snap/81_1627042868.png',1),(749,78,2021,'II TRI',NULL,'Si conferma per il 60.1% , predoniminante, il fatturato della macroarea LLF., a seguire  NCV , IND, TV.','Tenendo conto che a 09/2021 verrà consegnato un secondo forno di TV, è necessario acqusire offerta vuoto 337081 (SIAP). Comunicare a tappetto \nla nuova capacità reparto TV.','/snap/78_1628093145.png',1),(750,77,2021,'II TRI',NULL,NULL,NULL,'/snap/77_1623059856.png',1),(751,75,2021,'II TRI',NULL,NULL,NULL,'/snap/75_1623059860.png',1),(752,74,2021,'II TRI',NULL,'aggiornamento formula in corso Da calcolo corretto rispetto al budget 2021 si registra una decremento del 5% Rispetto al fatturato totale fino al 30.06.2021 una valore positivo con  17.60%. ','Monitorare la situazione di alcuni clienti critici, chiamandoli e chiedendo previsioni fino a fine anno sui volumi, (che hanno avuto fermi produttivi durante l\'anno  e diminuzioni delle quantità inviate Ben Vautier, Omme,  Weatherford Cebi)selezionati come da file \"situazione fatturato 2021\" ','/snap/74_1628093174.png',1),(753,73,2021,'II TRI',NULL,'L\'andamento del fatturato segue quanto ipotizzato nel budget previsionale 2021. Si attende fine anno per stabilire se i risultati sono stati raggiunti.\nIl budget teneva conto dell\'acquisizione di un nuovo cliente (Bonfiglioli), tuttavia abbiamo registrato perdite di fatturato a causa del trend negativo dei nostri clienti di fascia A per crisi chip (settore automotive) con blocchi produttivi.','Mettere a disposizione gli LLF di altri clienti i forni dedicati per le produzione di serie dei clienti automotive attualmente ferme o in calo (ad esempio:  acquisire produzione Smith, acquisire il terzo codice Bonfiglioli ecc).','/snap/73_1628093436.png',1),(754,72,2021,'II TRI',NULL,'Target raggiunto con trend positivo rispetto al 2020 e rispetto al budget.','Considerati gli ultimi blocchi produttivi, bisogna puntare sull\'acquisizione di nuovi clienti per ottimizzare l\'impegno dei forni.\nIn primis le offere emessse in stand by CNH,SMITH.','/snap/72_1628093509.png',1),(755,69,2021,'II TRI',NULL,'In attesa dati 2020.','','/snap/69_1623062314.png',1),(771,84,2021,'I TRI',NULL,'In attesa Bilancio Conclusivo 2021','In attesa Bilancio Conclusivo 2021','/snap/84_1623315768.png',1),(772,86,2021,'I TRI',NULL,'Nel primo trimestre 2021 abbiamo mantenuto il target previsto di 0 aumenti. ','Dall\'inizio dell\'anno 2021 ad oggi, abbiamo subito un forte e repentino incremento dei costi energetici  e delle materie prime di processo relativi a olio, gas, attrezzature industriali per trattamento, da parte dei nostri fornitori. Tutto ciò premesso e considerando che da Luglio 2021 per gli effetti dell\'aggiornamento del contratto CCNL vi sarà un ulteriore incremento anche del costo della manodopera,  purtroppo, non ci è più possibile garantire i prezzi fino ad oggi applicati e saremo costretti a rivedere le quotazioni dei trattamenti termici in funzione dell\'incidenza dell\'aumento dei costi sopra descritti.','/snap/86_1623315771.png',1);
INSERT INTO `assessment_widget` VALUES (773,83,2021,'I TRI',NULL,'Nel corso del 2021 sono state emesse offerte per circa 3.800.000 euro. Inoltre il valore delle offerte confermate ( 900.000 euro) è superiore al target di 500.000 euro','Monitorare il valore delle offerte in standby e le offerte confermate affiche siano rispettati i volumi oggetto dell\'offerta.','/snap/83_1623315766.png',1),(774,136,2021,'I TRI',NULL,'Aggiornare a giugno 2021 per avere una visione più ampia (semestrale) dei motivi di rinunicia','Continuare con quanto stabilito nel riesame del 2020: monitoraggio dei progetti nuovi ecc..','/snap/136_1623315765.png',1),(775,74,2021,'I TRI',NULL,'Rispetta al budget previsionale 2020-2021 si registra una crescita del 2.38% ma inferiore dell\'1.33% rispetto all\'anno precedente. Ciò è dovuto alla diminuzione del fatturato sui clienti automotrice a causa di una flessione della produzione per mancanza chip.','Aumento generalizzato dei prezzi a tutti i clienti (automotive e non) causa aumento costi materie prime che non permettono di attendere la ripresa.','/snap/74_1623315696.png',1),(777,73,2021,'I TRI',NULL,'L\'andamento del fatturato segue quanto ipotizzato nel budget previsionale 2021. Si attende fine anno per stabilire se i risultati sono stati raggiunti. Il budget teneva conto dell\'acquisizione di un nuovo cliente (Bonfiglioli), tuttavia abbiamo registrato perdite di fatturato a causa del trend negativo dei nostri clienti di fascia A per crisi chip (settore automotive) con blocchi produttivi.','Mettere a disposizione gli LLF di altri clienti i forni dedicati per le produzione di serie dei clienti automotive attualmente ferme o in calo (ad esempio:  acquisire produzione Smith, acquisire il terzo codice Bonfiglioli ecc).','/snap/73_1623315721.png',1),(779,72,2021,'I TRI',NULL,'Target raggiunto con trend positivo rispetto al 2020 e rispetto al budget','Considerati gli ultimi blocchi produttivi, bisogna puntare sull\'acquisizione di nuovi clienti per ottimizzare l\'impegno dei forni.','/snap/72_1623315749.png',1),(785,119,2021,'I TRI',NULL,'OTTIMO RISUTATO E IN LINEA CON GLI ANNI PRECEDENTI','CONTINUARE COSI','/snap/119_1623771274.png',1),(787,114,2021,'I TRI',NULL,'Nota: si riportano i dati in screenshot del solo LLF ma si sono analizzatu tutti i reparti (TV, NCV, CBF,POZZO). La nitrocarburazione in sali viene smantellata a fine marzo 2021.\nDati stabili rispetto all\'anno precedente (ultimI 12 mesi)','Continuare con il piano stabilito in Riesame della direzione 2020 (aggiornamento 20/01/2021)','/snap/114_1623673306.png',1),(788,124,2021,'I TRI',NULL,'Nota: si riportano i dati in screenshot del solo LLF ma si sono analizzatu tutti i reparti (TV, NCV, CBF,POZZO). La nitrocarburazione in sali viene smantellata a fine marzo 2021. Tranne che per LLF si aumenta l\'ottimizzazione delle rese carica, inserendo più particolari per volume disponibile\n','Continuare con quanto stabilito nel 2020','/snap/124_1623673313.png',1),(789,115,2021,'I TRI',NULL,'Nota: si riportano i dati in screenshot del solo LLF ma si sono analizzatu tutti i reparti (TV, NCV, CBF,POZZO). La nitrocarburazione in sali viene smantellata a fine marzo 2021. \nIl rendimento degli impianti rimane statico nel tempo. Il dato peggiore è per il TV, che deve essere ottimizzato sui fermi manutentivi. ','Continuare con quanto stabilito nel Riesame Anno 2020 (20/01/2021)','/snap/115_1623673316.png',1),(790,117,2021,'I TRI',NULL,'','','/snap/117_1623673318.png',1),(791,140,2021,'I TRI',NULL,'Nota: si riportano i dati in screenshot del solo LLF ma si sono analizzatu tutti i reparti (TV, NCV, CBF,POZZO). La nitrocarburazione in sali viene smantellata a fine marzo 2021. \nLa produzione media degli impianti si attesta sul 45% di tempo utile (per sola produzione) La maggior parte del tempo ciclo perso si può rapportare all\'assenza materiale. ','Continuare con il piano stabilito in Riesame della direzione 2020 (aggiornamento 20/01/2021)','/snap/140_1623673320.png',1),(792,156,2021,'I TRI',NULL,NULL,NULL,'/snap/156_1623673323.png',1);
INSERT INTO `assessment_widget` VALUES (793,137,2021,'I TRI',NULL,'Nota: si riportano i dati in screenshot del solo LLF ma si sono analizzatu tutti i reparti (TV, NCV, CBF,POZZO). La nitrocarburazione in sali viene smantellata a fine marzo 2021. \nIl valore medio dell\'OEE (efficienza globale impianto) è tra il 30-35% su tutti gli impianti per gli ultimi mesi. ','Continuare con il piano stabilito in Riesame della direzione 2020 (aggiornamento 20/01/2021)','/snap/137_1623673327.png',1),(805,116,2021,'I TRI',NULL,'I DATI DIMOSTRANO UN LEGGERO MIGLIORAMENTO PER QUANTO RIGUARDA IL REPARTO POZZI E VUOTO,STABILE LA LINEA AUTOMATICA, LEGGERMENTE INFERIORE RISPETTO ALL\'ANNO SCORSO L\'EFFICACIA DEL REPARTO NITRURAZIONE, SEPPUR AL DI SOPRA DEL TARGET','CONTINUARE CON QUESTO IMPEGNO E DEDIZIONE E , SE POSSIBILE, IMPLEMENTARE IL MAGAZZINO SCORTE CRITICHE','/snap/116_1623771988.png',1),(806,120,2021,'I TRI',NULL,'SI DENOTA UN MIGLIORAMENTO ,RISPETTO ALL\'ANNO PRECEDENTE,NEI REPARTI VUOTO E POZZO. SOSTANZIALEMNTE STABILE QUELLO DELLA LINEA AUTOMATICA . IN CALO L\'INDICATORE DEL REPARTO NITRURAZIONE; QUESTO è IMPUTABILE AL GUASTO DELLA POMPA DEL VUOTO CHE HA COSTRETTO AL FERMO MACCHINA ','CONTINUARE CON L\'IMPEGNO DIMOSTRATO E IMPLEMENTARE, COME GIA FATTO, LE SCORTE CRITICHE DEL REPARTO NITRURAZIONE PER EVITARE FERMI IMPIANTI','/snap/120_1623771984.png',1),(809,118,2021,'I TRI',NULL,'OTTIMA PERFORMANCE  CON UN LEGGERO RITARDO NEL MESE DI MARZO, COMUNQUE AL DI SOTTO DEL TARGET','CONTINUARE COSI PUNTANDO SEMPRE PIU SULLA FORMAZIONE DEI MANUTENTORI','/snap/118_1623772086.png',1),(811,149,2021,'I TRI',NULL,'IL NUMERO DELLE ATTIVITA SONO AUMENTATE DEL 24% RISPETTO ALL\'ANNO PRECEDENTE. QUESTO è IMPUTABILE A UNA MAGGIORE SENSIBILITà DA PARTE DEI CAPITURNI SEMPRE PRONTI A SEGNALARE EVENTUALI PROBLEMATICHE','CERCARE DI LIMITARE SEMPRE PIU GLI INTERVENTI STRAORDINARI ANDANDO, LADDOVE SIA POSSIBILE, A MODIFICARE/AUMENTARE I CONTROLLI DI MANUTENZIONE PROGRAMMATA','/snap/149_1623772204.png',1),(813,98,2021,'I TRI',NULL,'Nel 2020 si è registrato un notevole calo dei costi non qualità (0.59% contro il 1.13% del 2019) riuscendo a scendere al di sotto del target del 1%. Anche nel primo trimestre del 2021 si continuo con lo stesso trend, si è passati a 0.36 con un target di 0.9','La strategia di formazione e aggiornamenti delle matrici polifunzionali sta portando vantaggi notevoli.','/snap/98_1626761608.png',1),(814,95,2021,'I TRI',NULL,'Nel periodo di riferimento non sono registrati scarti.','L\'attuazione di attività correttive scaturite dagli 8D si stanno rilevando robuste','/snap/95_1626761553.png',1),(815,97,2021,'I TRI',NULL,'Gli addebiti nel periodo di riferimento, confrontati con l\'anno precedente, risultano notevolmente migliorati. Infatti si osserva una riduzione percentuale notevole dallo 0.15% nel 2020 allo 0.08% nell\'anno in corso.','Una maggiore attenzione alla  definizione dei processi e una attività sempre più attenta alla formazione degli operatorie non meno importante l\'implementazione di azione correttive scaturite dai vari 8D risultano essere funzionanti come strategia qualitativa. \nIl target per il primo trimestre è rispetatto.','/snap/97_1623845992.png',1),(816,96,2021,'I TRI',NULL,'Le NC interne diminuiscono nel periodo di riferimento. Nonostante le NC interne risultano inferiori nel trimestre 2021 rispetto al trimestre precedente, il target non viene rispettato. La riduzione della percentuale di NC interne rispetto all\'anno precedente è un segnale positivo della strategia adottata.','Il miglioramento dell\'analisi delle NC con l\'attenzione spostata più verso il sistema che sugli operatori \nha fatto in modo che fosse possibile registrare una riduzione sensibile rispetto all\'anno precedente. Puntare alla strategia intrapresa.','/snap/96_1623846089.png',1);
INSERT INTO `assessment_widget` VALUES (817,94,2021,'I TRI',NULL,'i PPM del terzo trimestri risultano essere maggiori rispetto al trimestre precedente. Da un lato e tenuto conto del KPI PPM scarti molto basso, questo indici indica che temprasud intercetta e rilavora i pezzi difettosi senza che il cliente abbia percezione. Il target non è rispettato.','Migliorare le analisi sulle cause delle rilavorazioni.\nContinuare ad agire sul sistema piuttosto che sugli operatori.','/snap/94_1626761513.png',1),(818,151,2021,'I TRI',NULL,'Target rispettato ','Continuare con la strategia proposta nel riesame 2020','/snap/151_1626780271.png',1),(835,107,2021,'I TRI',NULL,'Nel corso del 2021 (primo trimestre), il valore medio è 80% contro il 100% dello stesso periodo del 2020). \nTraget non raggiunto','Verificare le campionature NC in modo da avere una \"lesson learned\" da applicare per il 2021','/snap/107_1623846405.png',1),(836,108,2021,'I TRI',NULL,'Nel periodo selezionato, con un target di 15 giorni (totali), il tempo di campionatura è pari a 8 giorni contro i 4 giorni medi del 2020. \nTarget raggiunto. Ciò è dovuto alla complessità generale delle campionature analizzate (es: campionature DANA o BROVEDANI)','Continuare con la strategia proposta nel riesame 2020','/snap/108_1623846408.png',1),(837,143,2021,'I TRI',NULL,'Non sono stati sostenuti costi dall\'azienda (lotti inviati al cliente già conformi) per il primo trimestre 2021','Continuare con la strategia proposta nel riesame 2020','/snap/143_1623846410.png',1),(841,114,2021,'II TRI',NULL,'CBF dato del 2°TR 82.5% in sensibile miglioramento rispetto al 1°TR 79.92 ai precedenti anni 2020 80.33% e 2019 79.92%\n\nLLF 94.42% dato migliorativo rispetto al 1°TR 92.83 ','CBF accumulare materiale per poi accendere il forno per il trattamento sicuramente porta i suoi frutti in termini di rendimento e risparmio energetico','/snap/114_1627976940.png',1),(842,124,2021,'II TRI',NULL,'in crescita i valori di resa carica media per i reparti NCV 6.31 LLF 3.54 TV 3.44 mentre il CBF registra un netto valore negativo -5.72\n','','/snap/124_1627981037.png',1),(843,115,2021,'II TRI',NULL,'LLF 2°TR 93.83 in aumento rispetto al 1° TR 92.8 e non molto distante allo stesso periodo del 2019 94.42\n\nNCV andamento stabile 2°TR 99% 1°TR 98.83% \n\nCBF 75.25% migliorativo rispetto al 1°TR 72.92\n\nTV 89.58% dato del semestre che arresta la discesa riscontrata nel 1°TR','','/snap/115_1627982672.png',1),(844,117,2021,'II TRI',NULL,'NCV media 1°TR 37.3% mentre nel 2°TR 44.6%\n\nLLF media 1°TR  51.6% mentre nel 2°TR 65%\n\nTV media 1°TR 65.3% mentre nel 2°TR 52% (Cogeme -20% causa difficoltà nel reperire materia prima, a settembre ci sarà un riallineamento)\n\nCBF media 1°TR 41.3% mentre nel 2°TR 51.3%','','/snap/117_1627983578.png',1),(845,140,2021,'II TRI',NULL,'Analisi tempo utile\nLLF 2021 2°TR 52.97%, seppur superiore al 2020(49.59%) siamo distanti dal 2019(73.91%)\n\nNCV 2021 2°TR 37.10%, seppur superiore al 2020(31.92%) siamo distanti dal 2019(63.02%) decisivo è la riduzione di lavoro da parte di alcuni clienti pin Cogeme, Housing STM, Proma\n\nTV anche se nel 2° TR si riscontra un calo rispetto al 1°TR, i trend è in crescita 2019 16.25% 2020 31.47% 2021 44.47%\n','','/snap/140_1627984901.png',1),(846,156,2021,'II TRI',NULL,NULL,NULL,'/snap/156_1625557826.png',1),(847,137,2021,'II TRI',NULL,NULL,NULL,'/snap/137_1627987334.png',1),(848,127,2021,'II TRI',NULL,NULL,NULL,'/snap/127_1625558585.png',1),(849,125,2021,'II TRI',NULL,NULL,NULL,'/snap/125_1625558951.png',1),(853,126,2021,'II TRI',NULL,NULL,NULL,'/snap/126_1626337860.png',1),(873,109,2021,'II TRI',NULL,NULL,NULL,'/snap/109_1626357883.png',1),(874,109,2020,'I TRI',NULL,NULL,NULL,'/snap/109_1626357996.png',1);
INSERT INTO `assessment_widget` VALUES (902,150,2021,'II TRI',NULL,'Target raggiunto per alcuni operatori (1 azione chiusa). Restano, per alcuni Responsabili funzione ancora un quantitativo importante di attività (es: Scarinci, 11 attività)','Per la formazione:\n-programmare le attività formative richiste, assegnado ai relatori (RSGI)\nPer le attività \n-revisione settimanale dei progressi con evidenza delle attività svolte','/snap/150_1626775327.png',1),(903,147,2021,'II TRI',NULL,'Target raggiunto (aperte 7 attività nel trimestre contro l\'una(1) prevista a target)','A seguito dell\'accordo sindacale firmato in data 01/07/2021 si suggerisce l\'intevento del personale (attraverso anche membri del personale di rappresentanza) alla redazione delle NC.','/snap/147_1626682916.png',1),(904,130,2021,'II TRI',NULL,'Rispetto al trimestre precedente (I/2021) sui registra un aumento delle NC emerse (nel primo trimestre raggiunto lo 0.69%, mentre nel secondo trimestre lo 0,71%) ed ancora di più ci si discosta dal target, fissato allo 0.30%. Delle NC emesse nel periodo in esame (aprile-giugno) il 20% sono riscontrabile all’ambito sicurezza e gestite da RSPP. La totalità delle NC si riscontrano nel campo QUALITA\'. Rispetto al precedente anno le NC sono aumentate (0,52% nel 2020. La maggior parte delle NC di Qualità sono legate a : logisitica interna/esterna (particolari danneggiati, non identificati, particolari spediti erroneamente), fusione in induzione, errate protezioni','1) Completare la formazione sulla IO 4.4-IO4.7 (blisteratura ed imballaggio)\n2)Ripasso formazione in induzione (in special modo sulla gestione IND2)\n3) Modifica IO 4.8 con lavoro a sistemi di sicurezza bypassati\n4) Ripasso sulla tracciabilità imballo e gestione NC (da inserire nelle prossime formazioni di Qualità previste)\n','/snap/130_1626769798.png',1),(945,152,2021,'I TRI',NULL,'Target rispettato','Continuare con la strategia proposta nel riesame 2020','/snap/152_1626780309.png',1),(948,97,2021,'II TRI',NULL,'L\'indice risulta migliorato rispetto al trimestre 2020 ma peggiorativo rispetto al primo trimestre dell\'anno 2021. Analizzando le fonti di addebito per il secondo trimestre si registrano 3 NC (vedi qwin 42-45-53) con incidenza importante sulla rilavorazione/fatturato.\nIl target di 0.2% non è stato rispettato.','Considerando il miglioramento continuo rispetto all\'anno precedente ritengo di procedere con la strategia già discussa nel primo trimstre','/snap/97_1626762705.png',1),(949,96,2021,'II TRI',NULL,'KPI in netto miglioramento per il secondo trimestre. Target ancora lontano. ','Strategia da adottare fino a fine anno.','/snap/96_1626762707.png',1),(950,94,2021,'II TRI',NULL,'Il dato del ppm external è ancora troppo alto e lontano dal target. Peggiorativo rispetto all\'anno precedente e al primo trimestre.','Aumentare il livello di analisi in fase di progettazione processo. Migliorare le analisi delle criticità legate al tt. Puntare sulle formazioni a operatori in modo da commettere meno errori possibili in tutte le fasi','/snap/94_1626762431.png',1),(953,95,2021,'II TRI',NULL,'Analizzando le NC si nota subito come una carica non conforme del cliente BRV ha fatto sì che l\'indice veda un notevole incremento.','Fatto salvo il caso isolato di BRV, TS è riuscita a tenere basso il numero delle cariche non conforme.','/snap/95_1626762550.png',1),(956,98,2021,'II TRI',NULL,'L\'indice risulta essere migliorativo rispetto all\'anno precedente. Il target è rispettato.','La strategia messa in pista sta dando i risultati asettati.','/snap/98_1626762710.png',1),(961,151,2021,'II TRI',NULL,'Il target dei 5 giorni nel secondo semestre non viene rispettato.\nLa gestione delle attività non viene adeguatamente gestita','Implementare una gestione con allarmi per le scadenze delle attività','/snap/151_1626780368.png',1);
INSERT INTO `assessment_widget` VALUES (964,152,2021,'II TRI',NULL,'L\'indice dei nuovi 8D è perfettamento allineato con il target. Peggiorativo rispetto al trend del trimestre precedente. \n','Continuare ad insitere sul sistema e sulle formazioni a operatori\n','/snap/152_1628098153.png',1),(965,107,2021,'II TRI',NULL,'L\'efficacia migliora al 100% nel secondo trimestre. target raggiunto e superato. Migliorato l\'indice di performance rispetto al primo trimestre','Migliorare l\'analisi dei processi con il coinvolgimento del team. Una sempre più massiccia collaborazione con DS e PRG e la sensibilizzazione a tutti gli operatori all\'acquisizione di nuove commesse ha fatto registrare un successo del 100%. Continuare con tale strategia. ','/snap/107_1626763459.png',1),(966,108,2021,'II TRI',NULL,'L\'indice rispetta sempre il target. Peggiora rispetto al trimestre precedente e a quello dell\'anno precedente. Tale incremento è dovuto alle campionature eseguite per alcuni clienti come FPT e OMN e SMITH dove il materiale viene accettato da ts e avviato alla t.t. solo dopo definizioni delle specifiche tecniche e audit da parte del cliente.','La strategia di coinvolgere tutti gli enti alla campionatura ha dato linfa all\'organizzazione. Tutti si sento responsabili del successo.','/snap/108_1626763462.png',1),(967,143,2021,'II TRI',NULL,'Il costo comunque sotto il target, è dovuto alla campionatura di Fematic circa la tempra induzione delle leve. I costi comprendono anche l\'attrezzatura realizzata.','','/snap/143_1626766828.png',1),(968,107,2020,'I TRI',NULL,'L\'efficacia delle campionature non risulta ottimale a causa di due campionature eseguite per il cliente dana che non sono andate a buon fine. Il target non viene raggiunto.','Il dato si riferisce per lo più a proccesi con poco Know How. Tuttavia i fallimenti di queste 2 campionature sono legati soprattutto ad una mancata percezione failure sugli impianti. ','/snap/107_1626763007.png',1),(969,108,2020,'I TRI',NULL,'Il kpi di riferimento è soddisfacente. Il target è rispettatto.','Continuare con le strategie definite nel riesame 2020','/snap/108_1626763011.png',1),(970,143,2020,'I TRI',NULL,'Non si registrano costi di Campionature. ','Continuare a coinvolgere i clienti nel processo di campionatura con contributi mirati almeno alla copertura dei costi sostenuti da TS.\n','/snap/143_1626763014.png',1),(992,123,2021,'II TRI',NULL,'tutti i gruppi di lavoro stanno al di sotto del lead time, anche se l\'induzione si trova al limite in quanto sono stati fatti interventi su macchine che hanno portato rallentamenti e spesso per urgenze di clienti \"importanti\" vengono lasciate indietro commesse di altri clienti arrivate prima. Le tempistiche del vuoto in confronto al I trimestre sono migliorate','continuare a monitorare le commesse in ritardo segnalandole al responsabile di reparto','/snap/123_1626869381.png',1),(993,128,2021,'II TRI',NULL,'in rapporto al I trimestre i costi extra trasporto sono diminuiti grazie alla maggiore attenzione degli addetti al reparto','continuare con i controlli, mantenendo sempre alta la soglia di attenzione.','/snap/128_1626843912.png',1),(1003,121,2021,'II TRI',NULL,NULL,NULL,'/snap/121_1626869751.png',1),(1013,135,2021,'II TRI',NULL,'nessuna non conformità nel II trimestre.\nL\'introduzione di un capofficina come supervisore (Alex Di Fonzo) ha sensibilmente migliorato la situazione generale, con risultati ottimali','continuare con il percorso intrapreso','/snap/135_1626870149.png',1),(1016,154,2021,'II TRI',NULL,'come per il precedente trimestre il trasporto su Bari risulta sempre essere il più economico per uso ns mezzo a pieno carico.\nPer Ancona e Lazio, dove viene utilizzato il corriere Palena, il costo medio si mantiene comunque al di sotto del target','continuare, come programmato, con corriere per Lazio e Ancona, fino a dicembre 2021, continuando a monitorare i costi. Avendo eliminato la zona abruzzo non ci sono perdit di clienti. ','/snap/154_1626869987.png',1);
INSERT INTO `assessment_widget` VALUES (1019,153,2021,'II TRI',NULL,NULL,NULL,'/snap/153_1626869791.png',1),(1034,85,2021,'II TRI',NULL,'Il 43% delle offerte emesse non è andato in porto perchè i particolari non sono stati prodotti dai clienti. Il 45,2% risulta invece attualmente in stand-by e una percentuale inferiore non è andata in porto per ragioni di prezzo elevato.','Continauare a monitorare l\'esito delle offerte importanti (es: CNH, SIAP, ROSSI, COGEME) contattare anche le offerte ritenute elevate per eventuali margini di trattativa.','/snap/85_1628088346.png',1),(1039,82,2021,'II TRI',NULL,'Target raggiunto','Continuare e mantenere gli obiettivi prefissati (consegna offerta in 24 ore dalla ricezione).','/snap/82_1628092374.png',1),(1045,80,2021,'II TRI',NULL,NULL,NULL,'/snap/80_1627042876.png',1),(1046,79,2021,'II TRI',NULL,NULL,NULL,'/snap/79_1627043486.png',1),(1062,116,2021,'II TRI',NULL,'il target è ampiamente rispettato . si nota un miglioramento per quanto riguarda il t.v. e un leggero peggioramento del reparto ncv dovuto al fermo ncv3 (risolto con aggiornamento scorte critiche)','la strategia futura deve essere quella di individuare con precisione le scorte critiche con un lead time elevato.','/snap/116_1627031622.png',1),(1063,120,2021,'II TRI',NULL,'anche se è molto ambizioso un target al 90% delle man programmate.il reparto ncv risulta non conforme a causa della rottura valvola di non ritorno della pompa del vuoto.questo ha causato un fermo impianto importante a causa del lead time del pezzo danneggiato. ','continuare ad essere intransigenti sul rispetto delle scadenze delle man programmate. onde evitare il ripetersi del problema avuto sull\'impianto ncv3 (NC n°50)  sono stati aggiornati mo7.1 scorte critiche e  mo 7.11c controllo valvola di non ritorno.questo ci assicura fermi impianti ridotti.','/snap/120_1627031625.png',1),(1064,118,2021,'II TRI',NULL,'risultati ben al di sotto del target','continuare cosi e formare nuovo personale sulle man predittive .','/snap/118_1627031627.png',1),(1065,149,2021,'II TRI',NULL,'abbiamo avuto un aumento del 32% di segnalazioni su apposito  modulo MO 7.11L rispetto all\'anno precedente. ','sensibilizzare e formare  i ct , lab e ind su cosa va segnalato e cosa non va segnalato','/snap/149_1627031631.png',1),(1066,157,2021,'II TRI',NULL,NULL,NULL,'/snap/157_1628059222.png',1),(1067,158,2021,'II TRI',NULL,NULL,NULL,'/snap/158_1628059219.png',1),(1068,159,2021,'II TRI',NULL,NULL,NULL,'/snap/159_1628059217.png',1),(1164,68,2021,'II TRI',NULL,NULL,NULL,'/snap/68_1628088208.png',1),(1198,111,2021,'II TRI',NULL,NULL,NULL,'/snap/111_1630998860.png',1),(1199,112,2021,'II TRI',NULL,NULL,NULL,'/snap/112_1630999107.png',1),(1200,114,2021,'III TRI',NULL,'media riscontrata a 09/21 96% in netto aumento con il 1° e 2° TR rispettivamente 80% e 85%, superando anche 2019 95%.','Ridurre il più possibile le ore di vuoto del forno onde evitare sprechi di energia. Concentrare le lavorazioni in pochi giorni settimanali.','/snap/114_1636966539.png',1),(1202,124,2021,'III TRI',NULL,'La carica media rispetto al 2020  non è aumentata, sostanzialmente invariata attestandosi ad un -0.5%\nCariche standardizzate e  cariche dedicate con l\'impossibilità di effettuare il groupage hanno determinato il mancato aumento del KPI\nStrategia futura\nLa strategia di raggruppare materiale simile nella fase di tempra in vuoto per poi separare in altri impianti la fase di rinvenimento ha dato i risultati previsti. \n','Continuare con la strategia di raggruppare materiale simile nella fase di tempra in vuoto per poi separare in altri impianti la fase di rinvenimento. \n','/snap/124_1636645343.png',1);
INSERT INTO `assessment_widget` VALUES (1203,115,2021,'III TRI',NULL,'Il valore del RGI è intorno al 90 % indice di un basso numero di ritrattamenti annui in linea con il target.\n','Continuare in un accurata analisi del materiale e geometria da trattare in modo da non dover eseguire ritrattamenti. Continua formazione del personale e adeguata manutenzione possono ridurre le ore di rilavorazione. \n ','/snap/115_1636967662.png',1),(1206,117,2021,'III TRI',NULL,'I valori riscontrati sono abbondantemente al di sotto del target e comunque migliorativi rispetto all\'anno precedente\n2020 31%\n2021 51%','      È necessario agire commercialmente sul reperimento di nuovi clienti che possano saturare impianto.  \n','/snap/117_1636645374.png',1),(1211,140,2021,'III TRI',NULL,'Nel 2021 abbiamo un deciso miglioramento del tempo produttivo 45% rispetto al 32% del 2020.\n\nÈ necessario agire commercialmente sul reperimento di nuovi clienti che possano saturare impianto.  \n','l\'incremento di lavoro ci ha permesso di migliorare il KPI.\nContinuare nella ricerca di nuove commesse.','/snap/140_1636645394.png',1),(1213,156,2021,'III TRI',NULL,'LLF 95.08\nNCV 99.67\nCBF 95.58\nTV 89.75','','/snap/156_1636622143.png',1),(1225,137,2021,'III TRI',NULL,'44% in netto aumento rispetto al 26% del 2020 ','Reperire nuove commesse per aumentare la saturazione degli impianti','/snap/137_1636645410.png',1),(1272,109,2021,'III TRI',NULL,'Alla fine del primo semestre abbiamo riscontrato che dal 2018 a Giugno 2021 il valore dell\'assenteismo è salito da 2,88 (fine Dicembre 2018) a 4,45%.\nEscludendo il 2020  (anno pandemico)l\'aumento di questo valore ci ha fatto riflettere sulla possibilità che esso sia dovuto a cause aziendali.\nPer quanto concerne il 3° trim,\nil valore dell\'assenteismo è sceso da 4,45 a 4,22 %, una riduzione minima che potrebbe essere dovuta ai mesi caldi.\n\n\n ','1)abbiamo stipulato l\'accordo di secondo livello con l\'obiettivo di riconoscere dei premi al conseguimento di determinati risultati, in base anche alla % di assenza che si riscontrerà nell\'anno 2021, per cui dobbiamo attendere l\'anno prossimo per verificare l\'efficacia dell\'accordo di secondo livello.\n2)\nPer quanto concernono le eventuali cause aziendali abbia predisposto l\'acquisto di sollevatori automatici per ridurre gli sforzi degli operatori. \n\n\n\n','/snap/109_1636795544.png',1),(1274,111,2021,'III TRI',NULL,'Dal 2018 al 2021 abbiamo assistito ad una graduale riduzione della % di ferie (13,75% nel 2018,11% nel 2019, 7,84% nel 2020). Nell\'analisi del primo semestre abbiamo rilevato una  una stabilizzazione della % delle ferie,  cioè una media di 7,86% sui primi 2 trimestri, attualmente abbiamo una media di 7,99% su 3 trimestri,\nper cui possiamo dire che il valore medio contin\nua ad essere stabile, anche se con una leggera risalita \nma siamo sempre al di sotto del target,  segno del fatto che la turnazione con i giornalieri continua a riscontrare effetti positivi\n','Strategia futura\n1)predisporre piano di ferie concordati per impiegati e operai per ridurre la % dei rol, che per alcuni continua ad essere elevata, mentre per le ferie siamo al di sotto del limite legale.\n\n\n\n','/snap/111_1636795553.png',1);
INSERT INTO `assessment_widget` VALUES (1278,110,2021,'III TRI',NULL,'Nell\'analisi del primo semestre abbiamo rilevato una notevole riduzione della % degli straordinari, rispetto agli anni passati) \nAbbiamo parlato di una stabilizzazione  nei primi 2 trimestri con un a media del 3,11% al di sotto del target che è del 5%.\nCon il 3°trimestre rileviamo una media del 3,19%,per cui il valore continua ad essere stabile, segno del fatto che la turnazione dei giornalieri funziona, cioè oltre a garantire una migliore distribuzione dell\'orario di lavoro, incide positivamente sugli straordinari, riducendo indennità notturne e pomeridiane. \n\n  \n','\n\nStrategia futura\n1)	La stabilizzazzione degli straordinari e delle ferie, considerando la crescita dell’assenteismo ,ci porterebe a dire che la situazione occupazionale sia ottimale, ma data l’esigenza di manodopera richiesta, siamo portati a riflettere sulla reale efficienza del personale in forza.\n\n\n\n\n  ','/snap/110_1636796413.png',1),(1281,112,2021,'III TRI',NULL,'Nel terzo trimestre si conferma l\'assenza di infortuni, come nei 2 trimestri precedenti.\nPer quanto concernono i quasi infortuni abbiamo riscontrato a Settembre  2021 la % dello 0,28%. Siamo in target, anche se rispetto al 2020 abbiamo un numero più elevato di quasi infortuni denunciati (da Settembre a Settembre: 4 nel 2021 e 1 nel 2020).\n\n\n  \n\n','\nStrategia futura\nL’analisi rilevata ci porta a non abbassare la guardia e a tenere sempre alto il livello di attenzione sulla sicurezza, \na)	Continuando con la formazione cogente e non sulla sicurezza.\nb)	rafforzando sempre più la consapevolezza dell’uso dei dpi e dei rischi legati alla mansione.\nc)	Aumentando le verifiche ispettive (RSPP) e la vigilanza da parte dei preposti sull’osservanza delle misure di sicurezza.\nd)	implementando il sistema di denuncia della azioni di quasi infortunio, con riunioni del comitato di rappresentanza. \nLo scopo è rafforzare l\'azione preventiva in materia di sicurezza e ottenere la certificazione iso 45001.\n  \n','/snap/112_1638534026.png',1);
INSERT INTO `assessment_widget` VALUES (1315,113,2021,'III TRI',NULL,'Dall\'analisi del questionario il risultato totale è 3,9%.  Facendo\nuna sintesi fra tutte le aree, le domande   comuni a tutte o quasi tutte le aree ,con valore in target, ma più basso rispetto alle altre o con valore negativo sono le seguenti:\n1)domanda 9(Ritengo di essere retribuito in modo adeguato rispetto alle mie prestazioni) 3,1 % per gli impiegati,\n3,3% (indiretti) mentre per l\'area della produzione abbiamo un valore negativo: 2,8%.\n  2)domanda 12 :nell\'azienda c\'è un\'atmosfera positiva e armoniosa)\nabbiamo un valore più basso cioè del 3% per l\'area produzione (anche se più alto rispetto al 2020: 2,75%).\nRiscontriamo invece il valore  negativo 2,9 % nell\'area dei preposti, relativamente alla quale si rileva valore negativo anche sulla  domanda 18 \"quando vengono date nuove istruzioni si riceve il necessario supporto e formazione.\"\ndomanda 14)i colleghi si aiutano reciprocamente e comunicano tra di loro\" \"3,1 per i preposti,3,3 per la produzione e per gli impiegati.\nPer\nl\'area indiretti abbiamo rilevato un valore negativo\n2,6% per la domanda 17: \"i \"miei superiori mi coinvolgono nelle decisioni che riguardano il mio lavoro\".\n\n\n\n\n','Per quanto concerne \nla retribuzione, \na)	Valutazione del passaggio di livello da D1 ex 2 A D2 ex3.\nPer quanto concernono la mancanza di atmosfera armoniosa e mancanza di comunicazione e aiuto reciproco tra i colleghi dobbiamo\nprogrammare con Adecco per l\'anno 2022 progetti castomizzati di tipo ludico per i prepostiper aumentare il senso di condivisione e appartenza all\'azienda.\nInvitare il comitato di rapprese a raccogliere problematiche sociali  da riferire in sede di riunione trimestrale. \nFar partecipare alle riunioni del comitato di rappresentanza anche i capiturno a rotazione e a campione anche operatori del più basso livello per dare evidenza dell\'importanza che l\'azienda da alle riunioni in senso paritetico, valorizzando così il coinvolgimenmto dei dipendenti nelle decisioni lavorative a livello aziendale..\ndando attuazione a quanto previsto nell\'accordo di secondo livello.\n\n\n \n','/snap/113_1638287937.png',1),(1321,88,2021,'III TRI',NULL,'Situazione in linea con I e II trimestre\nNel Terzo Abbiamo avuto Una Nc su trasporto.\nAbbiamo condiviso con il fornitore la criticità che ha comportato questa NC\nCon risultato positivo\n\n','Costante Monitoraggio dei Fornitori al fine di identificare eventuali deviazioni.\n','/snap/88_1637921148.png',1),(1323,89,2021,'III TRI',NULL,'Anche nel Terzo Trimestre non si riscontrano anomalie \nnelle consegne\nConsegne effettuate\nrispettando Tempi di Consegna permettendo \nottimizzazione delle scorte di magazzino.','Costante Monitoraggio dei Fornitori al fine di identificare eventuali deviazioni.\n','/snap/89_1637167115.png',1),(1324,90,2021,'III TRI',NULL,'Indice in Linea \ncon il precedente.','Costante Monitoraggio dei Fornitori al fine di identificare eventuali deviazioni.','/snap/90_1637167119.png',1),(1326,91,2021,'III TRI',NULL,'Risultato ottimale che pur troppo non potrà essere confermato nel quarto ed ultimo\ntrimestre del 2021 causa Crisi del mercato dell\'energia e del metano che ha totalmente stravolto gli equilibri economici esistenti ','Contratti \nEnergia/Gas:\nRichiesta di un contratto Variabile \ncon l\'opportunità di poter fissa il prezzo nel periodo di massima flessione dei prezzi.\nSulla restanti materie prime si cerca di lavorare con contratti di breve termine con l\'opzione di revisionare e ottenere dei prezzi migliori con verifica andamento mercati\nper  singoli trimestri','/snap/91_1637167123.png',1),(1327,141,2021,'III TRI',NULL,NULL,NULL,'/snap/141_1637167209.png',1),(1332,93,2021,'III TRI',NULL,NULL,NULL,'/snap/93_1637170167.png',1);
INSERT INTO `assessment_widget` VALUES (1347,130,2021,'III TRI',NULL,'Si identifica una diminuzione del numero di NC globali nel periodo analizzato ( il valore medio per il 2021 si attesta al 0.53 % contro lo 0.61% del 2020). Target dello 0.3% non raggiunto. La totalità delle NC si riscontrano nel campo QUALITA\'. Ciò è correlato ad una più attenta analisi delle NC avvenute, alla struttura ed alle procedure di gestione più precisa ed a un sistema più recettivo all’identificazione delle deviazioni (prima, quindi, che si trasformino in problemi). Per un\'analisi dei singoli reparti fare riferimento alle sezioni Assicurazione Qualità (per Area QUALITA\') e Logistica (per area Logistica). Per le sezioni AMBIENTE non si registrano NC. Per la SICUREZZA la causa principale è riscontrabile nella manutenzione degli impianti e nell\'uso degli stessi da parte degli operatori in sicurezza (es: verifica catene paranco SAB, uso casco in fase di uso carroponte/paranco, ecc).','1) Aumentare il livello di controllo per le tematiche ambientali e di sicurezza (in ottica di secondo stage ISO 45001). \n2) Continuare l\'attività di informazione sulla sicurezza (come pianificato); a discrezione dei RF anche corsi agli operatori sulla qualità (che cosa è un sistema di qualità, obblighi del produttore, ecc)','/snap/130_1639044328.png',1),(1348,147,2021,'III TRI',NULL,'Target di 1 attività aperta per trimestre (nel plant) raggiunto.  Si verifica una preponderanza di azioni correlate ad audit di processo/sistema/prodotto (non azioni di migioramento)','Porre attenzione alle proposte/suggerimenti; eseguire, periodicamente, nelle riunioni delle 8:45 (giornaliere) un meeting report (a cadenza, ad esempio settimanale)','/snap/147_1637570511.png',1),(1349,150,2021,'III TRI',NULL,'Non si è raggiunto l’obiettivo della chiusura dei task. Da intervista agli RF pare correlata ai troppi referenti che assegnano le attività (es: RSGI, HR, DG). Si suggerisce una riunione mensile in cui gli RF riportano le attività assegnate, ripianificando le scadenze e l\'assegnazione delle attività. Alcune attività correlate alla revisione del sistema (revisione procedure, aggiornamento matrice di poli competenza, aggiornamento procedure per sistema ISO 45001) hanno comportato un piano di formazione non ancora completato. ','Tenendo conto del secondo stage della 45001, la chiusura delle attività correlate alla 45001 dovrebbe comportare una diminuzione del (15-20)% delle attività in corso (ed aperte).','/snap/150_1637570514.png',1),(1353,128,2021,'III TRI',NULL,'il risultato si mantiene costante come nel II trimestre, senza costi extra trasporti.\nSi evince che in rapporto allo stesso periodo dell\'anno precedente i costi sono diminuiti del 70% circa.','Visto il risultato, mantenere l\'attuale linea di condotta, continuando a prestare sempre la massima attenzione per evitare errori','/snap/128_1638878707.png',1),(1355,123,2021,'III TRI',NULL,'i gruppi di lavoro sono al di sotto del target, tranne induzione e vuoto, che come nei mesi precedenti continuano ad avere ritardi','con l\'implemento effettuato sul QWin, controllo su lavorazioni eseguite e sollecitando al reparto di competenza (produzione-laboratorio) la lavorazione mancante e ogni lunedì fare il punto della situazione con le commesse in ritardo','/snap/123_1637581626.png',1),(1357,121,2021,'III TRI',NULL,'','','/snap/121_1637596056.png',1);
INSERT INTO `assessment_widget` VALUES (1358,153,2021,'III TRI',NULL,'La resa trasporti nel III trimestre si mantiene sopra il target solo per la zona di Bari in quanto il mezzo viaggia sempre a pieno carico. Per il trasporto nel Lazio e nelle Marche la resa non è ottimizzata perché i quantitativi  hanno avuto una diminuzione in rapporto al 2020 del 40% circa sia nella zona di Ancona che nel Lazio (diminuzione q.tà trasportate ad Ancona del cliente Cebi e nel Lazio per i clienti Ben Vautier e CML) e il costo del trasporto è inferiore laddove i carichi sono maggiori ','Analisi Risultati\nLa resa trasporti nel III trimestre si mantiene sopra il target solo per la zona di Bari in quanto il mezzo viaggia sempre a pieno carico. Per il trasporto nel Lazio e nelle Marche la resa non è ottimizzata perché i quantitativi  hanno avuto una diminuzione in rapporto al 2020 del 40% circa sia nella zona di Ancona che nel Lazio (diminuzione q.tà trasportate ad Ancona del cliente Cebi e nel Lazio per i clienti Ben Vautier e CML) e il costo del trasporto è inferiore laddove i carichi sono maggiori \nStrategia futura\nIn base alle decisioni aziendali, tenendo conto delle necessità logistiche dei clienti di BARI (stesso giorno carico e scarico), malgrado che il costo con Palena risulterebbe inferiore, si mantiene il trasporto con ns mezzo. Stiamo valutando il trasporto Vs Bari soltanto per i clienti Dana e Brovedani gestibile più facilmente con un corriere esterno in quanto non richiedono il carico e scarico nello stesso giorno. Attendiamo quotazione del corriere Palena per procedere. Ai clienti del Lazio su cui abbiamo avuto un calo di produzione, abbiamo aumentato le spese di trasporto \n','/snap/153_1638878805.png',1),(1359,154,2021,'III TRI',NULL,'','','/snap/154_1637596087.png',1),(1360,135,2021,'III TRI',NULL,'Nonostante il raggiungimento del target nei primi tre trimestri 2021, si esegue comunque analisi dove è stata identificata la NC a rischio maggiore (la nr. 74-costi maggiori sostenuti dall’azienda) e le attività intraprese per evitare il ripetersi dell’evento si sono rivelate efficaci.','Per evitare ulteriori problemi anche per altre tipologie di imballo con spedizione tramite corriere, creare una visual check per i magazzinieri ed i trasportatori. Per le attività quotidiane di logistica, verificare che siano sempre apposte in bacheca le informazioni più importanti e continuare ad utilizzare il gruppo whatsapp della logistica e produzione creato nel 2021 come canale di comunicazione immediato.  ','/snap/135_1638878938.png',1),(1366,125,2021,'III TRI',NULL,NULL,NULL,'/snap/125_1637689692.png',1),(1367,126,2021,'III TRI',NULL,NULL,NULL,'/snap/126_1637689445.png',1),(1368,127,2021,'III TRI',NULL,NULL,NULL,'/snap/127_1637689478.png',1),(1389,131,2021,'III TRI',NULL,NULL,NULL,'/snap/131_1637689528.png',1);
INSERT INTO `assessment_widget` VALUES (1408,97,2021,'III TRI',NULL,'Il diagramma presenta temporalmente per mese l‘andamento della % degli addebiti; quindi addebiti su fatturato.\n\nMediamente il dato risulta essere oltre il target e  più alto dell\'anno precedente.\nLa causa principale delle NC ricevute che hanno scaturito addebito è dovuta ad ERRORI DELL\'OPERATORE.\nI clienti per cui si è registrato una ripetizione degli eventi sono Rossi Motoriduttori e Osa Demolition.\nNon meno importante il cliente D','La formazione e la sensibilizzazione agli operatori dovrà essere una priorità per il futuro. E\' opportuno redigere un piano formativo robusto con programma da seguire a tutti i livelli, dall\'operatore al capo officina. Quest\'ultimo dovrà garantire con controlli giornalieri la corretta esecuzione delle fasi mediante controllo smarcature. Consigliabile un registro di controllo con linee guida. L\'aggiornamento del mansionario per il C.O. dovrà prevedere nei suoi compiti questo controllo. Inoltre RSGI o DS dovranno eseguire a scadenza settimanale, mediante un piano di mini audit, la verifica delle smarcature e il rispetto delle Istruzioni di lavoro.\nIncrementare la presenza del personale indiretto in officina ridurrebbe gli errori legati all\'operatore.','/snap/97_1638804198.png',1),(1412,96,2021,'III TRI',NULL,'Il diagramma presenta l‘andamento della % delle commesse rilavorate per difetti di trattamento.\nQ.ty internal N.C.(Batch) / Batch n°/months.\n\nLa percentuale delle NC interne per rilavorazione risultano sopra il target anche se migliorativo rispetto all\'anno precedente.\nIl dato medio registrato è di 0.85% rispetto allo 0.96%  del 2020 \n\nLe cause principali in questo caso sono legate ad Errori Impianti, nel particolare alle rilavorazioni di ripristino mediante sabbiatura del cliente Rossi per sfogliature superficialiche coinvolge il reparto di nitrurazione nello specifico il forno NCV3.\nAnche le rilavorazioni per il cliente Cogeme, reparto forno in vuoto risultano essere impattanti.\n\n\n\n','La strategia da attuare per migliorare ulteriormente l\'indicatore è quella di coinvolgere il fornitore ad eseguire un\'analisi attenta sull\'impianto NCV3 che crea il problema di sfolgliatura (al contrario del forno NCV4).\nMentre è importante una revisione della procedura di ricondizionamento forno TV dopo cicli di cementazione in bassa pressione. ','/snap/96_1638804202.png',1),(1414,94,2021,'III TRI',NULL,'\nIl diagramma presenta temporalmente per mese l‘andamento in parti per milioni dei pezzi scartati dal cliente e inviati a Temprasud per rilavorazione, o rottamati  per difettosità.\nL\'andamento medio risulta essere oltre il target, \nLe cause principali sono legati ad errori da operatori quali movimentazione e sequenza delle fasi.\nReparto a maggior peso e la linea a camera cieffe.\nOsa e Rossi restano i clienti più colpiti.','Anche in questo caso è necessario un piano formativo a tutti gli operatori per commettere meno errori possibili. \n(Vedi kpi % addebiti)','/snap/94_1638804205.png',1),(1420,95,2021,'III TRI',NULL,'Seppur il target non è stato rispettato, il dato medio riporta un miglioramento rispetto all\'anno precedente. \nle cause di questo dato non sufficiente sono dovute ad errori impianto (Brovedani) e errori logistici (Cogeme).\nNon meno importante la problematica di skip process di Rossi\nI reparti colpiti sono Nitrurazione e linea a camera.','Il punto a favore è che TS è riuscita sempre ad avere una detection senza inviare i pezzi scarto al cliente. \nAutomatizzare la linea della CO2, aumentare le corte in esercizio mediante pacchi bombole, incrementare il livello di gestione forni NCV a tutti gli operatori mediante piani formativi mirati saranno le strategie future','/snap/95_1639064549.png',1);
INSERT INTO `assessment_widget` VALUES (1424,98,2021,'III TRI',NULL,'Il diagramma presenta l‘andamento dei costi complessivi / Fatturato \nL\'indicatore è positivo (0.58%) e in miglioramento rispetto all\'anno precedente.  I costi di non qualità risultano essere migliorativi rispetto all\'anno precedente e rispettano il target nonostante ridotto da 1% a 0,9%','Maggiore attenzione ai processi produttivi mediante breafing giornalieri e l\'irrobustimento del piano di manutenzione ha portato ad un miglioramento continuo.\nContinuare con questa strategia.','/snap/98_1638804211.png',1),(1425,151,2021,'III TRI',NULL,'I tempi medi di risposta delle attività TS risulta rispettato.\nL\'organizzazione riesce a rispondere agli 8D nei tempi prefissati.\nIl diagramma registra invece un dato controcorrente nel 4^trimestre.\nLa causa principale è dovuta ad alcune azioni da attuare che hanno richiesto un tempo tecnico di implementazione più importante e ad una tenuta non efficiente di controllo scadenze. ','Il breafing mattutino funziona. Le verifiche di avanzamento lavori settimanali sono spesso rispetatte. Le attività  Vengo definite anche se non spesso implementate a causa della subordinazione di clienti e fornitori coinvolti.\nAggiornamento del modulo 8D con tools 5WHY','/snap/151_1638804214.png',1),(1429,152,2021,'III TRI',NULL,'Target rispettato.  Analizzando le NC, ne si deduce che le cause delle problematiche anche in questo caso sono riconducibili ad attività legate all\'operatore, movimentazione e esecuzione delle fasi.\nRossi e Osa e D','Irrobustire il sistema con istruzione sempre più di basso livello.\nFormazione a tutti i livelli con piani formativi robusti.','/snap/152_1638887447.png',1),(1431,107,2021,'III TRI',NULL,'Indicatore al massimo della perfomance. Target raggiunto e superato','Coinvolgimento a tutti i livelli con il personale, impianti sempre in ottimo stato, capacità organizzative del Team sono i punti di forza di questo risultato.\nIl nuovo modulo APQP ha migliorato l\'organizzazione dei lavori.\nContinuare con questa strategia','/snap/107_1638800756.png',1),(1433,108,2021,'III TRI',NULL,'Target rispettato.\nIl tempo medio delle campionature eseguite nel 3^trimestre è di 11.22 giorni. Migliorativo rispetto al trimestre precedente\n','Le riunioni in team e la divisione dei ruoli, il nuovo tools APQP e suoi allegati, un nuovo assetto al laboratorio con il responsabile che si dedica alla parte operativa ha dato.\nContinuare con questa strategia','/snap/108_1638800775.png',1),(1435,143,2021,'III TRI',NULL,'il kpi medio è di 760€\nil target non è stato superato.','L\'ottimizzazione delle campionature accorpandole a cariche di produzione di serie e  la richiesta di contributi a cliente, insieme all\'ottimo lavoro svolto dalla parte commerciale.\n\nContinuare con tale strategia ','/snap/143_1638800792.png',1),(1437,86,2021,'III TRI',NULL,'L\'incidenza dell\'aumento ponderato nel  2021 è pari a 1,85% Rispetto al target programmato nel 2021 di circa il 3,5%. Questo gap è dovuto ad alcuni clienti che hanno ricevuto aumento inferiore del 7% (vedi alfagomma, vedi dsa dal modulo MO1.8) causa ritrosia cliente.\nParte del gap verrà recuperata con il 2022  grazie agli aumenti applicati ai clienti di fascia A con un incidenza del 7,28% vedi MO 1.8.','Dal momento che l\'incidenza sui costi della produzione in funzione della quale sono state decise le percentuali da ribaltare ai clienti  è peggiorata passando dal 14% (analisi mercato di settembre) al 18,33% (analisi mercato di novembre) sarà necessario monitorare l\'andamento del mercato per il trimestre 2022 per definire i listini dei clienti fascia A vedi MO1.8, nonchè aggiornare con nuovo  aumento i listini dei clienti che hanno ricevuto percentuali inferiori al 7% (vedi Alfagomma) o per i quali l\'aumento non risulta sufficiente causa lavorazioni sottocosto (vedi ind. Marvit alberino).','/snap/86_1644508104.png',1);
INSERT INTO `assessment_widget` VALUES (1439,68,2021,'III TRI',NULL,'Causa pandemia il mercato del settore di TT ha subito una contrazione importante del 11%; in particolare Temprasud del 10,26%. Tale contrazione è stata recuperata nel corso dell\'anno 2021  tuttavia gli effetti correlati alla pandemia (mancanza materie prime, microprocessori e crescita del mercato delle auto ibride-elettriche) ha determinato una riduzione dei volumi automotive, (che caratterizza la percentuale più elevata dei clienti temprasud che generano l\'80% del fatturato) situazione che è perdurata nel 2021.','Diversificare la clientela puntando su settori non auto che sono in crescita con acquisizioni di nuovi clienti. ','/snap/68_1644508109.png',1),(1440,84,2021,'III TRI',NULL,'I tempi di incasso 2020 sono superiori 117 gg rispetto al target di 100 ma in riduzione rispetto agli anni precedenti.','Nel 2022 ridurre tempi di incasso dei clienti che hanno modalità di pagamento con tempi elevati superiori al target. Per i clienti con fatturato >50.000€ inserire come valore massimo della modalità di pagamento tramite bonifico 90gg.Per i clienti con fatturato inferiore adottare riba 60 gg. ','/snap/84_1644508126.png',1),(1442,85,2021,'III TRI',NULL,'La percentuale più elevata 46,9% delle offerte emesse è in stand-by. Il 41,8% sono offerte chiuse perse per pezzi non prodotti  dai clienti il 6,8% non è andato in porto a causa quotazione elevata.','Monitorare nuovamente con rischista riscontro ai clienti lo stato delle offerte in stand-by e rivalutare le quotazioni con prezzi reputati dal cliente elevati (come ad esempio il caso di Mta induzione) tramite il supporto dell\'ufficio tecnico con ottimizzazioni ciclo dove possibile. ','/snap/85_1644508130.png',1),(1443,83,2021,'III TRI',NULL,'Nel corso dell\'anno sono state emesse offerte per un valore di 4.720k. Il valore delle offerte confermate raggiunge  684.340€ è quindi superiore al target di 500.000, ','Verificare  che siano rispettati volumi oggetto d\'offerta e nel caso in cui i volumi effettivi siano minori rispetto a quelli prospettati dai clienti verificare i prezzi . ','/snap/83_1644508151.png',1),(1444,136,2021,'III TRI',NULL,'Le offerte più importanti emesse sono  in attesa di riscontro cliente: \nFUTURATECH(2.000.000€ il cliente ci aveva inchiestato per esubero della produzione e momentaneo guasto linea interna, attualmente ha difficoltà di reperimento materia prima e fermo produzione casa mancanza chip, non esclude esserci possibilità di collaborazione (ma non prima del febbraio 2022) in quanto le campionature eseguite sono state benestariate, l\'omologazione con audit a distanza è stata superata. COGEME (la partenza dei progetti oggetto di richiesta d\'offerta è successiva al 2022 e il cliente non ha ancora ricevuto feedback dal cliente finale) Rossi (offerte settore eolico progetto rimasto bloccato per mancanza riscontro cliente finale)','Continuare con monitoraggio ogni tre mesi dello stato delle offerte   facendo leva sul prezzo nei casi in cui risultiamo meno competitivi. attraverso un riesame dei costi . ','/snap/136_1644508155.png',1),(1445,82,2021,'III TRI',NULL,'L\'efficacia commerciale è pari a 1,2 gg in linea con i risultati del periodo precedente e con il target di max 2gg. ','Continuare a mantenere il target di max 2 gg grazie all\'aggiornamento di listini  completi di tutti i trattamenti eseguiti. ','/snap/82_1644508242.png',1),(1446,81,2021,'III TRI',NULL,'Il grado di concentrazione dei clienti che generano l\'80% del fatturato è superato lievemente con 22 rispetto al target di 20.\n \n','Puntare sul consolidamento commerciale  di clienti con potenziale di fatturato elevato non auto come Dana, Smith , TAS e cercare di acquisire  nuovi clienti.','/snap/81_1644508171.png',1),(1447,80,2021,'III TRI',NULL,NULL,NULL,'/snap/80_1644508180.png',1);
INSERT INTO `assessment_widget` VALUES (1448,79,2021,'III TRI',NULL,'LLF \n2019:2917673\n2021:2485194 (-15% RISPETTO AL 2019   2% RISPETTO AL 2020)\nNCV\n2019:675683\n2021:626770(-7% RISPETTO AL 2019   27% RISPETTO AL 2020), \nIND\n2019:243604\n2021:336111\n( 38% RISPETTO AL 2019 E 2020);  VUOTO\n2019:57958\n2021:184638\n(  218% RISPETTO AL 2019  30% RISPETTO AL 2020)\nPOZZO\n2019:140248\n2021:93155(-34% RISPETTO AL 2019 E -30% RISPETTO AL 2020) \nI reparti in perdita rispetto al 2019 sono LLF -12% (perdita clienti come siap, brovedani) e NCV-7% (dovuto allo spostamento di lavorazioni su bari) \nPozzo -34% (dovuto allo spostamento di lavorazioni su bari) mentre per gli altri reparti si registrano trend positivi  30% VUOTO e  38% Induzione.','Puntare sul potenziamento della tempra in vuoto con divulgazione della nuova potenzialità per arrivo nuovo forno nonchè cercare di acqusire commesse di cmt in bassa pressione e proporre ai clienti questa tecnologia in sostituzione di quella tradizionale ad elevato impatto ambientale .\nPer recuperare il gap nel reparto LLF cercare di acquisire nuove commesse non automotive come DANA e SMITH e consolidare la collaborazione con TAS e BONFIGLIOLI. ','/snap/79_1644508262.png',1),(1449,78,2021,'III TRI',NULL,'Il reparto cementazione nel 2021 rispetto al 2019 e anni precedenti han visto una riduzione relativa di fatturato a favore di altre lavorazioni come da target.  ','In ottica di diversificazione dei trattamenti proposti e del relativo rischio l\'azienda si pone come obiettivo di ridurre l\'incidenza del fatturato derivante da cementazione ad un valore massimo del 50% spingendo attraverso il commerciale sulle altre lavorazioni a livello di prezzo. ','/snap/78_1639060116.png',1),(1450,74,2021,'III TRI',NULL,'L\'andamento del fatturato 2021 rispetto al 2020 registra un valore positivo di  10,27% tuttavia rispetto al budget il valore è negativo pari a -3,43% causa commesse come Brovedani -80% (stimati 200.000€ anno)che non hanno rispettato i volumi previsti e i volumi in perdita dei clienti del settore auto rispetto al budget vedi Cebi-14,14%, BenVautier-80,82%,. ','Spingere per il rispetto dei volumi oggetto di contratto , cercare di aggiudicarsi le offerte in stand by, puntare sull\'acquisizione delle commesse non auto.','/snap/74_1638191806.png',1),(1451,73,2021,'III TRI',NULL,'L\'azienda dopo anni di crescita nel in cui il budget veniva raggiunto dai valori effettivi . Nel 2020 causa pandemia ed effetti correlati  , si è riscontrato un gap tra quanto previsto e quanto fatturato . Nel 2021 tale gap è ridotto.','Verificare cliente per cliente i potenziali valori di fatturato previsti per il 2022 in modo da ridurre l\'errore in fase di definizione dei budget commerciali e correlati ','/snap/73_1638897729.png',1),(1452,69,2021,'III TRI',NULL,'La quota di mercato Temprasud è ferma nel 2020 allo stesso valore del anno precedente  mentre i ns principali competitors  hanno guadagnato quote di mercato  (Colmegna 1.5 punti percentuali e GRTT 0.5)\n','Cercare di recuperare quote di mercato facendo leva sul prezzo (con aumenti inferiori rispetto ai concorrenti)','/snap/69_1638873123.png',1),(1461,100,2021,'III TRI',NULL,'Partendo dal target dello 0,3% abbiamo nel 2021 una medi a dei primi 3 trimestri pari  a:1,01 contro la media dello 0,69 nel 2020.\nE\'\' evidente che nel 2021 grazie al rallentamento del covid abbiamo potuto dare esecuzione ai corsi pianificati, tant\'è che sui 30 corsi del nostro piano di formazione possiamo considerare conclusi quasi 20 (18 conclusi e 2 in corso).\nAbbiamo  inoltre implementato molti corsi sulla sicurezza in vista della certificazione ISO 45001.\n\n\n\n\n','1) riprogrammare e concludere i corsi non portati a termine.\nEstendere come previsto assessment (tecniche di comunicazione e gestione conflitti) fatto per gli impiegati anche ai capiturno e agli operatori.\n2)Stiamo predisponendo con adecco progetti di tipo ludicocastomizzati sul senso di appartenenza all\'azienda.\n\n\n\n\n\n ','/snap/100_1638210112.png',1);
INSERT INTO `assessment_widget` VALUES (1533,116,2021,'III TRI',NULL,'Alla luce dei risultati ottenuti, si evince che i piani di manutenzione (programmati,predittivi e straordinari)sono funzionali per il raggiungimento dei risultati prefissati','La strategia per il futuro deve essere quella del miglioramento continuo e cioè di intendere i vari programmi di manutenzione \"dinamici\". questa strategia ci permette di integrare e correggere eventuali lacune e/o eliminare controlli che non ci garantiscono un valore aggiunto.','/snap/116_1638347747.png',1),(1535,120,2021,'III TRI',NULL,'Il target del 90% di manutenzione programmata è stato raggiunto per tutti gli impianti ad eccezione dei forni ncv. \nQuesto risultato non conforme è conseguenza di un fermo impianto (NCV3) prolungato per la mancanza di un ricambio difficilmente reperibile sul mercato. La relativa NC ( 50/2021) ha portato,come azione preventiva :\n1)aggiornamento piano di manutenzione MO 7,11C:Controllo valvola di non ritorno pompa vuoto	ncv3 e ncv4 	\n2)aggiornamento scorte critiche MO 7,11 REV 01 DEL 21/04/2021  : kit revisione pompa vuoto , costo 1380 euro','la strategia per il futuro, per evitare fermi impianti prolungati, deve essere quello dell\'aggiornamento continuo delle scorte critiche, ricerche di mercato che ci consentano, laddove possibile,di sostituire componenti di aziende difficilmente reperibili sul mercato con componenti compatibili con lead time ridotto.\ncontinuo sviluppo e aggiornamento dei moduli di manutenzione programmata e predittiva.\nRispettare la pianificazione della manutenzione programmata MO 7.11D  ','/snap/120_1638350255.png',1),(1536,118,2021,'III TRI',NULL,'I ritardi nell\'esecuzione delle manutenzioni, sia programmate che predittive, sono ben al di sotto del target assegnato','Per annullare completamente i ritardi è necessario continuare con la formazione delle nuove risorse sulla corretta esecuzione delle manutenzioni programmate e predittive ( 86bis/2021)','/snap/118_1638350244.png',1),(1540,149,2021,'III TRI',NULL,'Lo scopo di questo kpi è quello di monitorare il numero di interventi effettuati in base alle segnalazioni fatte su MO7.11L.I risultati mostrano una diminuzione di interventi rispetto all\'anno precedente del 5.67%. La diminuzione delle segnalazioni  significano anche che i programmi di manutenzione sugli impianti sono ottimali','Si analizzano le manutenzioni straordinarie per attuare modifiche alla manutenzione programmata per il 2022. ad esempio, per induzione, viste le ripetute segnalazioni, verrà inserito un trattamento antibatterico periodico su tutte le vasche di induzione e vasca quench.','/snap/149_1638351511.png',1),(1542,157,2021,'III TRI',NULL,'il tempo medio di riparazione per il reparto NCV risulta non conforme a causa di un fermo prolungato per mancanza pezzo di ricambio. ','in seguito ai fermi è necessario continuare ad analizzare nel migliore dei modi le NC per evitare il ripetersi delle failure.\nnello specifico :\n-NCV3: NC 50/2021 è scaturito:\n1)aggiornamento piano di manutenzione MO 7,11C:Controllo valvola di non ritorno pompa vuoto	ncv3 e ncv4 	\n2)aggiornamento scorte critiche MO 7,11 REV 01 DEL 21/04/2021  : kit revisione pompa vuoto\n','/snap/157_1638353706.png',1),(1546,158,2021,'III TRI',NULL,'per tutti i forni della famiglia LLF i dati sono ottimali e cioè al di sopra del target (non hanno subito fermi) ad eccezione dell\'llf1 che ha subito 2 fermi nel corso dell\'anno e , quindi , risulta al di sotto del target assegnato pari a 6 mesi.\n\nPER GIUSEPPE: INSERIRE GLI ALTRI SCREENSHOT PER I VARI REPARTI; NE SALVA SOLO 1','Continuare ad analizzare nella maniera più corretta possibile le NC in maniera tale da ottimizzare e implementare le manutenzioni sia programmate che predittive sugli impianti.(NC 94/2021)','/snap/158_1638354668.png',1);
INSERT INTO `assessment_widget` VALUES (1548,159,2021,'III TRI',NULL,'Il target asegnato del 95 % è stato raggiunto per tutti i forni tranne l\'NCV3 dove non era presente il pezzo di ricambio (NC 50/2021)\n\nPER GIUSEPPE: INSERIRE GLI ALTRI SCREENSHOT PER I VARI REPARTI; NE SALVA SOLO 1\n','Continuare ad analizzare le NC per rendere i controlli predittivi/programmati dinamici, cioè integrarli e migliorarli continuamente . Trimestralemte si esegue eventuale aggiornamento dei piani di manutenzione (programmata e predittiva).','/snap/159_1638355132.png',1),(1555,70,2021,'III TRI',NULL,'La redditività Tempra sud nel corso del 2020 è incrementata in controtendenza a tutti i concorrenti . Tale fenomento è dovuto da un lato al contenimento e ottimizzazione costi e dall\'altro alla sospensione dei leasing per 6 mesi .','Per il futuro l\'obiettivo è quello di raggiungere o avvicinare i risultati della Genarl tempering. ','/snap/70_1638470074.png',1),(1557,71,2021,'III TRI',NULL,'L\'incidenza degli oneri finanziari  è leggermente aumentato nel 2020 a causa della contrazione del fatturato . ','Cercare di ridurre il costo % degli oneri finanziari avvicinandoci al valore target del 0.75% attraverso una attenta analisi dei fidi bancari','/snap/71_1638470329.png',1),(1559,101,2021,'III TRI',NULL,'L\'indebitamento 2020 a causa della contrazione fatturato è arrivato nuovamente ai limiti accettabili . ','Contenere l\'indebitamento % al di sotto dell\'80 % del fatturato .','/snap/101_1638472163.png',1),(1561,105,2021,'III TRI',NULL,'Gli investimenti e la rivalutazione dei beni aziendali effettuata nel 2020 hanno determinato un aumento dell\'attivo aziendale che ha superato il valore obiettivo ','Continuare a investire parte del EBTDA in investimenti produttivi al fine di mantenere invariato l\'attivo patrimoniale. ','/snap/105_1638470510.png',1),(1563,103,2021,'III TRI',NULL,'L\'EBTDA %  sud nel corso del 2020 è incrementata . Tale fenomento è dovuto da un lato al contenimento e ottimizzazione costi e dall\'altro alla sospensione dei leasing per 6 mesi .','Mantenere EBTDA sopra il valore obiettivo del 20% del fatturato ','/snap/103_1638470576.png',1),(1565,104,2021,'III TRI',NULL,'ROI al di sotto del valore obiettivo anche a causa di un continuo aumento di capitale investito .','il mantenimento del capitale investito totale dovrà portare il ROI al valore obiettivo del 15% ','/snap/104_1638470634.png',1),(1567,106,2021,'III TRI',NULL,'Le perdite su crediti del 2020 nonostante la pandemia sono rimaste in linea con i valori dello scorso anno e sotto la soglia di allarme ','Continuare a monitorare il livello di rischio dei clienti in considerazione dei rischi di default successivi al termine di periodo di aiuti statali ','/snap/106_1638470705.png',1),(1569,102,2021,'III TRI',NULL,'La % di insoluti del 2020 è stata sopra la media degli ultimi semestri e sopra il target a causa delle difficoltà pandemiche . ','Nel 2021 e anni successivi è necessario monitorare attentamente la situazione insoluti bloccando le forniture al secondo episodio .','/snap/102_1638470760.png',1),(1574,155,2021,'III TRI',NULL,'Costi materie prime servizi e manodopera : Nel corso del 2020 tempra sud ha efficienziato il costo rispetto alla concorrenza (3°posto).\nRelativamente ai costi fissi risulta un incidenza maggiore per l\'elevata capitalizzazione .\n','L\'aumento dei costi di materie prime e servizi del prossimo anno , determinerà una situazione di tensione probabilmente maggiore per i nostri clienti rispetto a Tempra sud (meno esposta per servizi e materie prime ) ','/snap/155_1638472172.png',1);
INSERT INTO `assessment_widget` VALUES (1658,72,2021,'III TRI',NULL,'L\'andamento del fatturato 2021 rispetto al 2020 registra un valore positivo di  10,27% tuttavia rispetto al budget il valore è negativo pari a -3,43% causa commesse come Brovedani -80% (stimati 200.000€ anno)che non hanno rispettato i volumi previsti e i volumi in perdita dei clienti del settore auto rispetto al budget vedi Cebi-14,14%, BenVautier-80,82%,. ',' Spingere per il rispetto dei volumi oggetto di contratto , cercare di aggiudicarsi le offerte in stand by, puntare sull\'acquisizione delle commesse non auto.','/snap/72_1638895284.png',1),(1659,68,2019,'II TRI',NULL,'KPI CONFERMATO:\nCON DATI PRESI DA TABELLA CONCORRENTI \nINSERIMENTO ANNALE MANUALE','SPOSTARE IN SCHEDA DIREZIONE ','/snap/68_1643021292.png',1),(1660,69,2019,'II TRI',NULL,'KPI CONFERMATO:\nDATI PRESI DA TABELLA CONCORRENTE\nINSERIMENTO ANNALE MANUALE','SPOSTARE IN SCHEDA DIREZIONE','/snap/69_1643021295.png',1),(1661,72,2019,'II TRI',NULL,'KPI INVARIATO .\nDati di fatturato mensile li prende da QWIN .\n','MODIFICA : Il valore di budget in corso lo prenderà da file excel o  TEAM SYSTEM (DA DEFINIRE) .\n\n\nPREVEDERE STESSO KPI PER UNITRAT\n','/snap/72_1643021299.png',1),(1662,73,2019,'II TRI',NULL,'KPI INVARIATO .\nDati di fatturato mensile li prende da QWIN .','MODIFICA : Il valore di budget in corso lo prenderà da file excel o  TEAM SYSTEM (DA DEFINIRE).\n\nPREVEDERE STESSO KPI PER UNITRAT','/snap/73_1643019305.png',1),(1665,74,2019,'II TRI',NULL,'KPI INVARIATO .\nDati di fatturato mensile li prende da QWIN .','MODIFICA : Il valore di budget in corso lo prenderà da file excel o  TEAM SYSTEM (DA DEFINIRE).\n\nRAPPRESENTAZIONE GRAFICA : AVERE ISTOGRAMMA SU PIU\' ANNI CON RIFERIMENTO % A  BUDGET ANNO IN CORSO , ANNO N-1 , ED N-2 , E N-3 .\nSEMPRE VALORI IN % \n\nPREVEDERE STESSO KPI PER UNITRAT','/snap/74_1643021310.png',1),(1666,75,2019,'II TRI',NULL,'KPI INVARIATO .\nDati di fatturato mensile li prende da QWIN \n\nINSERIRE BUDGET ','MODIFICA : Il valore di budget in corso lo prenderà da file excel o  TEAM SYSTEM (DA DEFINIRE).\n\nMANTENERE PER I BUDGET STESSA FORMULA DI 11 MESI (CON DICEMBRE E AGOSTO CHE VALGONO 0.5) \n\nPREVEDERE STESSO KPI PER UNITRAT','/snap/75_1643021316.png',1),(1676,79,2019,'II TRI',NULL,'MODIFICARE KPI NELLA FORMA .\n','CREARE UNO TIPO \"Quote di mercato\" in modo da avere visione nel tempo dei fatturati macroarea.\n\nPRENDERE DATI DA VOCI GRUPPO DI LAVORAZIONI INVECE DI COME AVVIENE OGGI (CON LE LAVORAZIONI A CUI BISOGNA AGGIORNARE MAPPING) \n\nREPARTI:\nCMT\nNIT\nVUOTO\nIND\nALTRO\n\n\nPREVEDERE STESSO KPI PER UNITRAT\n\n\n','/snap/79_1643021326.png',1),(1678,78,2019,'II TRI',NULL,'KPI INVARIATO .\nDati di fatturato mensile li prende da QWIN ','PROPOSTE: PRENDERE DATI DA VOCI GRUPPO DI LAVORAZIONI INVECE DI COME AVVIENE OGGI (CON LE LAVORAZIONI A CUI BISOGNA AGGIORNARE MAPPING) \n\nREPARTI:\nCMT\nNIT\nVUOTO\nIND\nALTRO\n\nPREVEDERE STESSO KPI PER UNITRAT\n','/snap/78_1643021323.png',1),(1679,81,2019,'II TRI',NULL,'KPI CONFERMATO ','CAMBIARE NOME IN GDC 80% FATTURATO\n\nPREVEDERE STESSO KPI PER UNITRAT\n\nSPOSTARE IN CARTELLA DIREZIONE','/snap/81_1643021331.png',1),(1683,82,2019,'II TRI',NULL,'KPI CONFERMATO SOLO PER LE VOCI \" % DI CHIUSURA\" E \"TEMPO DI EMISSIONE\". SDOPPIARE IN DUE KPI DISTINTI.\n\nELIMINARE  IMPORTO TOTALE OFFERTE EMESSE E\nVALORE OFFERTE CONFERMATE \n','DA VALUTARE COME PRENDERE I DATI DALLE OFFERTE EMESSE DA TEAM SYSTEM.\n\nI DUE KPI DEVONO ESSERE GRAFICAMENTE DIVERSI DAL TACHIMETRO IN MODO DA DARE INDICAZIONE NEGLI ANNI RISPETTO A N-1 E N-2 (ISTOGRAMMA).\n\nPREVEDERE STESSO KPI PER UNITRAT  \n\n\n','/snap/82_1643021335.png',1),(1689,80,2019,'II TRI',NULL,'ELIMINARE ','','/snap/80_1643021328.png',1),(1690,77,2019,'II TRI',NULL,'ELIMINARE ','','/snap/77_1643021318.png',1);
INSERT INTO `assessment_widget` VALUES (1692,84,2019,'II TRI',NULL,'CONFERMATO ','ATTUALMENTE DATO INSERITO MANUALE ANNUALMENTE ,DA VALUTARE LA POSSIBILITA\' DI PRELEVARE IL DATO TRIMESTRALMENTE IN AUTMATICO DA TEAM SYSTEM \n\nKPI DA SPOSTARE IN DIREZIONE\n\nPREVEDERE STESSO KPI PER UNITRAT','/snap/84_1643020047.png',1),(1698,83,2019,'II TRI',NULL,'OK CONFERMATO','DA VALUTARE COME PRENDERE I DATI DALLE OFFERTE EMESSE DA TEAM SYSTEM.\n\nMODIFICARE IN STILE \"QUOTE DI MERCATO\" PER VEDERE L\'ANDAMENTO DELLE OFFERTE PER REPARTO (DA VEDERE CON TEAM SISTEM COME GESTIRE I REPARTI) \n\nPREVEDERE STESSO KPI PER UNITRAT\n\n','/snap/83_1643193866.png',1),(1700,86,2019,'II TRI',NULL,'KPI CONFERMATO ','DATO INSERITO IN MANUALE UNA VOLTA ALL\'ANNO ','/snap/86_1643021349.png',1),(1703,85,2019,'II TRI',NULL,'CONFERMATO CON MODIFICHE','DA VALUTARE COME PRENDERE I DATI DALLE OFFERTE EMESSE DA TEAM SYSTEM.\n\n\nMODIFICARE IN STILE \"QUOTE DI MERCATO\" PER VEDERE L\'ANDAMENTO DELLE OFFERTE PER REPARTO \n\nPREVEDERE STESSO KPI PER UNITRAT\n','/snap/85_1643021343.png',1),(1704,136,2019,'II TRI',NULL,'KPI CONFERMATO','DA VALUTARE COME PRENDERE I DATI DALLE OFFERTE EMESSE DA TEAM SYSTEM.\n\nMODIFICARE IN STILE \"QUOTE DI MERCATO\" PER VEDERE L\'ANDAMENTO DELLE OFFERTE PER REPARTO\n\nPREVEDERE STESSO KPI PER UNITRAT','/snap/136_1643021137.png',1),(1706,87,2019,'II TRI',NULL,'ELIMINARE ','','/snap/87_1643021437.png',1),(1737,70,2019,'II TRI',NULL,'KPI CONFERMATO\n\nMANTENERE INSERIMENTO MANUALE\nANNUALE\n\nproposta di presentazione grafica \n\n ','','/snap/70_1643043380.png',1),(1739,71,2019,'II TRI',NULL,'KPI CONFERMATO \n\nMANTENERE INSERIMENTO MANUALE\nANNUALE\n \n\neventuale proposta grafica ','','/snap/71_1643043414.png',1),(1741,101,2019,'II TRI',NULL,'KPI CONFERMATO \n\nMANTENERE INSERIMENTO MANUALE\nANNUALE\n\nDA PREVEDERE ANCHE IN UNITRAT\n','','/snap/101_1643043548.png',1),(1743,105,2019,'II TRI',NULL,'KPI CONFERMATO \n\nMANTENERE INSERIMENTO MANUALE\nANNUALE\n\nDA PREVEDERE ANCHE IN UNITRAT','','/snap/105_1643043641.png',1),(1744,103,2019,'II TRI',NULL,'KPI CONFERMATO \n\nMANTENERE INSERIMENTO MANUALE\nANNUALE\n\nDA PREVEDERE ANCHE IN UNITRAT','','/snap/103_1643043650.png',1),(1746,104,2019,'II TRI',NULL,'KPI CONFERMATO \n\nMANTENERE INSERIMENTO MANUALE\nANNUALE\n\nDA PREVEDERE ANCHE IN UNITRAT','','/snap/104_1643190658.png',1),(1747,106,2019,'II TRI',NULL,'KPI CONFERMATO \n\nMANTENERE INSERIMENTO MANUALE\nANNUALE\n\nDA PREVEDERE ANCHE IN UNITRAT','MODIFICARE LA SCALA DA SEMETRALE A ANNUALE','/snap/106_1643043690.png',1),(1748,102,2019,'II TRI',NULL,'KPI CONFERMATO \n\nDA PREVEDERE ANCHE IN UNITRAT\n\nprevedere per tutti i kpi unitrat tempra sud anche due target diversi  ','VERIFICARE ACQUISIZIONE AUTOMATICA DA FILE EXCEL MO 9.3  SEMESTRALE .\n\ncolonna importo  \n','/snap/102_1643043789.png',1),(1753,155,2019,'II TRI',NULL,'KPI DA MODIFICARE','INSERIRE IN STILE \"QUOTE DI MERCATO \" COSTI DIVISI PER TIPOLOGIA PER ANNO \n\nMANTENERE INSERIMENTO MANUALE DATI ','/snap/155_1643043946.png',1),(1764,130,2019,'II TRI',NULL,'SDOPPIARE KPI ED ELIMINARE TRIMESTRE PRECEDENTE  \n\n','SOPPIARE IL KPI PER LE TIPOLOGIE \nPRESENTI SU QWIN \n1)AMBIENTE \n2)SICUREZZA \n3)QUALITA\' (RACCOGLIE TUTTI GLI ALTRI : ACQUISTI - LOGISTICA - MANUTENZIONE - QUALITA\' - SISTEMA  )\n\nPREVEDERE ANCHE PER UNITRAT   ','/snap/130_1643025657.png',1),(1765,147,2019,'II TRI',NULL,'MANTENERE STESSA GRAFICA KPI ','CONTEGGIARE SOLO LE NUOVE AZIONI DI MIGLIORAMENTO APERTE NEL PERIODO DI TEMPO SELEZIONATO.SDOPPIARE secondo grafico  PER TAG (AMBIENTE SICUREZZA QUALITA\') \n\nPREVEDERE ANCHE PER UNITRAT ','/snap/147_1643191710.png',1),(1766,150,2019,'II TRI',NULL,'MANTENERE STESSA GRAFICA KPI','MONITORAR LE AZIONI DI MIGLIORAMENTO CHIUSE O IN CORSO  NELL\'ANNO DI RIFERIMENTO NEL PROGETTO PIANO DI MIGLIORAMENTO CONTINUO .\nSDOPPIARE UN SECONDO GRAFICO IN CUI SI PUO\' SELEZIONARE IL TAG (SCEGLIERE TRA: SICUREZZA QUALITA\' AMBIENTE).\n\nMANTENERE STESSI STATI\n\n\nPREVEDERE ANCHE PER UNITRAT ','/snap/150_1643025687.png',1);
INSERT INTO `assessment_widget` VALUES (1775,109,2019,'II TRI',NULL,'KPI DA MANTENERE E REPLICARE PER UNITRAT ','CONFERMATA FORMULA . \n\nORE MALATTIE/ORE LAVORATE \n\n\nVERIFICARE SE E\' POSSIBILE ACQUISIRE IN AUTOMATICO LE ORE MALATTIA E LAVORATE DA SOFTWARE HR\n\n\n','/snap/109_1643041437.png',1),(1778,111,2019,'II TRI',NULL,'KPI DA MANTENERE E REPLICARE PER UNITRAT','MODIFICARE FORMULA. \n\nORE FERIE RESIDUE /(ORE STANDARD ANNUE) \n \nORE STANDARD ANNUE = 200 \n * 8 ORE * NUMERO DIPENDENTI \n\nVERIFICARE SE E\' POSSIBILE ACQUISIRE IN AUTOMATICO LE ORE FERIE RESIUDE E NUMERO DIPENDENTI MEDIO ANNUO  DA SOFTWARE HR\n\n\n','/snap/111_1643041611.png',1),(1781,110,2019,'II TRI',NULL,'KPI DA MANTENERE E REPLICARE PER UNITRAT','ORE STRAORDINARIO /ORE LAVORATE \n\n\nVERIFICARE SE E\' POSSIBILE ACQUISIRE IN AUTOMATICO LE ORE STRAORDINARIO E LAVORATE DA SOFTWARE HR\n\n\n','/snap/110_1643042724.png',1),(1788,112,2019,'II TRI',NULL,'SDOPPIARE IN DUE KPI \n\n\nDA REPLICARE IN UNITRAT \n','% INFORTUNI : LASCIARE COSI IL CALCOLO\nVERIFICANDO SE INSERIRE ORE O GIORNI IN BASE A TEAM SYSTEM\n\nNEAR MISS (QUASI INFOTUNI ) CONTEGGIARE IL NUMERO DI EVENTI AL MESE E VALORE MEDIO ANNUO CON INSERIMENTO MANUALE\n\nSPOSTARE IN SICUREZZA  ENTRAMBI I KPI','/snap/112_1643199380.png',1),(1805,113,2019,'II TRI',NULL,'KPI DA CONFERMARE CON INSERIMENTO MANUALE ANNUALE DEL DATO \n\n\nPREVEDERE PER UNITRAT','CREARE NUOVO KPI DI DETTAGLIO ISTOGRAMMA DELLE DOMANDE  ATTINGENDO DA UN QUESTIONARIO AUTOMATICO DA GESTIRE CON TS O ALTRO SOFTWARE','/snap/113_1643042777.png',1),(1807,100,2019,'II TRI',NULL,'KPI DA MANTENERE \n\n\nELIMINARE LA BARRA DEI TRIMESTRI PRECEDENTI\n\nMODIFICARE IN ISTOGRAMMA CON VALORE ANNO IN CORSO , VALORE BUDGET E VALORE ANNO -1  E -2 ','VERIFICARE AUTOMAZIONE CON HR CON IMPORTAZIONE AUTOMATICA DEL VALORE ECONOMICO DELLE FORMAZIONI VALORIZZANDO LE ORE A COSTO ORARIO STANDARD \n\nIN ALTERNATIVA MONITORARE LE ORE DI FORMAZIONE E RAPPORTARLE AL MONTE ORE DI PERIODO STANDARD  ','/snap/100_1643042929.png',1),(1814,128,2019,'II TRI',NULL,'MANTENERE KPI\n\nPREVEDERE PER UNITRAT  \n','IL COSTO DA PRENDERE E\' IL COSTO NON QUALITA\' LOGISTICO \n\n\n','/snap/128_1643045481.png',1),(1845,97,2019,'II TRI',NULL,'MANTENERE KPI \n\nPREVEDERE STESSO PER UNITRAT ','SDOPPIARE PER AUTOMOTIVE O NON AUTOMOTIVE CON MENU A TENDINA\n\nELIMINARE TRIMESTRE PRECEDENTE   ','/snap/97_1643044146.png',1),(1847,96,2019,'II TRI',NULL,'KPI DA VERIFICARE \n\nPREVEDERE ANCHE PER UNITRAT  ','VERIFICARE FORMULA\n\nCONTABILIZZARE SOLO LE NC LEGATE A QUALITA\'  \n\nNON QUELLE GENERICHE SENZA COMMESSA O LEGATE A ALTRE CAUSE (AMBIENTE , LOGISTICA , MANUTENZIONE \nETC) \n\nSDOPPIARE PER AUTOMOTIVE O NON AUTOMOTIVE CON MENU A TENDINA  \n\nELIMINARE TRIMESTRE PRECEDENTE ','/snap/96_1643044200.png',1),(1851,94,2019,'II TRI',NULL,'KPI DA MANTENERE \n\n\n\n\nPREVEDERE ANCHE PER UNITRAT ','VERIFICARE FORMULA CON DATI PRESI DA QWIN \n\n(PEZZI SCARTATI    ACCETTATI IN DEROGA   RILAVORATI) / NUMERO PEZZI FATTURATI\n\nINSERIRE SU NC QWIN LE TRE VOCI INVECE DI ANDARE SU COLLAUDO \n\nSDOPPIARE PER AUTOMOTIVE O NON AUTOMOTIVE CON MENU A TENDINA \n\nELIMINARE TRIMESTRE PRECEDENTE \n ','/snap/94_1643044409.png',1),(1853,98,2019,'II TRI',NULL,'KPI DA MANTENERE \n\n\n\n\nPREVEDERE ANCHE PER UNITRAT ','SOMMA COSTI COMPLESSIVI (RILAVORAZIONE   ADDEBITO ) PER LA SOLA TIPOLOGIA QUALITA\' \n\nELIMINARE TRIMESTRE PRECEDENTE \n\nSDOPPIARE PER AUTOMOTIVE O NON AUTOMOTIVE CON MENU A TENDINA ','/snap/98_1643044447.png',1),(1859,95,2019,'II TRI',NULL,'KPI DA MANTENERE \n\n\n\n\nPREVEDERE ANCHE PER UNITRAT','PRENDERE SOLO VALORI DI SCARTO DA MODULO NC QWIN \n\nELIMINARE TRIMESTRE PRECEDENTE \n\nSDOPPIARE PER AUTOMOTIVE O NON AUTOMOTIVE CON MENU A TENDINA \n','/snap/95_1643202399.png',1),(1862,151,2019,'II TRI',NULL,'KPI DA MANTENERE \n\n\n\n\nPREVEDERE ANCHE PER UNITRAT','DAL 2022 PRENDERE IL DATO DA NC \n\nSOLO NC 8D PROBLEM SOLVING  \n\nDATA DI APERTURA  \nDATA DI CHIUSURA\n\nSDOPPIARE TRA AUTOMOTIVE E NON\nCON TENDINA  ','/snap/151_1643044953.png',1);
