INSERT INTO `filter` VALUES (50,'reparto_ts','autocomplete','global/local',0,'temprasud_bi: SELECT DISTINCT reparto, reparto\r\nFROM kpi_produzione\r\nWHERE reparto != \"IND\" AND reparto != \"CBF\"',NULL,'Reparto:',NULL,3,'NCV','NCV',0),(51,'fornitori_mp_ts','autocomplete','global/local',0,'temprasud_bi: SELECT DISTINCT cod_clifo, name \r\nFROM fornitori_con_ordini\r\nWHERE tipologia = \'Materia_Prima\'\r\nUNION ALL SELECT \'-Tutti-\' AS cod_clifo, \'-Tutti-\' AS name\r\nORDER BY name',NULL,'Fornitore:',NULL,0,'-Tutti-','0',0),(52,'fornitori_con_ordini_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT fornitori.id_crm, name \r\nFROM fornitori_con_ordini\r\nLEFT JOIN fornitori ON fornitori.id_crm = fornitori_con_ordini.id_crm\r\nWHERE fornitori.monitora = 1\r\nUNION ALL SELECT \'-Tutti-\' AS id_crm, \'-Tutti-\' AS name\r\nORDER BY name',NULL,'Fornitore:',NULL,0,'-Tutti-','-Tutti-',0),(53,'nc_reparti_ts','combo','global/local',0,'','-tutte-:-Tutte-;27:Ambiente;28:Logistica;30:Qualità;43:Sicurezza;29:Manutenzione;65:Acquisti;66:Esterna;31:Di Sistema','Motivazione:',NULL,2,'27','27',0),(54,'clienti_ind_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT cl.codice_anagrafica, cl.rag_sociale\r\nFROM registro_induzione AS i\r\nLEFT JOIN commesse AS co ON i.NumeroCommessa = co.`Numero Commessa`\r\nLEFT JOIN clienti AS cl ON cl.codice_anagrafica = co.`Codice Cliente`\r\nUNION ALL\r\nSELECT \"-Tutti-\" AS codice_anagrafica, \"-Tutti-\" AS rag_sociale\r\nORDER BY rag_sociale',NULL,'Cliente:',NULL,0,'-Tutti-','-Tutti-',0),(55,'pezzi_ind_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT co.IDProdotto, CONCAT(co.CodiceProdotto, \" - \", co.`Descrizione Prodotto`)\r\nFROM registro_induzione AS i\r\nLEFT JOIN commesse AS co ON i.NumeroCommessa = co.`Numero Commessa`\r\nUNION ALL\r\nSELECT \"-Tutti-\" AS IDProdotto, \"-Tutti-\" AS `Descrizione Prodotto`\r\nORDER BY IDProdotto',NULL,'Pezzo:',NULL,1,'-Tutti-','-Tutti-',0),(56,'operatori_ind_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT o.`ID Operatore`, o.NomeOperatore\r\nFROM registro_induzione AS i\r\nLEFT JOIN operatori AS o ON i.IDOperatore = o.`ID Operatore`\r\nUNION ALL\r\nSELECT \"-Tutti-\" AS `ID Operatore`, \"-Tutti-\" AS NomeOperatore\r\nORDER BY `ID Operatore`',NULL,'Operatore:',NULL,2,'-Tutti-','-Tutti-',0),(57,'all_reparto_ts','autocomplete','global/local',0,'temprasud_bi: SELECT DISTINCT reparto, reparto\r\nFROM kpi_produzione',NULL,'Reparto:',NULL,3,'NCV','NCV',0),(58,'materie_prime_only_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT  CONCAT(prodotti_new.idz,\"@\",prodotti_new.fk_fornitore) AS id, TRIM(CONCAT(prodotti_new.name,\" - \", replace(f.rag_sociale, \'\"\', \"\'\"))) AS name\r\nFROM prodotti_new \r\nLEFT JOIN fornitori AS f ON f.id_crm = prodotti_new.fk_fornitore\r\nWHERE tipologia = \"Materia Prima\" AND fk_fornitore IS NOT NULL AND f.monitora = 1\r\nUNION ALL SELECT \'-Tutte-\' AS id, \'-Tutti-\' AS name\r\nORDER BY name ASC',NULL,'Materia prima:',NULL,2,'-Tutte-','-Tutte-',0),(59,'automtive_ts','combo','global/local',0,'','-tutte-:-Tutte-;automotive:Automotive;non_automotive:Non automotive','Tipologia:',NULL,2,'-tutte-','-tutte-',0),(60,'utenti_zp_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT owners_id, owners_name\r\nFROM zp_task\r\nUNION ALL\r\nSELECT \'-Tutti-\' AS owners_id, \'-Tutti-\' AS owners_name\r\nORDER BY owners_name',NULL,'Utente:',NULL,2,'-Tutti-','-Tutti-',0),(61,'anno_zp_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT YEAR(start_date)\r\nFROM zp_task',NULL,'Anno:',NULL,2,'2019','2019',0),(62,'zone_trasporti_ts','autocomplete','global/local',1,'temprasud_bi: SELECT DISTINCT zona FROM excel_analisi_trasporti UNION SELECT \'-Tutte-\'',NULL,'Zona:',NULL,2,'2019','2019',0);
