INSERT INTO `widget` VALUES (68,'Quote di mercato','qm_fatturati','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene i fatturati della Temprasud e dei sui correnti suddivisi per anno. Ogni pila corrisponde ad un anno.</p>','<p>Tabella dati concorrenti su SAPERE.</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\REPORTING\\CONCORRENTI.xlsx',1,NULL,NULL),(69,'Quote di mercato','qm_quote','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma a torta ripartisce le quote di mercato tra Temprasud e i suoi concorrenti per l\'anno selezionato</p>','<p>Tabella dati concorrenti su SAPERE.</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\REPORTING\\CONCORRENTI.xlsx',1,NULL,NULL),(70,'ROS Concorrenti','ros_concorrenti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento dei fatturati di Tempra sud e dei suoi concorrenti.</p>','<p>Tabella dati concorrenti su SAPERE.</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\REPORTING\\CONCORRENTI.xlsx',1,NULL,NULL),(71,'ROD %','rod_concorrenti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento del rapporto tra Oneri finanziari e Debiti Totali.</p>\r\n<p><b>Formula: </b>Oneri finanziari / Debiti Totali</p>','<p>Tabella dati concorrenti su SAPERE.</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\REPORTING\\CONCORRENTI.xlsx',1,NULL,NULL),(72,'Fatturato per mese','fatturato_per_mese','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento dei fatturati cumulati degli ultimi anni e del budget dell\'ultimo anno.</p>\r\n<p>Il fatturato del mese in corso e dei mesi futuri è stimato in base alla variazione percentuale del fatturato dell\'anno in corso rispetto all\'anno precedente.</p>','<p>QWIN (fatturato)</p>','D:\\ARCHIVIO\\COMMERCIALE\\budget_commerciale_corretto.xls',1,NULL,NULL),(73,'Budget/fatturato','budget_fatturato','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma contiene i fatturati e i budget annuali della Temprasud per anno espressi a coppie di barre.</p>','<p>QWIN (fatturato)</p>\r\n<p>Tabella Budget SAPERE</p>\r\n','D:\\ARCHIVIO\\COMMERCIALE\\budget_commerciale.xls',1,NULL,NULL),(74,'Fatturato - Confronto','fatturato_confronto','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene 2 barre rappresentanti la % del fatturato del periodo scelto rispetto all\'anno precedente e rispetto al budget.</p>\r\n<p>Il budget di uno specifico cliente viene calcolato prendendo il budget anunale del cliente dell\'anno della data di partenza del periodo di riferimento rapportato al numero di mesi selezionati</p>','<p>QWIN (fatturati clienti con Temprasud)</p>\r\n<p>Tabella Budget SAPERE</p>\r\n','D:\\ARCHIVIO\\COMMERCIALE\\budget_commerciale_corretto.xls',1,NULL,NULL),(75,'Fatturato Clienti','fatturato_clienti','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene, per il cliente selezionato, i fatturati totali e i fatturati con Temprasud per anno espressi a coppie di barre.</p>','<p>QWIN (fatturati clienti con Temprasud), Excel (fatturato totale cliente)</p>','D:\\ARCHIVIO\\COMMERCIALE\\budget_commerciale_corretto.xls',1,NULL,NULL),(77,'Fatturato Clienti nel tempo','./widgets/temprasud/fatturato_clienti_nel_tempo','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>QWIN (fatturati clienti con Temprasud), Excel (fatturato totale cliente)</p>','D:\\ARCHIVIO\\COMMERCIALE\\budget_commerciale_corretto.xls',1,NULL,NULL),(78,'Fatturato Macroaree','fatturato_macroaree','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento del fatturato delle 5 macroaree.</p>','<p>QWIN (fatturato), la ripartizione del fatturato in macroaree viene fatta tramite un excel di mapping.</p>',NULL,1,NULL,NULL);
INSERT INTO `widget` VALUES (79,'Fatturato Macroaree - Confronto','fatturato_macroaree_confronto','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene un istogramma rappresentante il fatturato della macroarea selezionata (o di tutte le macroaree) del periodo scelto rispetto all\'anno precedente.</p>','<p>QWIN</p>',NULL,1,NULL,NULL),(80,'GDC nel tempo','./widgets/temprasud/gdc_nel_tempo','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>QWIN</p>',NULL,1,NULL,NULL),(81,'GDC 80% Fatturato','gdc_80_perc','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre o annualmente il numero di clienti che generano l\'80% del fatturato.</p>\r\n<p>Per calcolare l\'80% del fatturato si considera l\'incrementale del trimestre o dell\'anno in corso.</p>','<p>QWIN, dati sul fatturato</p>',NULL,1,NULL,NULL),(82,'Efficacia Commerciale Tempo Emissione','efficacia_commerciale_emissione','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma rappresenta il valore della metrica \"Tempo di emissione\" delle offerte e lo stesso valore nei 2 periodi precedenti.</p><p><b>Formula Team System: </b>SUM(DataDocumento - DataConsegna) / Tot. offerte</p>','<p>Team System - modulo Offerte</p>\r\n<p>Con campi DataDocumento e DataConsegna valorizzati.</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(83,'Valore offerte nel tempo','valore_offerte_nel_tempo','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta per anno l\'andamento per reparto dell\'importo totale delle offerte e del valore di quelle confermate.</p>\r\n<p>Si considera la data del documento come riferimento.</p>\r\n<p><b>Formula: </b>è la somma dell\'importo delle offerte, per reparto.</p>','<p>Team System</p>\r\n<p>Campi: Importo, RepartoOfferta</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(84,'Tempo di incasso','tempo_di_incasso','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno il tempo di incasso (somma voci 14 e 15 / somma fatturato x 365).</p>\r\n<p>Per gli anni per i quali non sono ancora presenti i saldi di apertura dei bilanci vengono considerati i crediti fino all\'ultimo anno con bilancio chiuso.</p>\r\n<p>I valori delle voci sono composti dalla somma di tutti i relativi conti ignorando i movimenti di chiusura.</p>\r\n<p>Per l\'anno corrente viene considerato il fatturato cumulato degli ultimi 12 mesi.</p>','<p>Excel MO 1.6_Budget commerciale integrato, colonna \"GG. PAGAMENTO MEDIO\".</p>',NULL,1,NULL,NULL),(85,'Motivi di rinuncia per numero','motivi_di_rinuncia','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma ripartisce i motivi di rinuncia delle offerte.</p>\r\n<p>Per ripartire le offerte nel tempo si utilizza la data del documento.</p>\r\n<p>Vengono considerate solo le offerte con esito negativo o con esito non specificato o con Stato CRM \'Stand by\'.</p>\r\n<p>Vengono ignorate le offerte di tipo \'AUMENTO\'.</p>\r\n<p>Le offerte per le quali il motivo di rinuncia non è stata specificato vengono conteggiate nel diagramma nel gruppo \'Non specificato\'.</p>','<p>Fino ad aprile 2019 Excel Offerte, foglio OFFERTE (presente un excel per ogni anno)</p>\r\n<p>Da aprile 2019 a dicembre 2022 Zoho CRM</p>\r\n<p>D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL);
INSERT INTO `widget` VALUES (86,'Variazione prezzi','variazione_prezzi','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno la variazione % generale dei prezzi.</p>\r\n<p><b>Formula: </b>(somma fatturato * %aumento) / somma fatturato</p>','<p>QWIN per il fatturato e file excel MO 1.6_Budget commerciale integrato 2023 per l\'aumento di listino (Colonna \"aumento strutturale 2023 %\").</p>\r\n<p>Negli anni precedenti l\'aumento di listino era gestito tramite il CRM.</p>\r\n<p>Per maggiori info sui dati consulta la <a href=\"http://sapere-temprasud.studioware.it/tabella-riepilogo-clienti\">Tabella Riepilogo Clienti</a></p>','D:\\ARCHIVIO\\COMMERCIALE\\budget_commerciale_corretto.xls',1,NULL,NULL),(88,'% R.N.C. a fornitori da CRM','conformita_fornitori_crm','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene la conformità del fornitore selezionato, in percentuale.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p><b>Formula:</b> Ordini con stato non conforme / Totale ordini</p>','<p>CRM fino al 2022</p>\r\n<p>Non Conformi con Status = \'Evaso con non conformità\'</p>\r\n<p>Totale Ordini con Status != \'In Corso\' </p>',NULL,1,NULL,NULL),(89,'Ritardo medio ordini da CRM','ritardo_medio_fornitori_crm','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta il ritardo medio degli ordini calcolato in base al Lead Time sui prodotti e alla data di evasione ordine.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p>Nel calcolo del tempo di evasione dell\'ordine cengono ignorati i weekend e il giorno della data di apertura ordine.</p>\r\n<p><b>Formula: </b> (Data Evasione Ordine - Data Ordine) - Lead Time Prodotto</p>','<p>CRM fino al 2022</p>',NULL,1,NULL,NULL),(90,'Puntualità Fornitori da CRM','puntualita_fornitori_crm','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta la percentuale di ordini chiusi in tempo consideranto il lead time target dei prodotti e il tempo di evasione degli ordini stessi.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p>Il ritardo medio di un ordine è così calcolato = (Data Evasione Ordine - Data Ordine) - Lead Time Prodotto</p>\r\n<p>Se il ritado medio è > 0 l\'ordine viene considerato in ritardo.</p>\r\n<p>Nel calcolo del ritado medio di evasione dell\'ordine Vengono ignorati i weekend e il giorno della data di apertura ordine.</p>\r\n<p><b>Formula: </b> [1 - (ordini in ritardo / totale ordini)] * 100</p>','<p>CRM fino al 2022</p>',NULL,1,NULL,NULL),(91,'Costo Materie Prime da CRM','costo_materie_prime_crm','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento dell\'aumento ponderato dei costi delle materie prime.</p>\r\n<p><b>Formula: </b>SUM(variaz_perc_anno_prec * totale ordinato) / SUM(totale ordinato)</p>','<p>Excel Materie Prime (fino al 2014, i valori dell\'excel sono congelati)</p>\r\n<p>CRM (dal 2015 in poi fino al 2022)</p>',NULL,1,NULL,NULL),(92,'Tempo medio pagamento','./widgets/temprasud/tempo_pagamenti_fornitori','temprasud','small','\'100%\'','\'100%\'',NULL,'GAMMA',NULL,1,NULL,NULL);
INSERT INTO `widget` VALUES (93,'Report Acquisti','report_acquisti','temprasud','small','\'100%\'','\'100%\'','<p>Nel widget sono presenti i link ai report dell‘ambito acquisti.</p>\r\n<p>I dati sono un\'aggregazione in Excel dei kpi della Dashboard Acquisti.</p>','<p>Team System e QWIN</p>\r\n<p><b>Report Performance Fornitori:</b></p>\r\n<ul>\r\n    <li>anno di riferimento</li>\r\n    <li>ordini annui</li>\r\n    <li>% NC ordini</li>\r\n    <li>% Puntualità</li>\r\n    <li>% Aumento ponderato prezzi prodotti per fornitore con media ponderata pesata</li>\r\n</ul>\r\n<p><b>Report Costi Materie Prime:</b> per ogni prodotto, per anno in corso e anno-1 e anno-2</p>\r\n<ul>\r\n    <li>quantità acquistata</li>\r\n    <li>importo speso</li>\r\n    <li>% aumento ponderato tra un anno e l\'altro</li>\r\n</ul>',NULL,1,NULL,NULL),(94,'KPI External (Rilavorazioni + Scarti + Deroga)','kpi_external','temprasud','small','\'100%\'','\'90%\'','Il diagramma presenta temporalmente per trimestre l‘andamento in parti per milioni dei pezzi rilavorati, scartati o derogati dal cliente.','<p>QWIN - Modulo Timbrate NC Esterne</p>\r\n<p><b>Formula</b> = [(Pezzi Scartati + Pezzi accettati in deroga + Pezzi rilavorati da reclamo) / Numero Pezzi fatturati ]  * 1 m</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,5),(95,'PPM Scarti','ppm_scarti','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento in parti per milioni dei pezzi rottamati (o scarto) dal cliente a causa di specifiche non conformi riconducibili a difetti di trattamento.</p>\r\n<p><b>Formula: </b>SUM(Q.ty reject pieces pcs/months) / SUM(Qtà consegnata pcs/months) * 1M</p>\r\n<p>La somma viene effettuata sui mesi di analisi scelti nei filtri.</p>','<p>QWIN Commesse NC PezziNonConformi e Quantità Consegnata dal fatturato (Da NC Esterne)</p>\r\n<p>Formula = (Q.ty reject pieces pcs/months)/ Qta consegnata pcs/months * 1M</p>',NULL,1,NULL,3),(96,'% Internal NC','internal_nc','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento della % delle commesse rilavorate per difetti di trattamento.</p>\r\n<p>Vengono contabilizzate solo le NC legate a qualità.</p>','<p>QWIN - Dati prelevati dal modulo \"Non Conformità\" di QWin. I dati sono presi e selezionati tenendo conto della data di apertura del report di NC.</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,4),(97,'% Addebiti','addebiti','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre l\'andamento della % degli addebiti.</p>\r\n<p><b>Formula: </b>addebiti € / Fatturato</p>','<p>QWIN - Dati inseriti in Costo Addebito</p>\r\n<p>Il costo viene estrapolato dalle NC Qualità ed Esterne, dalla casella Costo Addebito (Azioni Immediate)</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,2),(98,'Costi non qualità / fatturato','costi_non_qualita','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre l\'andamento dei costi complessivi / Fatturato</p>\r\n<p><b>Formula: </b> Costi non qualità / Fatturato</p>','<p>QWIN Commesse NC (Da NC Esterne e Qualita\')</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,1);
INSERT INTO `widget` VALUES (99,'% Efficacia azioni miglioramento','./widgets/temprasud/azioni_miglioramento','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>Zoho Projects</p>\r\n<p>Le azioni chiuse con esito positivo sono i task con stato \"Chiuso\"</p>\r\n<p>Le azioni chiuse con esito negativo sono i task con stato \"Archiviato\"</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2016.xsls',1,NULL,NULL),(100,'% Investimento formazione','./widgets/temprasud/inv_formazione','temprasud','medium','\'100%\'','\'100%\'',NULL,'Excel Formazione (foglio protocollo formazione, colonna costi), Excel Non conformitÃ  (colonna Fatturato n/months)<p>D:\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2014\\2014_Piano_di_formazione.xls\nD:\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2015\\ADDESTRAMENTO_FORMAZIONE PERSONALE 2015\\2015_Piano_di_formazione</p>\nD:\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2015\\ADDESTRAMENTO_FORMAZIONE PERSONALE 2016\\ADDESTRAMENTO_FORMAZIONE PERSONALE\\2016_Piano_di_formazione\nD:\\TEMPRASUD\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2017\\ADDESTRAMENTO_FORMAZIONE PERSONALE 2017\\2017_Piano_di_formazione.xls\nD:\\TEMPRASUD\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2018\\2018_Piano_di_formazione.xlsx</p>','D:\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2014\\2014_Piano_di_formazione.xls\nD:\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2015\\ADDESTRAMENTO_FORMAZIONE PERSONALE 2015\\2015_Piano_di_formazione',1,NULL,NULL),(101,'Indebitamento %','indebitamento_percentuale','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per annola % Indebitamebto (Indebitamento / Fatturato).</p>','<p>Tabella dati Direzione su SAPERE</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\KPI_Direzione.xlsx',1,NULL,NULL),(102,'% Insoluti','perc_insoluti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese la % insolui: Insoluti / Fatturato.</p>','<p>Tabella dati Direzione su SAPERE</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\KPI_Direzione.xlsx',1,NULL,NULL),(103,'EBTDA %','ebtda','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno la % EBTDA.</p>\r\n<p><b>Formula: </b>(Utile Netto + Tasse + Ammortamento + Oneri Finanziari) / Fatturato</p>','<p>Tabella dati Direzione su SAPERE</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\KPI_Direzione.xlsx',1,NULL,NULL),(104,'ROI %','roi','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno il ROI.</p>\r\n<p><b>Formula: </b>Utile Netto / Totale Passività</p>','<p>Tabella dati Direzione su SAPERE</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\KPI_Direzione.xlsx',1,NULL,NULL),(105,'Attivo','attivo','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno il Totale attivo.</p>','<p>Tabella dati Direzione su SAPERE</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\KPI_Direzione.xlsx',1,NULL,NULL),(106,'% Crediti Inesigibili','perc_crediti_inesigibili','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese la % scaduti: Scaduti / Fatturato.</p>','<p>Tabella dati Direzione su SAPERE</p>','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\KPI_Direzione.xlsx',1,NULL,NULL),(107,'Efficacia Campionature','eff_campionature','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre l\'efficacia delle campionature, #campionature approvate / tot campionature. Il valore è suddiviso per Automotive e Non Automotive.</p>\r\n','<p>QWIN modulo Campionature (colonne esito, numero campionature e data accetazione materiale)</p>','D:\\ARCHIVIO\\LABORATORIO\\CAMPIONATURE\\MO 7.5.1_ARCHIVIO CAMPIONATURE_ELENCO PPAP_2012_2013_2014_02.xlsx',1,NULL,NULL);
INSERT INTO `widget` VALUES (108,'Rapidità Campionature','rap_campionature','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre il lead time medio delle campionature, sia con esito positivo che negativo. Il valore è suddiviso per Automotive e Non Automotive</p>','<p>QWIN modulo Campionature  (colonne lead time e data accetazione materiale)</p>','D:\\ARCHIVIO\\LABORATORIO\\CAMPIONATURE\\MO LAB 102_ARCHIVIO CAMPIONATURE_PPAP_2012_2013_2014_02.xlsx',1,NULL,NULL),(109,'% Assenteismo','./widgets/temprasud/personale_assenteismo','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento della % assenteismo.</p>\r\n<p>Il diagramma disegna anche il valore in roll-up degli ultimi 12 mesi.</p>\r\n<p><b>Formula:</b> Ore malattia / Ore lavorate</p>','<p>Sincronizzazione da Team System HR</p>\r\n<p>Tabella \"Gestione dati Personale\" su SAPERE per consultazione e forzatura</p>','D:\\ARCHIVIO\\PERSONALE\\KPI PERSONALE.xlsx',1,NULL,NULL),(110,'% Straordinario','./widgets/temprasud/personale_straordinario','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento della % dello straoridnario.</p>\r\n<p>Il diagramma disegna anche il valore in roll-up degli ultimi 12 mesi.</p>\r\n<p><b>Formula:</b> Ore straordinari / Ore lavorate</p>','<p>Sincronizzazione da Team System HR</p>\r\n<p>Tabella \"Gestione dati Personale\" su SAPERE per consultazione e forzatura</p>','D:\\ARCHIVIO\\PERSONALE\\KPI PERSONALE.xlsx',1,NULL,NULL),(111,'% Ferie Residue','./widgets/temprasud/personale_ferie_residue','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento della % delle ferie residue.</p>\r\n<p>Il diagramma disegna anche il valore in roll-up degli ultimi 12 mesi.</p>\r\n<p><b>Formula:</b> Ore ferie residue / Ore standard</p>','<p>Sincronizzazione da Team System HR</p>\r\n<p>Tabella \"Gestione dati Personale\" su SAPERE per consultazione e forzatura</p>','D:\\ARCHIVIO\\PERSONALE\\KPI PERSONALE.xlsx',1,NULL,NULL),(112,'% Infortuni','perc_infortuni','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento della % infortuni.</p>\r\n<p>Il diagramma disegna anche il valore in roll-up degli ultimi 12 mesi.</p>','<p>Tabella \"Gestione dati Personale\" su SAPERE</p>','D:\\ARCHIVIO\\PERSONALE\\KPI PERSONALE.xlsx',2,'Target % quasi infortuni',NULL),(113,'Motivazione dipendenti','./widgets/temprasud/personale_soddisfazione','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno la soddisfazione complessiva dei dipendenti.</p>','<p>Tabella \"Gestione dati Personale\" su SAPERE</p>','D:\\ARCHIVIO\\PERSONALE\\KPI PERSONALE.xlsx',1,NULL,NULL),(114,'Efficienza produttiva','produzione_prod_impianti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l‘andamento della produttività degli impianti per il reparto scelto, intesa come Ore produttive/Ore acceso.</p>\r\n<p><b>Formula: Ore produttive / Ore acceso</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p> <p>Ore di funzionamento effettivo da datawarehouse</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(115,'Tasso Qualità','tasso_qualita','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese il rendimento globale degli impianti per il reparto scelto.</p>\r\n<p><b>Formula:</b> Ore produttive / Ore funzionamento effettivo</p>\r\n<p>Le <i>Ore Produttive</i> sono calcolate come le <i>Ore Funzionamento Effettivo - Rilavorazioni</i></p>\r\n<p>Le <i>Ore funzionamento effettivo</i> sono calcolate come le <i>Ore Acceso - Perdite</i></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>',NULL,1,NULL,NULL);
INSERT INTO `widget` VALUES (116,'Equipment Availability','produzione_efficacia_man','temprasud','medium','\'100%\'','\'100%\'','<p> Il diagramma presenta temporalmente per mese la efficacia della pianificazione manutenzione, intesa come:</p>\r\n<p><b>Formula:</b> 1 - (Ore spento per manutenzione programmata/preventiva + Ore spento per manutenzione straordinaria, guasto + Ore in stand-by per guasto / man. Straordinaria) / Capacità Teorica.</p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(117,'Saturazione Commerciale','produzione_saturazione_eff','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese la saturazione commerciale degli impianti.</p>\r\n<p><b>Intesa come (Capacità teorica-Festività- Ore spento per mancanza materiale –Ore spento per manutenzione programmata/preventiva - Ore spento per Man. Straordinaria/guasto)  / Capacità teorica.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(118,'Rapidità Manutenzione','./widgets/temprasud/produzione_rap_manutenzione','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per mese il ritardo della manutenzione programmata e della manutenzione predditiva sui vari impianti numero di manutenzioni programmate eseguite in ritardo / numero di manutenzioni programmate totali numero di manutenzioni predditive eseguite in ritardo / numero di manutenzioni predditive totali</p>','<p>Tabella Dati Ritardo Manutezione Predittiva/Programmata  su SAPERE</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(119,'Ritardo Man.ne Straord. Totali','./widgets/temprasud/produzione_rap_manutenzione_confronto','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>Tabella Dati Ritardo Manutezione Straordinaria su SAPERE</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(120,'Ripartizione Ore Manutenzione','./widgets/temprasud/produzione_efficacia_man_torta','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma ripartisce per reparto le ore di manutenzione svolte sugli impianti.</p>','<p>Tabella Dati Impianti  su SAPERE</p>\r\n<p>Dal 2022 viene sincronizzato il modulo Giustificativo Impianti</p>\r\n<p>Per il KPI vengono letti i dati su:</p>\r\n<p>Ore spento per manutenzione programmata/preventiva</p>\r\n<p>Ore spento per Man. Straordinaria/guasto</p>\r\n<p>Ore in stand-by per Man. Straordinaria/guasto</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(121,'LT medio','produzione_lt_medio','temprasud','medium','\'100%\'','\'100%\'','Il diagramma presenta temporalmente per gruppo il lead time medio delle commesse nel periodo selezionato.\r\n\r\nLead Time medio = Data chiusura - Data Ric. Mat.','QWIN (commesse)',NULL,1,NULL,NULL),(122,'Report Produzione','report_produzione','temprasud','small','\'100%\'','\'100%\'','<p>Nel widget sono presenti i link ai report dell‘ambito produzione.</p>','<p>QWIN</p>',NULL,1,NULL,NULL),(123,'% Lead time','produzione_lt_medio_target','temprasud','medium','\'100%\'','\'100%\'','Il diagramma presenta temporalmente per gruppo la percentuale di commesse in ritardo rispetto l\'lt target.\r\n\r\nLead Time medio = Data chiusura - Data Ric. Mat.','QWIN (commesse)',NULL,2,'Soglia gg per considerare una commessa in ritardo',NULL);
INSERT INTO `widget` VALUES (124,'Resa carica media','produzione_resa','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno la resa carica media dei cicli per il reparto selezionato intesa come (#Fornate x Kg/Fornate x Variazione % rispetto all\'anno precedente) / (Sommatoria #Fornate x Kg/Fornate). Nella sommatoria vengono considerati solo i cicli con una variazione di resa diversa da 0 rispetto all\'anno precedente e non superiore o inferiore al 100%.</p>\r\n<p><b>Formula: (#Fornate x Kg/Fornate x Variazione % rispetto all\'anno precedente) / (Sommatoria #Fornate x Kg/Fornate)</b></p>','QWIN (commesse)',NULL,1,NULL,NULL),(125,'Analisi perdite induzione','produzione_induzione_torta_mc','temprasud','medium','\'100%\'','\'100%\'','Il grafico ripartisce le ore non strettamente legate alla produzione (manutenzione, set up, guasto, ...) svolte sugli impianti del reparto induzione per l\'anno scelto rispetto al totale ore cartellino.','<p>Perdite induzione sul QWIN</p>\r\r\n<p>Ore Cartellino da Team System HR a cui vengono sottratte le ore di funzionamento effettivo provenienti da QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_INDUZIONE.xlsx',1,NULL,NULL),(126,'Efficienza Produttiva','produzione_induzione_eff','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma mostra per mese la produttività degli impianti induzione intesa come Ore funzionamento effettivo / Ore acceso.</p>\r\n<p>Per Induzione:</p>\r\n<p>ORE DI FUNZIONAMENTO EFFETTIVO = SOMMA (ORE SET-UP + ORE TEMPRA INDUZIONE DA SMARCATURA QWIN)</p>\r\n<p>ORE ACCESO = ORE CARTELLINO per operai reparto induzione</p>\r\n<p><b>Formula: </b>Ore funzionamento effettivo / Ore acceso</p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p> <p>Ore Cartellino da Team System HR</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_INDUZIONE.xlsx',1,NULL,NULL),(127,'Saturazione Commerciale Induzione','produzione_induzione_saturazione','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese la saturazione commerciale degli impianti.</p>\r\n<p><b>Intesa come (Capacità teorica-Festività- Ore spento per mancanza materiale –Ore spento per manutenzione programmata/preventiva - Ore spento per Man. Straordinaria/guasto)  / Capacità teorica.</b></p>','<p>Tabella Dati Impianti su SAPERE, (Capacità teorica-Festività-Ore spento per mancanza materiale)/Capacità teorica</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_INDUZIONE.xlsx',1,NULL,NULL),(128,'Costo non qualità','costo_non_qualita','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre i coti extra trasporti sostenuti.Il diagramma disegna anche il valore per lo stesso mese dell‘anno precedente.</p>','<p>QWIN / Qualità / Non conformità Tipo NC LOGISTICA (colonna CostoLavorazioni)</p>','D:\\TEMPRASUD\\ARCHIVIO\\SISTEMA QUALITA\' ED 2020\\P5 - Logistica\\MO\\MO 5.7 ANALISITRASPORTI.xlsx',1,NULL,NULL),(129,'% NC Logistica','./widgets/temprasud/nc_logistica','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>Fino al 2018 Excel Costi Extra Trasporti - D:\\ARCHIVIO\\ACQUISTI\\COSTI EXTRA TRASPORTI.xlsx</p>\n<p>Dal 2019 Costi Extra Trasporto registrati nel CRM</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,NULL),(130,'% NC per tipologia','nc_reparti','temprasud','small','\'100%\'','\'100%\'','Il diagramma presenta temporalmente per trimestre l‘andamento % delle non conformità legate alla motivazione selezionata.\r\n\r\nIl diagramma disegna anche il valore per lo stesso mese dell‘anno precedente.\r\n\r\nFormula: NC Motivazione / N° Commesse aperte nel periodo','<p>QWIN</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,NULL);
INSERT INTO `widget` VALUES (131,'Registro Induzione','produzione_registro_induzione','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta la produttività delle commesse (pz/h) per i filtri specificati: Pezzi Lavorati / Ore Totali Lavorate. Nelle Ore Totali Lavorate sono incluse solo le ore di lavorazione (no Tempi Setup, ...). Vengono mostrate solo le commesse con pezzi lavorati o ore lavorate maggiori di 0.</p>\r\n<p><b>Formula: Pezzi Lavorati / Ore Totali Lavorate</b></p>','<p>QWIN</p>',NULL,1,NULL,NULL),(132,'Registro Induzione Ponderato','produzione_registro_induzione_ponderato','temprasud','medium','\'100%\'','\'100%\'','Il diagramma presenta la produttività media delle commesse (pz/h) per mese per i filtri specificati. ','<p>QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_RITARDO MAN OK.xlsx',1,NULL,NULL),(133,'Rispetto tempistica APQP - DISMESSO','./widgets/temprasud/produzione_apqp_vumeter','temprasud','small','\'100%\'','\'100%\'',NULL,'Excel apqp<p>D:\\ARCHIVIO\\QUALITA\'\\APQP\\KPI APQP.xlsx (foglio per kpi)</p>','D:\\ARCHIVIO\\QUALITA\'\\APQP\\KPI APQP.xlsx',1,NULL,NULL),(134,'Rispetto tempistica APQP - DISMESSO','./widgets/temprasud/produzione_apqp_torta','temprasud','small','\'100%\'','\'100%\'',NULL,'Excel apqp<p>D:\\ARCHIVIO\\QUALITA\'\\APQP\\KPI APQP.xlsx (foglio per kpi)</p>','D:\\ARCHIVIO\\QUALITA\'\\APQP\\KPI APQP.xlsx',1,NULL,NULL),(135,'NC Logistica','nc_logistica_num','temprasud','small','\'100%\'','\'100%\'','Il diagramma mostra il numero di non conformità logistica (motivazione diversa da Produzione) per trimestre. ','<p>QWIN / Qualità / Non conformità Tipo NC LOGISTICA</p>\r\n','D:\\ARCHIVIO\\ACQUISTI\\COSTI EXTRA TRASPORTI.xlsx',1,NULL,NULL),(136,'Motivi di rinuncia per valore','motivi_di_rinuncia_per_valore','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma ripartisce i motivi di rinuncia delle offerte per valore.</p>\r\n<p>Per ripartire le offerte nel tempo si utilizza la data del documento.</p>\r\n<p>Vengono considerate solo le offerte con esito negativo o con esito non specificato o con Stato CRM \'Stand by\'.</p>\r\n<p>Vengono ignorate le offerte di tipo \'AUMENTO\'.</p>\r\n<p>Le offerte per le quali il motivo di rinuncia non è stata specificato vengono conteggiate nel diagramma nel gruppo \'Non specificato\'.</p>','<p>Fino ad aprile 2019 Excel Offerte, foglio OFFERTE (presente un excel per ogni anno)</p>\r\n<p>Da aprile 2019 a dicembre 2022 Zoho CRM</p>\r\n<p>D:\\ARCHIVIO\\TEMPRASUD\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\r\n    D:\\ARCHIVIO\\TEMPRASUD\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\r\n    D:\\ARCHIVIO\\TEMPRASUD\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx\r\n    D:\\ARCHIVIO\\TEMPRASUD\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2016.xlsx\r\n    D:\\ARCHIVIO\\TEMPRASUD\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2017.xlsx\r\n    D:\\ARCHIVIO\\TEMPRASUD\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2018.xlsx</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(137,'OEE','oee','temprasud','medium','\'100%\'','\'100%\'','<p>L\'Overall Equipment Effectiveness (OEE) è la misura di efficacia totale di un impianto e riassume in sé i concetti di: disponibilità (frazione di tempo in cui l\'impianto è effettivamente disponibile),efficienza (la velocità con cui l\'impianto sta lavorando come frazione rispetto a quella di progetto) ed il tasso di qualità ( cioè le unità in specifica rispetto a tutte quelle prodotte)\r\n</p>\r\n<p><b>Formula:</b> Tasso Qualità * Efficienza Produttiva * Eq.Availability </p>','<p>Tabella  Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p> <p>Ore di funzionamento effettivo da datawarehouse</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL);
INSERT INTO `widget` VALUES (140,'Sintesi Impianti','./widgets/temprasud/produzione_sintesi','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta una sintesi sulla percentuale di utilizzo degli impianti.</p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(142,'Report Manutenzione','./widgets/temprasud/manutenzione_reports','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>QWIN</p>',NULL,1,NULL,NULL),(143,'Numero di Campionature','numero_campionature','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre il numero di campionature. Il valore è suddiviso per Automotive e Non Automotive</p>','<p>QWIN modulo Campionature (colonna data ricezione materiale)</p>','D:\\ARCHIVIO\\LABORATORIO\\CAMPIONATURE\\MO 7.5.1_ARCHIVIO CAMPIONATURE_ELENCO PPAP_2012_2013_2014_02.xlsx',1,NULL,NULL),(144,'Ritardo Man.ne Straord. Mancanza Materie','./widgets/temprasud/produzione_rap_manutenzione_mancanza_materie','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>Tabella Dati Ritardo Manutezione Straordinaria su SAPERE</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(145,'Ritardo Man.ne Straord. Altre prioritÃ ','./widgets/temprasud/produzione_rap_manutenzione_altre_priorita','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>Tabella Dati Ritardo Manutezione Straordinaria su SAPERE</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(146,'Ritardo Man.ne Straord. Ripartizione','./widgets/temprasud/manutenzione_torta','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>Tabella Dati Ritardo Manutezione Straordinaria su SAPERE</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(147,'Nuove azioni di miglioramento','azioni_miglioramento_new','temprasud','medium','\'100%\'','\'100%\'','Il diagramma presenta temporalmente per trimestre le nuove azioni di miglioramento aperte.\r\n\r\nDal 2019 i dati vengono prelevati da Zoho Projects. Vengono considerati tutti i task dei progetti nei raggruppamenti \'Miglioramenti semplici\' e \'Attività di miglioramento\'','<p>Zoho Projects</p>\r\n   ','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2016.xsls',1,NULL,NULL),(149,'Interventi Richiesti da Produzione','attivita_manutenzione','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma mostra il numero di attività di manutenzione diviso per mese, in base al tipo di intervento richiesto.</p>','<p>Tabella Dati Manutezione su SAPERE</p>','',1,NULL,NULL),(150,'Andamento azioni di miglioramento','azioni_miglioramento_new2','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma mostra l\'andamento della attività di miglioramento per risorsa. I dati vengono prelevati da Zoho Projects. Vengono considerati tutti i task e i subtask dei progetti nei raggruppamenti \'Miglioramenti semplici\' e \'Attività di miglioramento\' per il progetto \"PIANO MIGLIORAMENTO CONTINUO TEMPRASUD\".</p>\r\n<p>Per le \'azioni aperte\' vengono considerate anche quelle aperte negli anni precedenti a quello selezionato e non ancora chiuse.</p>\r\n<p>Per le \'azioni chiuse\' vengono considerate quelle chiuse nell\'anno selezionato indipendentemente da quando sono state aperte.</p>','<p>Zoho Projects</p>\n<p>Le azioni chiuse con esito positivo sono i task con stato \"Chiuso\"</p>\n<p>Le azioni chiuse con esito negativo sono i task con stato \"Archiviato\"</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2016.xsls',1,NULL,NULL);
INSERT INTO `widget` VALUES (151,'Tempo di Chiusura 8D','8d_tempo_chiusura','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre il tempo medio di chiusura delle non conformità gestite con l\'8D e chiuse nel trimestre.</p>\r\n<p>Data di apertura = DataNC</p>\r\n<p>Data di chiusura = DataChiusuraNC</p>\r\n<p>Tempo di risposta = data di chiusura - data di apertura</p>\r\n<p><b>Formula: </b> SUM(Tempo di risposta) / Tot. NC 8D chiuse nel periodo</p>','<p>QWIN NC 8D</p>',NULL,1,NULL,6),(152,'Nuovi 8D','8d_nuovi','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre il numero di non conformità gestite con l\'8D.</p>\r\n<p>La media viene calcolata tenendo in considerazione il numero assoluto di 8D diviso i trimestri selezionati.</p>','<p>QWIN NC 8D</p>',NULL,1,NULL,7),(153,'Resa media trasporti','costo_trasporto_mezzi_propri','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta per zona e per trimestre la resa media trasporti.</p>\r\n<p><b>Formula: </b>SUM(Kg Consegna) / Tot. viaggi per zona</p>','<p>QWIN modulo Gite (colonne PesoConsegna, PesoRitiro, CodicePercorso per la zona)</p>\r\n','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(154,'Costo medio trasporti','costo_trasporto_mezzi_propri2','temprasud','small','\'100%\'','\'100%\'','Il diagramma presenta per zona temporalmente: \\n - il valore medio mensile del costo trasporto ( Media Costi Totali / Media resa KG) nella zona scelta','<p>Excel Costo Trasporto mezzi Propri</p>\n<p>D:\\TEMPRASUD\\ARCHIVIO\\LOGISTICA E AMMINISTRAZIONE\\MODULI E PROCEDURE\\MO 5.5 ANALISITRASPORTI.xlsx</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(155,'Costi Concorrenti','costi_concorrenti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento del costo selezionato di Temprasud e dei suoi concorrenti.</p>','Tablla dati concorrenti su SAPERE.','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\REPORTING\\CONCORRENTI.xlsx',1,NULL,NULL),(157,'Mean Time to Repair Reparti','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per gruppo di reparti il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(158,'Mean Time between Repair Reparti','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per gruppo di reparti il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(159,'Equipment Availability Guasto','./widgets/temprasud/manutenzione_disponibilita','temprasud','medium','\'100%\'','\'100%\'',NULL,'<p>Tabella Dati Impianti su SAPERE</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL);
INSERT INTO `widget` VALUES (160,'PPM Scarti Collaudi','./widgets/temprasud/ppm_scarti.collaudi','temprasud','small','\'100%\'','\'100%\'',NULL,'<p>QWIN</p>\r\n<p>Formula = Pezzi Scarto definiti sui Collaudi / Numero Pezzi fatturati </p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,3),(161,'Rifiuti','rifiuti','temprasud','small','100%','100%',NULL,'Tabella dati rifiuti su SAPERE.',NULL,1,NULL,NULL),(162,'Emissioni','emissioni','temprasud','small','100%','100%','<p>Il diagramma mostra le emissioni registrate sulla tabella di input di SAPERE e i limiti di legge associati ad ogni inquinante.</p>','<p>Tabella dati emissioni su SAPERE</p>',NULL,1,NULL,NULL),(163,'Consumo Materie Prime','costo_materie_prime','temprasud','small','100%','100%','<p>Il diagramma presenta il consumo delle materie prime rispetto alle tonnellate di prodotto suddivisi per gruppi di lavoro.</p>\r\n<p><b>Formula:</b> Quantità MP famiglia / Quantità t prodotti famiglia</p>\r\n<p>Le famiglie per le materie prime vengono individuate tramite le associazioni alle lavorazioni</p>\r\n<p>Le associazioni sono consultabili tramite la tabella Materie Prime-Lavorazioni</p>\r\n<p>Le associazioni delle famiglie delle materie prime sono consultabili tramite la Tabella Mapping Famiglie Materie Prime </p>','<p>Ordini Team System per le quantità di materia prima</p>\r\n<p>Materie Prime-Lavorazioni per l\'associazione alla famiglia in base alla macroarea</p>\r\n<p>Tabella Mapping Famiglie Materie Prime per l\'associazione della materia prima alla famiglia</p>',NULL,1,NULL,NULL),(164,'Rifiuti Prodotti','rifiuti_prodotti','temprasud','small','100%','100%','<p>Il diagramma presenta la quantità di rifiuti prodotti (scarico) rispetto ai quintali di prodotto effettivo suddiviso per gruppi di lavoro.</p>\r\n<p><b>Formula:</b> Quantità rifiuti famiglia / Quantità q prodotti famiglia</p>\r\n<p>Le famiglie per i rifiuti vengono individuate tramite le associazioni alle lavorazioni</p>\r\n<p>Le associazioni sono consultabili tramite la tabella Rifiuti-Lavorazioni</p>','<p>Tabella di input su SAPERE</p>\r\n<p>Tabella Dati Rifiuti</p>\r\n<p>Rifiuti-Lavorazioni per l\'associazione alla famiglia in base alla macroarea</p>',NULL,1,NULL,NULL),(165,'Consumo Energia','energia_consumata','temprasud','small','100%','100%','<p>Il diagramma presenta il consumo di energia rispetto ai quintali di prodotto suddivisi per gruppi di lavoro.</p>\r\n<p><b>Formula:</b> Quantità Energia famiglia / Quantità q prodotti famiglia</p>\r\n<p>Le famiglie per l\'energia elettrica vengono individuate tramite le associazioni alle lavorazioni</p>\r\n<p>Le associazioni sono consultabili tramite la tabella Contatori-Lavorazioni</p>','<p>Tabella di input su SAPERE</p>\r\n<p>Tabella Dati Misurazioni Contatori</p>\r\n<p>Contatori-Lavorazioni per l\'associazione alla famiglia in base alla macroarea</p>',NULL,1,NULL,NULL),(166,'Analisi perdite induzione','produzione_induzione_torta','temprasud','medium','\'100%\'','\'100%\'','Il diagramma a torta ripartisce le ore non strettamente legate alla produzione (manutenzione, set up, guasto, ...) svolte sugli impianti del reparto induzione per l\'anno scelto rispetto al totale ore cartellino.','<p>Perdite induzione sul QWIN</p>\r\r\n<p>Ore Cartellino da Team System HR a cui vengono sottratte le ore di funzionamento effettivo provenienti da QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_INDUZIONE.xlsx',1,NULL,NULL);
INSERT INTO `widget` VALUES (167,'Mean Time between Repair LLF','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto LLF il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(169,'Mean Time between Repair NCV Cieffe','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto NCV Cieffe il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(170,'Mean Time between Repair NCV Ipsen','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto NCV Ipsen il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(172,'Mean Time between Repair TV','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto TV il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(173,'Mean Time between Repair ALU','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto ALU il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(174,'Mean Time between Repair IND','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto INDUZIONE il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(175,'Mean Time to Repair LLF','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto LLF il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL);
INSERT INTO `widget` VALUES (177,'Mean Time to Repair NCV Cieffe','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto NCV Cieffe il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(178,'Mean Time to Repair NCV Ipsen','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto NCV Ipsen il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(180,'Mean Time to Repair TV','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto TV il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(181,'Mean Time to Repair ALU','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto ALU il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(182,'Mean Time to Repair IND','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per il reparto INDUZIONE il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(183,'Numero NC Manutentive','nc_manutentive','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma mostra per trimestre il numero delle NC di tipologia MANUTENZIONE.</p>\r\n<p>Il diagramma mostra anche il valore per il periodo precedente.</p>','<p>QWIN commesse nc</p>',NULL,1,NULL,NULL),(184,'Costo NC Manutentive','costo_non_qualita_manutentive','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma mostra per trimestre il costo delle NC di tipologia MANUTENZIONE.</p>\r\n<p>Il diagramma mostra anche il valore per il periodo precedente.</p>\r\n','<p>QWIN commesse nc (colonna CostoLavorazioni)</p>',NULL,1,NULL,NULL),(185,'% NC Ambiente','nc_reparti/ambiente','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre l\'andamento % delle non conformità legate alla motivazione Ambiente. Formula: NC Motivazione / N° Commesse aperte nel periodo</p>','<p>QWIN</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,NULL);
INSERT INTO `widget` VALUES (186,'% NC Sicurezza','nc_reparti/sicurezza','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre l\'andamento % delle non conformità legate alla motivazione Sicurezza. Formula: NC Motivazione / N° Commesse aperte nel periodo</p>','<p>QWIN</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,NULL),(187,'% NC Qualità','nc_reparti/qualità','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per trimestre l\'andamento % delle non conformità legate alla motivazione Qualità (raccoglie tutti gli altri: acquisti - logistica - manutenzione - qualità - sistema). Formula: NC Motivazione / N° Commesse aperte nel periodo</p>','<p>QWIN</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls',1,NULL,NULL),(188,'% R.N.C. a fornitori','conformita_fornitori_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene la conformità del fornitore selezionato, in percentuale.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p><b>Formula:</b> Ordini con stato non conforme / Totale ordini evasi</p>','<p>Team System sia per il totale ordini evasi sia per le non conformità.</p>\r\n<p>Il campo Stato Ordine deve essere obbligatoriamente valorizzato con \"EVASO_CON_NON_CONFORMITA\" per far si che la non conformità venga conteggiata.</p>\r\n<p>Se specificato nei filtri, vengono presi gli ordini nc corrispondenti al fornitore.</p>',NULL,1,NULL,NULL),(189,'Puntualità Fornitori','puntualita_fornitori_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta la percentuale di ordini chiusi in tempo consideranto la data di prevista consegna e la data di evasione degli ordini stessi.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p><b>Formula: </b> [1 - (ordini in ritardo / totale ordini)] * 100</p>\r\n<p>Un ordine è considerato in ritardo se: la data di evasione supera la data di prevista consegna.</p>','<p>Team System</p>\r\n<p>Totale ordini in base al periodo indicato. Per totale ordini si intende tutti gli ordini <b>evasi</b>, compresi gli ordini delle materie prime.</p>\r\n<p>Campi: DataEvasione (DataConsegna), DataPrevistaConsegna.</p>\r\n<p>Gli ordini devono avere i campi DataOrdine, DataEvasione e DataPrevistaConsegna valorizzati.</p>',NULL,1,NULL,NULL),(190,'Ritardo medio ordini','ritardo_medio_fornitori_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta il ritardo medio degli ordini calcolato in base alla data di evasione ordine e alla data prevista consegna.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p><b>Formula: </b> Ritardo Medio = <i>SUM(DataEvasione - DataPrevistaConsegna) / Tot. ordini</i> [esclusi i weekend]</p>\r\n<p>Un ordine è considerato in ritardo se: la data di evasione supera la data di prevista consegna.</p>\r\n<p>Un ordine in anticipo ha Ritardo Medio = 0</p>','<p>Team System</p>\r\n<p>Totale ordini in base al periodo indicato. Per totale ordini si intende tutti gli ordini <b>evasi</b>, compresi gli ordini delle materie prime.</p>\r\n<p>Per il calcolo del ritardo medio, campi: DataEvasione (DataConsegna) e DataPrevistaConsegna.</p>\r\n<p>Gli ordini devono avere i campi DataOrdine, DataEvasione e DataPrevistaConsegna valorizzati.</p>',NULL,1,NULL,NULL);
INSERT INTO `widget` VALUES (191,'Var. Media Ponderata Materie Prime','costo_materie_prime_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta il confronto per il mese selezionato dei costi delle materie prime.</p>\r\n<p>Viene visualizzato il costo medio del primo mese selezionato, il costo medio del secondo mese selezionato e l\'aumento medio del costo.</p>\r\n<p>Vengono considerate solo le Materie Prime Critiche</p>\r\n<p><b>Formule:</b></p>\r\n<p>Prima del 2022 i dati non sono gestiti da Team System, quindi si calcola la media: <i>(costoTotaleAnnuale / quantitaTotaleAnnuale) / 12</i> </p>\r\n<p>Dopo il 2022 viene calcolato il valore mensile in base agli ordini di Team System. Costo Medio Mensile: <i>costoTotale / quantitaTotale</i></p>\r\n<p>Aumento Medio: costoMedioMensile - costoPrecMedioMensile</p>','<p>Team System</p>\r\n<p>Campi: PrezzoProdotto, QuantitàOrdinata, CodiceArticolo (per la materia prima), DataOrdine</p>\r\n<p>Per gli ordini delle materie prime relative al 2021 e 2022: Tabella Dati Costo Materie Prime su SAPERE</p>',NULL,1,NULL,NULL),(192,'Motivi di rinuncia per numero','motivi_di_rinuncia_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma ripartisce i motivi di rinuncia delle offerte.</p>\r\n<p>Per ripartire le offerte nel tempo si utilizza la data del documento.</p>\r\n<p>Vengono considerate le offerte con stato != ACCETTATA.</p>','<p>Team System</p>\r\n<p>Campi: Stato, DataDocumento, RepartoOfferta</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(193,'Motivi di rinuncia per valore','motivi_di_rinuncia_per_valore_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma ripartisce i motivi di rinuncia delle offerte per valore.</p>\r\n<p>Per ripartire le offerte nel tempo si utilizza la data del documento.</p>\r\n<p>Vengono considerate le offerte con stato != ACCETTATA.</p>','<p>Team System</p>\r\n<p>Campi: Stato, DataDocumento, RepartoOfferta</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(194,'Efficacia Commerciale % di Chiusura','efficacia_commerciale_chiusura','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma rappresenta il valore della metrica \"% di chiusura\" delle offerte e lo stesso valore nei 2 periodi precedenti.</p>\r\n\r\n<p><b>Formula Team System: </b>offerte chiuse / offerte totali</p>','<p>Team System - modulo Offerte</p>\r\n<p>Per TS sono considerate chiuse le offerte con stato ACCETTATA.</p>','D:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2013.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2014.xlsx\nD:\\ARCHIVIO\\COMEMRCIALE\\MO COM 03_Protocollo OFFERTE 2015.xlsx',1,NULL,NULL),(195,'Fatturato Centri di Lavoro','fatturato_cdl','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento del fatturato dei Centri di Lavoro.</p>\r\n<p>Gli impianti che fatturano meno di 30\'000 € vengono aggregati in \"Altri impianti\"</p>','<p>QWIN</p>',NULL,1,NULL,NULL),(196,'Fatturato Gruppi Lavorazioni','fatturato_gruppi_lavorazioni','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento del fatturato dei Gruppi Lavorazioni.</p>\r\n<p>Le lavorazioni che fatturano meno di 500\'000 € vengono aggregati in \"ALTRE LAVORAZIONI\"</p>','<p>QWIN</p>',NULL,1,NULL,NULL),(197,'% Near Miss','perc_quasi_infortuni','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l\'andamento della % di quasi infortuni.</p>\r\n<p>Il diagramma disegna anche il valore in roll-up degli ultimi 12 mesi.</p>','<p>Tabella \"Gestione dati Personale\" su SAPERE</p>','D:\\ARCHIVIO\\PERSONALE\\KPI PERSONALE.xlsx',2,'Target % quasi infortuni',NULL);
INSERT INTO `widget` VALUES (198,'Puntualità Materie Prime','puntualita_fornitori_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta la percentuale di ordini chiusi in tempo consideranto la data di prevista consegna e la data di evasione degli ordini stessi.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p><b>Formula: </b> [1 - (ordini in ritardo / totale ordini)] * 100</p>\r\n<p>Un ordine è considerato in ritardo se: la data di evasione supera la data di prevista consegna.</p>','<p>Team System</p>\r\n<p>Totale ordini in base al periodo indicato. Per totale ordini si intende tutti gli ordini delle materie prime <b>evasi</b>.</p>\r\n<p>Campi: DataEvasione (DataConsegna), DataPrevistaConsegna.</p>\r\n<p>Gli ordini devono avere i campi DataOrdine, DataEvasione e DataPrevistaConsegna valorizzati.</p>',NULL,1,NULL,NULL),(199,'Lead Time Fornitori','lead_time_fornitori_ts','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma presenta il lead time medio degli ordini calcolato in base alla data prevista consegna e alla data ordine.</p>\r\n<p>Viene calcolato l\'indicatore per il periodo scelto e per lo stesso periodo dell\'anno-1 e anno-2.</p>\r\n<p><b>Formula: </b> Lead Time Medio = <i>SUM(DataPrevistaConsegna - DataOrdine) / Tot. ordini</i> [esclusi i weekend]</p>','<p>Team System</p>\r\n<p>Totale ordini in base al periodo indicato. Per totale ordini si intende tutti gli ordini <b>evasi</b>, compresi gli ordini delle materie prime.</p>\r\n<p>Per il calcolo del lead time, campi: DataOrdine e DataPrevistaConsegna.</p>\r\n<p>Gli ordini devono avere i campi DataOrdine, DataEvasione e DataPrevistaConsegna valorizzati.</p>',NULL,1,NULL,NULL),(200,'Fatturato Centri di Lavoro - Confronto','fatturato_cdl_confronto','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene un istogramma rappresentante il fatturato del Centro di Lavoro selezionato (o di tutti i centri) del periodo scelto rispetto all\'anno precedente.</p>','<p>QWIN</p>',NULL,1,NULL,NULL),(201,'Fatturato Gruppi di Lavorazioni - Confronto','fatturato_gruppi_lavorazioni_confronto','temprasud','small','\'100%\'','\'100%\'','<p>Il diagramma contiene un istogramma rappresentante il fatturato del Gruppo di Lavorazione selezionato (o di tutti i gruppi) del periodo scelto rispetto all\'anno precedente.</p>\r\n','<p>QWIN</p>',NULL,1,NULL,NULL),(202,'Costi Concorrenti','costi_concorrenti/stack','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per anno l\'andamento dei costi di Temprasud e dei suoi concorrenti.</p>','Tablla dati concorrenti su SAPERE.','D:\\ARCHIVIO\\CONTROLLO DI GESTIONE\\REPORTING\\CONCORRENTI.xlsx',1,NULL,NULL),(204,'Report Commerciale','report_commerciale','temprasud','small','\'100%\'','\'100%\'','<p>Nel widget sono presenti i link ai report dell‘ambito commerciale.</p>\r\n<p>I dati sono un\'aggregazione in Excel dei kpi della Dashboard Commerciale.</p>','<p>Team System e QWIN</p>\r\n<p><b>Report Performance Fornitori:</b></p>\r\n<ul>\r\n    <li>anno di riferimento</li>\r\n    <li>ordini annui</li>\r\n    <li>% NC ordini</li>\r\n    <li>% Puntualità</li>\r\n    <li>% Aumento ponderato prezzi prodotti per fornitore con media ponderata pesata</li>\r\n</ul>\r\n<p><b>Report Costi Materie Prime:</b> per ogni prodotto, per anno in corso e anno-1 e anno-2</p>\r\n<ul>\r\n    <li>quantità acquistata</li>\r\n    <li>importo speso</li>\r\n    <li>% aumento ponderato tra un anno e l\'altro</li>\r\n</ul>',NULL,1,NULL,NULL),(205,'Report Induzione','report_induzione','temprasud','small','\'100%\'','\'100%\'','<p>Nel widget sono presenti i link ai report dell\'ambito induzione.</p>\r\n<p>I dati sono un\'aggregazione in Excel dei kpi della Dashboard induzione.</p>','<p>QWIN</p>\r\n<p><b>Report Pzh Clienti:</b></p>\r\n<ul>\r\n    <li>pz/h da registro induzione</li>\r\n</ul>',NULL,1,NULL,NULL);
INSERT INTO `widget` VALUES (206,'Nuove azioni di miglioramento by TAG','azioni_miglioramento_tags','temprasud','medium','\'100%\'','\'100%\'','Il diagramma presenta temporalmente per trimestre le nuove azioni di miglioramento aperte.\r\n\r\nDal 2019 i dati vengono prelevati da Zoho Projects. Vengono considerati tutti i task dei progetti nei raggruppamenti \'Miglioramenti semplici\' e \'Attività di miglioramento\'','<p>Zoho Projects</p>\r\n ','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2016.xsls',1,NULL,NULL),(207,'Andamento azioni di miglioramento by TAG','azioni_miglioramento_tags2','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma mostra l\'andamento della attività di miglioramento per risorsa. I dati vengono prelevati da Zoho Projects. Vengono considerati tutti i task e i subtask dei progetti nei raggruppamenti \'Miglioramenti semplici\' e \'Attività di miglioramento\' per il progetto \"PIANO MIGLIORAMENTO CONTINUO TEMPRASUD\".</p>\r\n<p>Per le \'azioni aperte\' vengono considerate anche quelle aperte negli anni precedenti a quello selezionato e non ancora chiuse.</p>\r\n<p>Per le \'azioni chiuse\' vengono considerate quelle chiuse nell\'anno selezionato indipendentemente da quando sono state aperte.</p>','<p>Zoho Projects</p>','D:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2014.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2015.xsls\nD:\\ARCHIVIO\\QUALITA\\NON CONFORMITA\\non_conformita_MOD_8D_2016.xsls',1,NULL,NULL),(208,'OEE','oee_ind','temprasud','medium','\'100%\'','\'100%\'','<p>L\'Overall Equipment Effectiveness (OEE) è la misura di efficacia totale di un impianto e riassume in sé i concetti di: disponibilità (frazione di tempo in cui l\'impianto è effettivamente disponibile),efficienza (la velocità con cui l\'impianto sta lavorando come frazione rispetto a quella di progetto) ed il tasso di qualità ( cioè le unità in specifica rispetto a tutte quelle prodotte)\r\n</p>\r\n<p><b>Formula:</b> Tasso Qualità * Efficienza Produttiva * Eq.Availability </p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(209,'% Ore Formazione','perc_formazione','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma mostra la percentuale di ore di formazione rispetto al totale ore lavorate.</p>\r\n<p><b>Formula: </b>Ore Formazione / Ore Lavorate</p>','<p>Excel Formazione per le ore di formazione</p><p>Come data viene presa la data nella colonna \"DATA PREVISTA FINE INTERVENTO\"</p>\r\n<p>Team System HR per le ore lavorate</p>','D:\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2014\\2014_Piano_di_formazione.xls\r\nD:\\ARCHIVIO\\QUALITA\'\\SISTEMA GESTIONE QUALITA\'\\REGISTRAZIONI 2015\\ADDESTRAMENTO_FORMAZIONE PERSONALE 2015\\2015_Piano_di_formazione',1,NULL,NULL),(210,'Emissioni media complessiva','emissioni_media','temprasud','small','100%','100%','<p>Il diagramma mostra i  valori max-medio-min registrati per punto di emissione.</p>','<p>Tabella dati emissioni su SAPERE</p>',NULL,1,NULL,NULL),(211,'Laboratorio','laboratorio','temprasud','medium','\'100%\'','\'100%\'','<p>Questo KPI mostra il costo medio di un provino. Si ottiene dividendo i costi sostenuti dal laboratorio diviso il numero di provini prodotti. I dati sono suddivisi per trimestre.</p>','QWIN (collaudi - Nr Provini) e Tabella Dati Laboratorio su SAPERE',NULL,1,NULL,NULL);
INSERT INTO `widget` VALUES (212,'Equipment Availability Reparti','produzione_efficacia_man','temprasud','medium','\'100%\'','\'100%\'','<p> Il diagramma presenta temporalmente per mese la efficacia della pianificazione manutenzione, intesa come:</p>\r\n<p><b>Formula:</b> 1 - (Ore spento per manutenzione programmata/preventiva + Ore spento per manutenzione straordinaria, guasto + Ore in stand-by per guasto / man. Straordinaria) / Capacità Teorica.</p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(213,'Mean Time between Repair','mean_time_between_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per gruppo di reparti il tempo medio tra 2 failure inteso come:</p>\r\n<p><b>Formula: (Somma Ore Capacità Teorica - Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(214,'Mean Time to Repair','mean_time_to_repair','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta per gruppo di reparti il tempo medio in ore per effettuare le riparazioni inteso come:</p>\r\n<p><b>(Somma Ore spento e stand by per Man. Straordinaria/guasto) / Numero failure.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL),(215,'Tasso Qualità Reparti','tasso_qualita_reparti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese il rendimento globale dei reparti.</p>\r\n<p><b>Formula:</b> Ore produttive / Ore funzionamento effettivo</p>\r\n<p>Le <i>Ore Produttive</i> sono calcolate come le <i>Ore Funzionamento Effettivo - Rilavorazioni</i></p>\r\n<p>Le <i>Ore funzionamento effettivo</i> sono calcolate come le <i>Ore Acceso - Perdite</i></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>',NULL,1,NULL,NULL),(216,'Efficienza Produttiva Reparti','efficienza_produttiva_reparti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese l‘andamento della produttività dei reparti, intesa come Ore produttive/Ore acceso.</p>\r\n<p><b>Formula: Ore produttive / Ore acceso</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p> <p>Ore di funzionamento effettivo da datawarehouse</p>',NULL,1,NULL,NULL),(217,'Saturazione Commerciale Reparti','produzione_saturazione_reparti','temprasud','medium','\'100%\'','\'100%\'','<p>Il diagramma presenta temporalmente per mese la saturazione commerciale dei reparti.</p>\r\n<p><b>Intesa come (Capacità teorica-Festività- Ore spento per mancanza materiale –Ore spento per manutenzione programmata/preventiva - Ore spento per Man. Straordinaria/guasto)  / Capacità teorica.</b></p>','<p>Tabella Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p>',NULL,1,NULL,NULL);
INSERT INTO `widget` VALUES (218,'OEE Reparti','oee_reparti','temprasud','medium','\'100%\'','\'100%\'','<p>L\'Overall Equipment Effectiveness (OEE) è la misura di efficacia totale di un impianto e riassume in sé i concetti di: disponibilità (frazione di tempo in cui l\'impianto è effettivamente disponibile),efficienza (la velocità con cui l\'impianto sta lavorando come frazione rispetto a quella di progetto) ed il tasso di qualità ( cioè le unità in specifica rispetto a tutte quelle prodotte)\r\n</p>\r\n<p><b>Formula:</b> Tasso Qualità * Efficienza Produttiva * Eq.Availability </p>','<p>Tabella  Dati Impianti su SAPERE</p>\r\n<p>Dal 2022 vengono sincronizzati anche il modulo Giustificativo Impianti e le ore di rilavorazione dal QWIN</p> <p>Ore di funzionamento effettivo da datawarehouse</p>','D:\\ARCHIVIO\\PRODUZIONE\\KPI_PRODUZIONE_performance_IMPIANTI.xlsx',1,NULL,NULL);
